import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Slider } from "@/components/ui/slider";
import { Progress } from "@/components/ui/progress";
import { FileUpload } from "@/components/upload/FileUpload";
import { MapPicker } from "@/components/maps/MapPicker";
import { 
  Shield, 
  Camera, 
  Satellite, 
  FileText, 
  MapPin, 
  Calendar, 
  Crop, 
  Droplets, 
  Bug, 
  AlertTriangle,
  CheckCircle,
  Upload,
  Eye,
  Download,
  BarChart3,
  TrendingUp,
  Brain
} from "lucide-react";
import { RiskAssessment, AssessmentImage, AssessmentVideo, AssessmentReport } from "@/types/enhanced-api";

interface RiskAssessmentModuleProps {
  policyRequestId: string;
  farmerId: string;
  assessorId: string;
  onSubmit: (assessment: RiskAssessment) => void;
  onCancel: () => void;
}

export function RiskAssessmentModule({ 
  policyRequestId, 
  farmerId, 
  assessorId, 
  onSubmit, 
  onCancel 
}: RiskAssessmentModuleProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [assessment, setAssessment] = useState<Partial<RiskAssessment>>({
    policyRequestId,
    farmerId,
    assessorId,
    assessmentDate: new Date().toISOString(),
    seasonInfo: {
      seasonType: 'A',
      plantingDate: '',
      expectedHarvest: '',
      cropVariety: '',
      seedSpecifications: {
        type: '',
        supplier: '',
        germinationRate: 0
      },
      tillingMethods: []
    },
    agriculturalPractices: {
      fertilizers: {
        type: '',
        applicationSchedule: [],
        lastApplied: ''
      },
      irrigation: {
        systemType: 'manual',
        waterAvailability: 'moderate',
        frequency: ''
      },
      pestControl: {
        measures: [],
        lastTreatment: '',
        effectiveness: 'medium'
      }
    },
    riskFactors: {
      soilQuality: 'moderate',
      weatherExposure: 'medium',
      pestHistory: 'none',
      diseaseSusceptibility: 'medium',
      marketAccess: 'good'
    },
    documentation: {
      satelliteImages: [],
      droneFootage: [],
      fieldPhotos: [],
      reports: []
    },
    comments: '',
    riskScore: 0,
    riskCategory: 'medium',
    qaStatus: 'draft'
  });

  const [aiAnalysisResults, setAiAnalysisResults] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const totalSteps = 5;

  const handleInputChange = (section: string, field: string, value: any) => {
    setAssessment(prev => ({
      ...prev,
      [section]: {
        ...prev[section as keyof typeof prev],
        [field]: value
      }
    }));
  };

  const handleNestedInputChange = (section: string, subsection: string, field: string, value: any) => {
    setAssessment(prev => ({
      ...prev,
      [section]: {
        ...prev[section as keyof typeof prev],
        [subsection]: {
          ...(prev[section as keyof typeof prev] as any)?.[subsection],
          [field]: value
        }
      }
    }));
  };

  const handleArrayChange = (section: string, subsection: string, field: string, value: string, checked: boolean) => {
    const currentArray = (assessment as any)[section][subsection][field] || [];
    let newArray;
    if (checked) {
      newArray = [...currentArray, value];
    } else {
      newArray = currentArray.filter((item: string) => item !== value);
    }
    handleNestedInputChange(section, subsection, field, newArray);
  };

  const handleFileUpload = (type: 'satellite' | 'drone' | 'field' | 'report', files: File[]) => {
    const newFiles = files.map(file => ({
      id: `file_${Date.now()}_${Math.random()}`,
      url: URL.createObjectURL(file),
      caption: file.name,
      coordinates: assessment.seasonInfo?.coords || [30.1234, -1.9456],
      timestamp: new Date().toISOString()
    }));

    const currentDocs = assessment.documentation || { satelliteImages: [], droneFootage: [], fieldPhotos: [], reports: [] };
    
    switch (type) {
      case 'satellite':
        setAssessment(prev => ({
          ...prev,
          documentation: {
            ...currentDocs,
            satelliteImages: [...currentDocs.satelliteImages, ...newFiles]
          }
        }));
        break;
      case 'drone':
        setAssessment(prev => ({
          ...prev,
          documentation: {
            ...currentDocs,
            droneFootage: [...currentDocs.droneFootage, ...newFiles]
          }
        }));
        break;
      case 'field':
        setAssessment(prev => ({
          ...prev,
          documentation: {
            ...currentDocs,
            fieldPhotos: [...currentDocs.fieldPhotos, ...newFiles]
          }
        }));
        break;
      case 'report':
        const newReports = files.map(file => ({
          id: `report_${Date.now()}_${Math.random()}`,
          title: file.name,
          content: '',
          fileUrl: URL.createObjectURL(file),
          reportType: 'field_inspection' as const,
          generatedDate: new Date().toISOString()
        }));
        setAssessment(prev => ({
          ...prev,
          documentation: {
            ...currentDocs,
            reports: [...currentDocs.reports, ...newReports]
          }
        }));
        break;
    }
  };

  const calculateRiskScore = () => {
    let score = 50; // Base score

    // Soil quality impact
    const soilScores = { excellent: -20, good: -10, moderate: 0, poor: 15 };
    score += soilScores[assessment.riskFactors?.soilQuality || 'moderate'];

    // Weather exposure impact
    const weatherScores = { low: -15, medium: 0, high: 20 };
    score += weatherScores[assessment.riskFactors?.weatherExposure || 'medium'];

    // Pest history impact
    const pestScores = { none: -10, minor: 0, moderate: 10, severe: 25 };
    score += pestScores[assessment.riskFactors?.pestHistory || 'none'];

    // Disease susceptibility impact
    const diseaseScores = { low: -10, medium: 0, high: 15 };
    score += diseaseScores[assessment.riskFactors?.diseaseSusceptibility || 'medium'];

    // Market access impact
    const marketScores = { excellent: -5, good: -2, moderate: 5, poor: 10 };
    score += marketScores[assessment.riskFactors?.marketAccess || 'good'];

    // Irrigation system impact
    const irrigationScores = { excellent: -10, good: -5, moderate: 5, poor: 15 };
    score += irrigationScores[assessment.agriculturalPractices?.irrigation?.waterAvailability || 'moderate'];

    return Math.max(0, Math.min(100, score));
  };

  const getRiskCategory = (score: number): 'low' | 'medium' | 'high' => {
    if (score < 30) return 'low';
    if (score < 70) return 'medium';
    return 'high';
  };

  const runAIAnalysis = async () => {
    setIsAnalyzing(true);
    
    // Simulate AI analysis
    await new Promise(resolve => setTimeout(resolve, 3000));
    
    const riskScore = calculateRiskScore();
    const riskCategory = getRiskCategory(riskScore);
    
    setAiAnalysisResults({
      riskScore,
      riskCategory,
      confidence: 85,
      recommendations: [
        'Consider implementing drip irrigation for better water efficiency',
        'Apply organic fertilizers to improve soil quality',
        'Schedule regular pest monitoring visits',
        'Install weather monitoring sensors'
      ],
      threats: [
        { type: 'Weed Infestation', probability: 65, severity: 'medium' },
        { type: 'Drought Risk', probability: 40, severity: 'low' },
        { type: 'Pest Attack', probability: 30, severity: 'low' }
      ]
    });

    setAssessment(prev => ({
      ...prev,
      riskScore,
      riskCategory
    }));

    setIsAnalyzing(false);
  };

  const validateStep = (step: number): boolean => {
    switch (step) {
      case 1:
        return !!(assessment.seasonInfo?.plantingDate && assessment.seasonInfo?.expectedHarvest && assessment.seasonInfo?.cropVariety);
      case 2:
        return !!(assessment.agriculturalPractices?.fertilizers?.type && assessment.agriculturalPractices?.irrigation?.systemType);
      case 3:
        return true; // Risk factors always have defaults
      case 4:
        return assessment.documentation && (
          assessment.documentation.satelliteImages.length > 0 ||
          assessment.documentation.droneFootage.length > 0 ||
          assessment.documentation.fieldPhotos.length > 0
        );
      case 5:
        return !!(assessment.comments && assessment.comments.trim().length > 0);
      default:
        return false;
    }
  };

  const nextStep = () => {
    if (validateStep(currentStep) && currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const prevStep = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    if (validateStep(currentStep)) {
      const finalAssessment: RiskAssessment = {
        id: `assessment_${Date.now()}`,
        ...assessment,
        assessmentDate: new Date().toISOString(),
        riskScore: calculateRiskScore(),
        riskCategory: getRiskCategory(calculateRiskScore()),
        qaStatus: 'submitted',
        submissionDate: new Date().toISOString()
      } as RiskAssessment;
      
      onSubmit(finalAssessment);
    }
  };

  const renderStepIndicator = () => (
    <div className="flex items-center justify-center mb-8">
      {Array.from({ length: totalSteps }, (_, i) => (
        <div key={i} className="flex items-center">
          <div className={`
            w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium
            ${i + 1 <= currentStep 
              ? 'bg-blue-600 text-white' 
              : 'bg-gray-200 text-gray-500'
            }
          `}>
            {i + 1}
          </div>
          {i < totalSteps - 1 && (
            <div className={`
              w-16 h-1 mx-2
              ${i + 1 < currentStep ? 'bg-blue-600' : 'bg-gray-200'}
            `} />
          )}
        </div>
      ))}
    </div>
  );

  const renderSeasonInfo = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <Calendar className="h-12 w-12 mx-auto text-blue-600 mb-4" />
        <h3 className="text-xl font-semibold">Seasonal & Crop Information</h3>
        <p className="text-gray-600">Provide details about the farming season and crop specifications</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <Label htmlFor="seasonType">Season Type *</Label>
          <Select
            value={assessment.seasonInfo?.seasonType || 'A'}
            onValueChange={(value) => handleNestedInputChange('seasonInfo', 'seasonType', value)}
          >
            <SelectTrigger>
              <SelectValue placeholder="Select season type" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="A">Season A (Sept - Jan)</SelectItem>
              <SelectItem value="B">Season B (Feb - Jun)</SelectItem>
              <SelectItem value="C">Season C (Jul - Aug)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-2">
          <Label htmlFor="plantingDate">Planting Date *</Label>
          <Input
            id="plantingDate"
            type="date"
            value={assessment.seasonInfo?.plantingDate || ''}
            onChange={(e) => handleNestedInputChange('seasonInfo', 'plantingDate', e.target.value)}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="expectedHarvest">Expected Harvest Date *</Label>
          <Input
            id="expectedHarvest"
            type="date"
            value={assessment.seasonInfo?.expectedHarvest || ''}
            onChange={(e) => handleNestedInputChange('seasonInfo', 'expectedHarvest', e.target.value)}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="cropVariety">Crop Variety *</Label>
          <Input
            id="cropVariety"
            placeholder="Enter crop variety"
            value={assessment.seasonInfo?.cropVariety || ''}
            onChange={(e) => handleNestedInputChange('seasonInfo', 'cropVariety', e.target.value)}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="seedType">Seed Type</Label>
          <Input
            id="seedType"
            placeholder="Enter seed type"
            value={assessment.seasonInfo?.seedSpecifications?.type || ''}
            onChange={(e) => handleNestedInputChange('seasonInfo', 'seedSpecifications', 'type', e.target.value)}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="germinationRate">Germination Rate (%)</Label>
          <Input
            id="germinationRate"
            type="number"
            min="0"
            max="100"
            placeholder="Enter germination rate"
            value={assessment.seasonInfo?.seedSpecifications?.germinationRate || ''}
            onChange={(e) => handleNestedInputChange('seasonInfo', 'seedSpecifications', 'germinationRate', parseInt(e.target.value) || 0)}
          />
        </div>
      </div>

      <div className="space-y-4">
        <Label>Tilling Methods</Label>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          {['Conventional Tillage', 'Minimum Tillage', 'No-Till', 'Ridge Tillage', 'Strip Tillage', 'Mulch Tillage'].map((method) => (
            <div key={method} className="flex items-center space-x-2">
              <Checkbox
                checked={assessment.seasonInfo?.tillingMethods?.includes(method) || false}
                onCheckedChange={(checked) => handleArrayChange('seasonInfo', 'tillingMethods', method, checked as boolean)}
              />
              <Label className="text-sm">{method}</Label>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const renderAgriculturalPractices = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <Crop className="h-12 w-12 mx-auto text-green-600 mb-4" />
        <h3 className="text-xl font-semibold">Agricultural Practices</h3>
        <p className="text-gray-600">Document farming practices and inputs</p>
      </div>

      <div className="space-y-8">
        {/* Fertilizer Information */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Droplets className="h-5 w-5" />
              <span>Fertilizer Management</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="fertilizerType">Fertilizer Type *</Label>
                <Select
                  value={assessment.agriculturalPractices?.fertilizers?.type || ''}
                  onValueChange={(value) => handleNestedInputChange('agriculturalPractices', 'fertilizers', 'type', value)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select fertilizer type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="organic">Organic Fertilizer</SelectItem>
                    <SelectItem value="inorganic">Inorganic Fertilizer</SelectItem>
                    <SelectItem value="mixed">Mixed (Organic + Inorganic)</SelectItem>
                    <SelectItem value="none">No Fertilizer</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="lastApplied">Last Applied</Label>
                <Input
                  id="lastApplied"
                  type="date"
                  value={assessment.agriculturalPractices?.fertilizers?.lastApplied || ''}
                  onChange={(e) => handleNestedInputChange('agriculturalPractices', 'fertilizers', 'lastApplied', e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label>Application Schedule</Label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {['Pre-planting', 'At planting', 'Early growth', 'Mid-season', 'Pre-harvest'].map((schedule) => (
                  <div key={schedule} className="flex items-center space-x-2">
                    <Checkbox
                      checked={assessment.agriculturalPractices?.fertilizers?.applicationSchedule?.includes(schedule) || false}
                      onCheckedChange={(checked) => handleArrayChange('agriculturalPractices', 'fertilizers', 'applicationSchedule', schedule, checked as boolean)}
                    />
                    <Label className="text-sm">{schedule}</Label>
                  </div>
                ))}
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Irrigation Information */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Droplets className="h-5 w-5" />
              <span>Irrigation System</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="irrigationType">System Type *</Label>
                <Select
                  value={assessment.agriculturalPractices?.irrigation?.systemType || ''}
                  onValueChange={(value) => handleNestedInputChange('agriculturalPractices', 'irrigation', 'systemType', value)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select irrigation type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="drip">Drip Irrigation</SelectItem>
                    <SelectItem value="sprinkler">Sprinkler Irrigation</SelectItem>
                    <SelectItem value="flood">Flood Irrigation</SelectItem>
                    <SelectItem value="manual">Manual Watering</SelectItem>
                    <SelectItem value="rainfed">Rain-fed Only</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="waterAvailability">Water Availability</Label>
                <Select
                  value={assessment.agriculturalPractices?.irrigation?.waterAvailability || ''}
                  onValueChange={(value) => handleNestedInputChange('agriculturalPractices', 'irrigation', 'waterAvailability', value)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select water availability" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="excellent">Excellent</SelectItem>
                    <SelectItem value="good">Good</SelectItem>
                    <SelectItem value="moderate">Moderate</SelectItem>
                    <SelectItem value="poor">Poor</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="irrigationFrequency">Irrigation Frequency</Label>
              <Input
                id="irrigationFrequency"
                placeholder="e.g., Every 3 days, Weekly, etc."
                value={assessment.agriculturalPractices?.irrigation?.frequency || ''}
                onChange={(e) => handleNestedInputChange('agriculturalPractices', 'irrigation', 'frequency', e.target.value)}
              />
            </div>
          </CardContent>
        </Card>

        {/* Pest Control Information */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Bug className="h-5 w-5" />
              <span>Pest Control</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="lastTreatment">Last Treatment</Label>
                <Input
                  id="lastTreatment"
                  type="date"
                  value={assessment.agriculturalPractices?.pestControl?.lastTreatment || ''}
                  onChange={(e) => handleNestedInputChange('agriculturalPractices', 'pestControl', 'lastTreatment', e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="effectiveness">Treatment Effectiveness</Label>
                <Select
                  value={assessment.agriculturalPractices?.pestControl?.effectiveness || ''}
                  onValueChange={(value) => handleNestedInputChange('agriculturalPractices', 'pestControl', 'effectiveness', value)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select effectiveness" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="high">High</SelectItem>
                    <SelectItem value="medium">Medium</SelectItem>
                    <SelectItem value="low">Low</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label>Pest Control Measures</Label>
              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                {['Chemical Pesticides', 'Organic Pesticides', 'Biological Control', 'Cultural Practices', 'Physical Barriers', 'None'].map((measure) => (
                  <div key={measure} className="flex items-center space-x-2">
                    <Checkbox
                      checked={assessment.agriculturalPractices?.pestControl?.measures?.includes(measure) || false}
                      onCheckedChange={(checked) => handleArrayChange('agriculturalPractices', 'pestControl', 'measures', measure, checked as boolean)}
                    />
                    <Label className="text-sm">{measure}</Label>
                  </div>
                ))}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );

  const renderRiskFactors = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <AlertTriangle className="h-12 w-12 mx-auto text-orange-600 mb-4" />
        <h3 className="text-xl font-semibold">Risk Factor Assessment</h3>
        <p className="text-gray-600">Evaluate various risk factors affecting crop production</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {[
          { key: 'soilQuality', label: 'Soil Quality', options: ['excellent', 'good', 'moderate', 'poor'] },
          { key: 'weatherExposure', label: 'Weather Exposure', options: ['low', 'medium', 'high'] },
          { key: 'pestHistory', label: 'Pest History', options: ['none', 'minor', 'moderate', 'severe'] },
          { key: 'diseaseSusceptibility', label: 'Disease Susceptibility', options: ['low', 'medium', 'high'] },
          { key: 'marketAccess', label: 'Market Access', options: ['excellent', 'good', 'moderate', 'poor'] }
        ].map((factor) => (
          <Card key={factor.key}>
            <CardHeader>
              <CardTitle className="text-lg">{factor.label}</CardTitle>
            </CardHeader>
            <CardContent>
              <Select
                value={(assessment.riskFactors as any)?.[factor.key] || 'moderate'}
                onValueChange={(value) => handleNestedInputChange('riskFactors', factor.key, value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder={`Select ${factor.label.toLowerCase()}`} />
                </SelectTrigger>
                <SelectContent>
                  {factor.options.map((option) => (
                    <SelectItem key={option} value={option}>
                      {option.charAt(0).toUpperCase() + option.slice(1)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </CardContent>
          </Card>
        ))}
      </div>

      <Card className="bg-blue-50">
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <BarChart3 className="h-5 w-5" />
            <span>Risk Score Preview</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <span>Calculated Risk Score</span>
              <Badge variant="outline" className="text-lg">
                {calculateRiskScore()}/100
              </Badge>
            </div>
            <Progress value={calculateRiskScore()} className="w-full" />
            <div className="flex justify-between text-sm text-gray-500">
              <span>Low Risk</span>
              <span>Medium Risk</span>
              <span>High Risk</span>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const renderDocumentation = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <Upload className="h-12 w-12 mx-auto text-purple-600 mb-4" />
        <h3 className="text-xl font-semibold">Documentation Upload</h3>
        <p className="text-gray-600">Upload satellite images, drone footage, and field photos</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Satellite Images */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Satellite className="h-5 w-5" />
              <span>Satellite Images</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <FileUpload
              onUpload={(files) => handleFileUpload('satellite', files)}
              accept=".jpg,.jpeg,.png,.tiff"
              maxSize={10 * 1024 * 1024} // 10MB
              multiple={true}
            />
            {assessment.documentation?.satelliteImages && assessment.documentation.satelliteImages.length > 0 && (
              <div className="space-y-2">
                <Label>Uploaded Images ({assessment.documentation.satelliteImages.length})</Label>
                <div className="grid grid-cols-2 gap-2">
                  {assessment.documentation.satelliteImages.map((image, index) => (
                    <div key={image.id} className="relative">
                      <img src={image.url} alt={image.caption} className="w-full h-20 object-cover rounded" />
                      <Badge className="absolute top-1 right-1 text-xs">Satellite</Badge>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Drone Footage */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Camera className="h-5 w-5" />
              <span>Drone Footage</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <FileUpload
              onUpload={(files) => handleFileUpload('drone', files)}
              accept=".mp4,.avi,.mov,.mkv"
              maxSize={50 * 1024 * 1024} // 50MB
              multiple={true}
            />
            {assessment.documentation?.droneFootage && assessment.documentation.droneFootage.length > 0 && (
              <div className="space-y-2">
                <Label>Uploaded Videos ({assessment.documentation.droneFootage.length})</Label>
                <div className="space-y-2">
                  {assessment.documentation.droneFootage.map((video, index) => (
                    <div key={video.id} className="flex items-center space-x-2 p-2 bg-gray-50 rounded">
                      <video src={video.url} className="w-16 h-12 object-cover rounded" />
                      <div className="flex-1">
                        <p className="text-sm font-medium">{video.caption}</p>
                        <p className="text-xs text-gray-500">Duration: {video.duration}s</p>
                      </div>
                      <Badge variant="outline">Drone</Badge>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Field Photos */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <Camera className="h-5 w-5" />
              <span>Field Photos</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <FileUpload
              onUpload={(files) => handleFileUpload('field', files)}
              accept=".jpg,.jpeg,.png"
              maxSize={5 * 1024 * 1024} // 5MB
              multiple={true}
            />
            {assessment.documentation?.fieldPhotos && assessment.documentation.fieldPhotos.length > 0 && (
              <div className="space-y-2">
                <Label>Uploaded Photos ({assessment.documentation.fieldPhotos.length})</Label>
                <div className="grid grid-cols-3 gap-2">
                  {assessment.documentation.fieldPhotos.map((photo, index) => (
                    <div key={photo.id} className="relative">
                      <img src={photo.url} alt={photo.caption} className="w-full h-20 object-cover rounded" />
                      <Badge className="absolute top-1 right-1 text-xs">Field</Badge>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Reports */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <FileText className="h-5 w-5" />
              <span>Assessment Reports</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <FileUpload
              onUpload={(files) => handleFileUpload('report', files)}
              accept=".pdf,.doc,.docx"
              maxSize={10 * 1024 * 1024} // 10MB
              multiple={true}
            />
            {assessment.documentation?.reports && assessment.documentation.reports.length > 0 && (
              <div className="space-y-2">
                <Label>Uploaded Reports ({assessment.documentation.reports.length})</Label>
                <div className="space-y-2">
                  {assessment.documentation.reports.map((report, index) => (
                    <div key={report.id} className="flex items-center space-x-2 p-2 bg-gray-50 rounded">
                      <FileText className="h-8 w-8 text-blue-600" />
                      <div className="flex-1">
                        <p className="text-sm font-medium">{report.title}</p>
                        <p className="text-xs text-gray-500">{report.reportType}</p>
                      </div>
                      <Button size="sm" variant="outline">
                        <Download className="h-3 w-3 mr-1" />
                        Download
                      </Button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );

  const renderAIAnalysis = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <Brain className="h-12 w-12 mx-auto text-indigo-600 mb-4" />
        <h3 className="text-xl font-semibold">AI Risk Analysis</h3>
        <p className="text-gray-600">AI-powered assessment and recommendations</p>
      </div>

      <div className="flex justify-center mb-6">
        <Button
          onClick={runAIAnalysis}
          disabled={isAnalyzing}
          className="bg-indigo-600 hover:bg-indigo-700"
        >
          {isAnalyzing ? (
            <>
              <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2" />
              Analyzing...
            </>
          ) : (
            <>
              <Brain className="h-4 w-4 mr-2" />
              Run AI Analysis
            </>
          )}
        </Button>
      </div>

      {aiAnalysisResults && (
        <div className="space-y-6">
          {/* Risk Score */}
          <Card className="bg-gradient-to-r from-indigo-50 to-purple-50">
            <CardHeader>
              <CardTitle className="flex items-center space-x-2">
                <TrendingUp className="h-5 w-5" />
                <span>AI Risk Assessment</span>
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="text-center">
                  <div className="text-3xl font-bold text-indigo-600">
                    {aiAnalysisResults.riskScore}
                  </div>
                  <div className="text-sm text-gray-600">Risk Score</div>
                </div>
                <div className="text-center">
                  <Badge 
                    variant={aiAnalysisResults.riskCategory === 'low' ? 'default' : 
                            aiAnalysisResults.riskCategory === 'medium' ? 'secondary' : 'destructive'}
                    className="text-lg px-4 py-2"
                  >
                    {aiAnalysisResults.riskCategory.toUpperCase()} RISK
                  </Badge>
                </div>
                <div className="text-center">
                  <div className="text-3xl font-bold text-green-600">
                    {aiAnalysisResults.confidence}%
                  </div>
                  <div className="text-sm text-gray-600">AI Confidence</div>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Recommendations */}
          <Card>
            <CardHeader>
              <CardTitle>AI Recommendations</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {aiAnalysisResults.recommendations.map((recommendation: string, index: number) => (
                  <div key={index} className="flex items-start space-x-3 p-3 bg-blue-50 rounded-lg">
                    <CheckCircle className="h-5 w-5 text-blue-600 mt-0.5 flex-shrink-0" />
                    <p className="text-sm">{recommendation}</p>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Threat Analysis */}
          <Card>
            <CardHeader>
              <CardTitle>Threat Analysis</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {aiAnalysisResults.threats.map((threat: any, index: number) => (
                  <div key={index} className="flex items-center justify-between p-3 bg-orange-50 rounded-lg">
                    <div>
                      <p className="font-medium">{threat.type}</p>
                      <p className="text-sm text-gray-600">Severity: {threat.severity}</p>
                    </div>
                    <div className="text-right">
                      <div className="text-lg font-bold text-orange-600">
                        {threat.probability}%
                      </div>
                      <div className="text-xs text-gray-500">Probability</div>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Comments */}
      <Card>
        <CardHeader>
          <CardTitle>Assessment Comments</CardTitle>
        </CardHeader>
        <CardContent>
          <Textarea
            placeholder="Add your observations, recommendations, and any additional notes..."
            value={assessment.comments || ''}
            onChange={(e) => handleInputChange('comments', e.target.value)}
            rows={6}
          />
        </CardContent>
      </Card>
    </div>
  );

  const renderCurrentStep = () => {
    switch (currentStep) {
      case 1:
        return renderSeasonInfo();
      case 2:
        return renderAgriculturalPractices();
      case 3:
        return renderRiskFactors();
      case 4:
        return renderDocumentation();
      case 5:
        return renderAIAnalysis();
      default:
        return null;
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl text-center">Risk Assessment Module</CardTitle>
          <p className="text-center text-gray-600">
            Comprehensive field assessment and risk evaluation
          </p>
        </CardHeader>
        <CardContent>
          {renderStepIndicator()}
          
          <div className="mb-8">
            {renderCurrentStep()}
          </div>

          <div className="flex justify-between">
            <Button
              variant="outline"
              onClick={currentStep === 1 ? onCancel : prevStep}
            >
              {currentStep === 1 ? 'Cancel' : 'Previous'}
            </Button>

            {currentStep < totalSteps ? (
              <Button
                onClick={nextStep}
                disabled={!validateStep(currentStep)}
              >
                Next
              </Button>
            ) : (
              <Button
                onClick={handleSubmit}
                disabled={!validateStep(currentStep)}
                className="bg-green-600 hover:bg-green-700"
              >
                Submit Assessment
              </Button>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { 
  Bell, 
  Search, 
  Filter,
  CheckCircle,
  AlertTriangle,
  Info,
  Clock,
  User,
  FileText,
  MapPin,
  Settings,
  Phone,
  Mail,
  Calendar,
  X,
  RefreshCw
} from "lucide-react";
import assessmentsApiService from "@/services/assessmentsApi";
import { getClaims } from "@/services/claimsApi";
import { getUserId } from "@/services/authAPI";
import { getUserById } from "@/services/usersAPI";
import { getFarmById } from "@/services/farmsApi";
import { useToast } from "@/hooks/use-toast";

interface Notification {
  id: string;
  type: string;
  title: string;
  message: string;
  priority: "high" | "medium" | "low";
  status: "read" | "unread";
  timestamp: string;
  farmerId?: string;
  farmerName?: string;
  location?: string;
  dueDate?: string;
  assessmentType?: string;
  claimId?: string;
  assessmentId?: string;
  trainingDate?: string;
  trainingTopic?: string;
  equipmentType?: string;
}

export default function AssessorNotifications() {
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");
  const [selectedNotification, setSelectedNotification] = useState<Notification | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const assessorId = getUserId() || "";

  useEffect(() => {
    loadNotifications();
  }, []);

  const loadNotifications = async () => {
    setLoading(true);
    setError(null);
    try {
      const [assessmentsResp, claimsResp] = await Promise.allSettled([
        assessmentsApiService.getAllAssessments(),
        getClaims()
      ]);

      const notificationsList: Notification[] = [];

      // Process assessments
      if (assessmentsResp.status === 'fulfilled') {
        const assessmentsData = (assessmentsResp.value as any).data || assessmentsResp.value || [];
        const assessmentsArray = Array.isArray(assessmentsData) ? assessmentsData : (assessmentsData.items || assessmentsData.results || []);
        
        // Filter assessments assigned to this assessor
        const assignedAssessments = assessmentsArray.filter((assessment: any) => {
          if (!assessorId) return false;
          const assessmentAssessorId = assessment.assessorId || assessment.assessor?._id || assessment.assessor?.id;
          return assessmentAssessorId === assessorId || assessmentAssessorId === assessorId.toString();
        });

        // Generate notifications from assessments
        for (const assessment of assignedAssessments) {
          const farmId = assessment.farmId || assessment.farm?._id || assessment.farm?.id;
          let farmerName = "Unknown Farmer";
          let location = "Unknown Location";
          let farmerId = "";

          // Try to get farmer info from assessment data
          if (assessment.farm) {
            if (assessment.farm.farmerId) {
              farmerId = assessment.farm.farmerId._id || assessment.farm.farmerId.id || assessment.farm.farmerId || "";
              farmerName = assessment.farm.farmerId.firstName && assessment.farm.farmerId.lastName
                ? `${assessment.farm.farmerId.firstName} ${assessment.farm.farmerId.lastName}`
                : assessment.farm.farmerId.email || assessment.farm.farmerId.phoneNumber || "Unknown Farmer";
            }
            
            if (assessment.farm.location) {
              if (typeof assessment.farm.location === 'string') {
                location = assessment.farm.location;
              } else if (assessment.farm.location.coordinates && Array.isArray(assessment.farm.location.coordinates)) {
                location = `${assessment.farm.location.coordinates[1]?.toFixed(4)}, ${assessment.farm.location.coordinates[0]?.toFixed(4)}`;
              }
            }
          }

          // Try to get farmer info from API if not in assessment
          if (farmerName === "Unknown Farmer" && farmId) {
            try {
              const farmData = await getFarmById(farmId);
              const farm = farmData.data || farmData;
              if (farm?.farmerId) {
                const farmerInfo = typeof farm.farmerId === 'string' 
                  ? await getUserById(farm.farmerId).catch(() => null)
                  : farm.farmerId;
                if (farmerInfo) {
                  const farmer = farmerInfo.data || farmerInfo;
                  farmerId = farmer._id || farmer.id || "";
                  farmerName = farmer.firstName && farmer.lastName
                    ? `${farmer.firstName} ${farmer.lastName}`
                    : farmer.email || farmer.phoneNumber || "Unknown Farmer";
                }
              }
              if (farm?.location && !location) {
                if (typeof farm.location === 'string') {
                  location = farm.location;
                } else if (farm.location.coordinates && Array.isArray(farm.location.coordinates)) {
                  location = `${farm.location.coordinates[1]?.toFixed(4)}, ${farm.location.coordinates[0]?.toFixed(4)}`;
                }
              }
            } catch (err) {
              console.error('Failed to load farm data:', err);
            }
          }

          const assessmentId = assessment._id || assessment.id || "";
          const assessmentDate = assessment.createdAt || assessment.assessmentDate || new Date().toISOString();
          const status = assessment.status?.toLowerCase() || "pending";
          
          // Create notification based on assessment status
          if (status === "pending" || status === "in_progress") {
            const daysSinceCreation = Math.floor((new Date().getTime() - new Date(assessmentDate).getTime()) / (1000 * 60 * 60 * 24));
            const isNew = daysSinceCreation <= 1;
            
            notificationsList.push({
              id: `assessment-${assessmentId}`,
              type: isNew ? "new_assignment" : "assessment_reminder",
              title: isNew ? "New Assessment Assignment" : "Assessment Due Soon",
              message: isNew 
                ? `You have been assigned a new risk assessment for farmer ${farmerName}${location !== "Unknown Location" ? ` in ${location}` : ""}.`
                : `Risk assessment for farmer ${farmerName}${location !== "Unknown Location" ? ` in ${location}` : ""} is pending. Please complete your field visit.`,
              priority: isNew ? "high" : "medium",
              status: "unread",
              timestamp: assessmentDate,
              farmerId,
              farmerName,
              location,
              assessmentType: "risk_assessment",
              assessmentId
            });
          } else if (status === "submitted" || status === "approved") {
            notificationsList.push({
              id: `assessment-approved-${assessmentId}`,
              type: "assessment_approved",
              title: "Assessment Approved",
              message: `Your risk assessment for farmer ${farmerName}${location !== "Unknown Location" ? ` in ${location}` : ""} has been ${status === "approved" ? "approved" : "submitted"} ${status === "approved" ? "by the insurer" : ""}.`,
              priority: "low",
              status: "read",
              timestamp: assessmentDate,
              farmerId,
              farmerName,
              location,
              assessmentId,
              assessmentType: "risk_assessment"
            });
          }
        }
      }

      // Process claims
      if (claimsResp.status === 'fulfilled') {
        const claimsData = (claimsResp.value as any).data || claimsResp.value || [];
        const claimsArray = Array.isArray(claimsData) ? claimsData : (claimsData.items || claimsData.results || []);
        
        // Filter claims assigned to this assessor
        const assignedClaims = claimsArray.filter((claim: any) => {
          if (!assessorId) return false;
          const claimAssessorId = claim.assessorId || claim.assessor?._id || claim.assessor?.id;
          return claimAssessorId === assessorId || claimAssessorId === assessorId.toString();
        });

        // Generate notifications from claims
        for (const claim of assignedClaims) {
          const claimId = claim._id || claim.id || "";
          const claimDate = claim.createdAt || claim.submittedAt || new Date().toISOString();
          const farmerId = claim.farmerId?._id || claim.farmerId || claim.farmer?.id || "";
          let farmerName = "Unknown Farmer";
          const location = "Unknown Location";

          // Get farmer info
          if (claim.farmer || claim.farmerId) {
            const farmer = claim.farmer || claim.farmerId;
            if (typeof farmer === 'object') {
              farmerName = farmer.firstName && farmer.lastName
                ? `${farmer.firstName} ${farmer.lastName}`
                : farmer.email || farmer.phoneNumber || "Unknown Farmer";
            }
          }

          // Try to get farmer info from API if needed
          if (farmerName === "Unknown Farmer" && farmerId) {
            try {
              const farmerData: any = await getUserById(farmerId);
              const farmer = farmerData.data || farmerData;
              farmerName = farmer.firstName && farmer.lastName
                ? `${farmer.firstName} ${farmer.lastName}`
                : farmer.email || farmer.phoneNumber || "Unknown Farmer";
            } catch (err) {
              console.error('Failed to load farmer data:', err);
            }
          }

          notificationsList.push({
            id: `claim-${claimId}`,
            type: "claim_assignment",
            title: "New Claim Assessment",
            message: `You have been assigned to assess claim ${claim.claimNumber || claimId} for farmer ${farmerName}${location !== "Unknown Location" ? ` in ${location}` : ""} regarding ${claim.lossEventType || claim.damageType || "damage"}.`,
            priority: "high",
            status: claim.status === "pending" ? "unread" : "read",
            timestamp: claimDate,
            farmerId,
            farmerName,
            location,
            claimId,
            assessmentType: "loss_assessment"
          });
        }
      }

      // Sort notifications by timestamp (newest first)
      notificationsList.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

      setNotifications(notificationsList);
    } catch (err: any) {
      console.error('Failed to load notifications:', err);
      setError(err.message || 'Failed to load notifications');
      toast({
        title: 'Error loading notifications',
        description: err.message || 'Failed to load notifications',
        variant: 'destructive'
      });
    } finally {
      setLoading(false);
    }
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case "new_assignment": return <FileText className="h-5 w-5" />;
      case "assessment_reminder": return <Clock className="h-5 w-5" />;
      case "claim_assignment": return <AlertTriangle className="h-5 w-5" />;
      case "assessment_approved": return <CheckCircle className="h-5 w-5" />;
      case "training_reminder": return <Calendar className="h-5 w-5" />;
      case "equipment_update": return <Settings className="h-5 w-5" />;
      default: return <Info className="h-5 w-5" />;
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "high": return "bg-red-100 text-red-700 border border-red-200";
      case "medium": return "bg-yellow-100 text-yellow-700 border border-yellow-200";
      case "low": return "bg-green-100 text-green-700 border border-green-200";
      default: return "bg-gray-100 text-gray-700 border border-gray-200";
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case "new_assignment": return "bg-blue-100 text-blue-800";
      case "assessment_reminder": return "bg-orange-100 text-orange-800";
      case "claim_assignment": return "bg-red-100 text-red-800";
      case "assessment_approved": return "bg-green-100 text-green-800";
      case "training_reminder": return "bg-purple-100 text-purple-800";
      case "equipment_update": return "bg-gray-800/20 text-white";
      default: return "bg-gray-800/20 text-white";
    }
  };

  const filteredNotifications = notifications.filter(notification => {
    const matchesSearch = notification.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         notification.message.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         notification.farmerName?.toLowerCase().includes(searchTerm.toLowerCase());
    
    const matchesType = filterType === "all" || notification.type === filterType;
    const matchesStatus = filterStatus === "all" || notification.status === filterStatus;
    
    return matchesSearch && matchesType && matchesStatus;
  });

  const unreadCount = notifications.filter(n => n.status === "unread").length;

  const handleNotificationClick = (notification: Notification) => {
    setSelectedNotification(notification);
    setIsDetailOpen(true);
    // Mark as read when clicked
    if (notification.status === "unread") {
      setNotifications(prev => prev.map(n => 
        n.id === notification.id ? { ...n, status: "read" as const } : n
      ));
    }
  };

  const handleMarkAsRead = (e: React.MouseEvent, notificationId: string) => {
    e.stopPropagation();
    setNotifications(prev => prev.map(n => 
      n.id === notificationId ? { ...n, status: "read" as const } : n
    ));
    if (selectedNotification?.id === notificationId) {
      setSelectedNotification({ ...selectedNotification, status: "read" });
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-6 pb-8">
      {/* Clean Header */}
      <div className="max-w-7xl mx-auto px-6 mb-6">
        <div className="bg-white border border-gray-200 rounded-lg shadow-sm px-6 py-5">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-semibold text-gray-900">Notifications</h1>
              <p className="text-sm text-gray-500 mt-1">Stay updated with your assessment assignments and tasks</p>
            </div>
            <Badge className="bg-green-50 text-green-700 border border-green-200">
              {unreadCount} unread
            </Badge>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-6">
        {/* Search and Filters */}
        <div className="space-y-4 mb-6">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-500" />
          <Input
            placeholder="Search notifications..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 bg-gray-50 border-gray-300 text-gray-900 placeholder:text-gray-500"
          />
        </div>
          <div className="flex gap-3">
            <Select value={filterType} onValueChange={setFilterType}>
              <SelectTrigger className="w-40 bg-gray-50 border-gray-200 text-gray-900 text-xs h-9">
                <SelectValue placeholder="All Types" />
              </SelectTrigger>
              <SelectContent className="bg-white border-gray-200">
                <SelectItem value="all">All Types</SelectItem>
                <SelectItem value="new_assignment">New Assignment</SelectItem>
                <SelectItem value="assessment_reminder">Assessment Reminder</SelectItem>
                <SelectItem value="claim_assignment">Claim Assignment</SelectItem>
                <SelectItem value="assessment_approved">Assessment Approved</SelectItem>
                <SelectItem value="training_reminder">Training Reminder</SelectItem>
                <SelectItem value="equipment_update">Equipment Update</SelectItem>
              </SelectContent>
            </Select>
            <Select value={filterStatus} onValueChange={setFilterStatus}>
              <SelectTrigger className="w-40 bg-gray-50 border-gray-200 text-gray-900 text-xs h-9">
                <SelectValue placeholder="All Status" />
              </SelectTrigger>
              <SelectContent className="bg-white border-gray-200">
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="unread">Unread</SelectItem>
                <SelectItem value="read">Read</SelectItem>
              </SelectContent>
            </Select>
            <Button 
              onClick={loadNotifications}
              variant="outline"
              size="sm"
              className="border-gray-200 hover:bg-gray-50 text-xs h-9 ml-auto"
              disabled={loading}
            >
              <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
              Refresh
            </Button>
          </div>
        </div>

        {/* Loading State */}
        {loading && (
          <Card className="bg-white border border-gray-200 shadow-sm">
            <CardContent className="p-12">
              <div className="flex items-center justify-center">
                <img src="/loading.gif" alt="Loading" className="w-16 h-16" />
              </div>
            </CardContent>
          </Card>
        )}

        {/* Error State */}
        {error && !loading && (
          <Card className="bg-white border border-gray-200 shadow-sm">
            <CardContent className="p-6">
              <div className="text-center text-red-600">
                <AlertTriangle className="h-12 w-12 mx-auto mb-4" />
                <p className="text-sm">{error}</p>
                <Button 
                  onClick={loadNotifications} 
                  className="mt-4 bg-green-600 hover:bg-green-700 text-white text-xs h-8"
                >
                  Retry
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Notifications List */}
        {!loading && !error && (
          <div className="space-y-3">
            {filteredNotifications.length === 0 ? (
              <Card className="bg-white border border-gray-200 shadow-sm">
                <CardContent className="p-12 text-center">
                  <Bell className="h-12 w-12 text-gray-300 mx-auto mb-4" />
                  <h3 className="text-sm font-medium text-gray-900 mb-1">No notifications found</h3>
                  <p className="text-xs text-gray-500">
                    {notifications.length === 0 
                      ? "You have no notifications yet. Notifications will appear here when you receive new assignments."
                      : "Try adjusting your search or filter criteria."}
                  </p>
                </CardContent>
              </Card>
            ) : (
              filteredNotifications.map((notification) => (
              <Card 
                key={notification.id} 
                className={`bg-white border border-gray-200 shadow-sm transition-all duration-200 cursor-pointer hover:bg-green-50/30 ${
                  notification.status === "unread" ? "border-l-4 border-l-green-500 bg-green-50/50" : ""
                }`}
                onClick={() => handleNotificationClick(notification)}
              >
                <CardContent className="p-4">
                  <div className="flex items-start gap-3">
                    <div className={`flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center ${
                      notification.status === "unread" ? "bg-green-100 text-green-600" : "bg-gray-100 text-gray-600"
                    }`}>
                      {getNotificationIcon(notification.type)}
                    </div>
                    
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2 mb-2">
                        <h3 className="text-sm font-semibold text-gray-900 leading-tight">
                          {notification.title}
                        </h3>
                        <Badge className={`${getPriorityColor(notification.priority)} text-xs`}>
                          {notification.priority}
                        </Badge>
                      </div>
                      
                      <p className="text-xs text-gray-600 mb-2 line-clamp-2">
                        {notification.message}
                      </p>
                      
                      <div className="flex items-center gap-4 text-xs text-gray-500">
                        <div className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          {new Date(notification.timestamp).toLocaleString()}
                        </div>
                        {notification.farmerName && (
                          <div className="flex items-center gap-1">
                            <User className="h-3 w-3" />
                            {notification.farmerName}
                          </div>
                        )}
                        {notification.location && (
                          <div className="flex items-center gap-1">
                            <MapPin className="h-3 w-3" />
                            {notification.location}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))
            )}
          </div>
        )}
      </div>

      {/* Notification Detail Dialog */}
      <Dialog open={isDetailOpen} onOpenChange={setIsDetailOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto bg-white border-gray-200">
          {selectedNotification && (
            <>
              <DialogHeader>
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${
                      selectedNotification.status === "unread" ? "bg-green-100 text-green-600" : "bg-gray-100 text-gray-600"
                    }`}>
                      {getNotificationIcon(selectedNotification.type)}
                    </div>
                    <div>
                      <DialogTitle className="text-xl text-gray-900">{selectedNotification.title}</DialogTitle>
                      <DialogDescription className="text-sm text-gray-600 mt-1">
                        {selectedNotification.type.replace(/_/g, ' ')}
                      </DialogDescription>
                    </div>
                  </div>
                  <Badge className={getPriorityColor(selectedNotification.priority)}>
                    {selectedNotification.priority}
                  </Badge>
                </div>
              </DialogHeader>
              
              <div className="space-y-6 mt-4">
                <div>
                  <p className="text-gray-700 leading-relaxed">{selectedNotification.message}</p>
                </div>

                <div className="grid grid-cols-2 gap-4 p-4 bg-gray-50 border border-gray-200 rounded-lg">
                  <div>
                    <p className="text-xs text-gray-600 mb-1">Timestamp</p>
                    <div className="flex items-center gap-2 text-sm text-gray-900">
                      <Clock className="h-4 w-4 text-gray-600" />
                      {new Date(selectedNotification.timestamp).toLocaleString()}
                    </div>
                  </div>
                  {selectedNotification.dueDate && (
                    <div>
                      <p className="text-xs text-gray-600 mb-1">Due Date</p>
                      <div className="flex items-center gap-2 text-sm text-gray-900">
                        <Calendar className="h-4 w-4 text-gray-600" />
                        {selectedNotification.dueDate}
                      </div>
                    </div>
                  )}
                </div>

                {selectedNotification.farmerName && (
                  <div className="p-4 bg-blue-50 border border-blue-200 rounded-lg">
                    <h4 className="text-sm font-semibold text-gray-900 mb-3 flex items-center gap-2">
                      <User className="h-4 w-4 text-gray-600" />
                      Farmer Information
                    </h4>
                    <div className="space-y-2">
                      <div>
                        <p className="text-xs text-gray-600">Name</p>
                        <p className="text-sm text-gray-900 font-medium">{selectedNotification.farmerName}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-600">Farmer ID</p>
                        <p className="text-sm text-gray-900 font-medium">{selectedNotification.farmerId}</p>
                      </div>
                      {selectedNotification.location && (
                        <div>
                          <p className="text-xs text-gray-600">Location</p>
                          <div className="flex items-center gap-2 text-sm text-gray-900">
                            <MapPin className="h-3 w-3 text-gray-600" />
                            {selectedNotification.location}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                )}

                {selectedNotification.claimId && (
                  <div className="p-4 bg-orange-50 border border-orange-200 rounded-lg">
                    <h4 className="text-sm font-semibold text-gray-900 mb-2">Claim Details</h4>
                    <div>
                      <p className="text-xs text-gray-600">Claim ID</p>
                      <p className="text-sm text-gray-900 font-medium">{selectedNotification.claimId}</p>
                    </div>
                  </div>
                )}

                {selectedNotification.assessmentId && (
                  <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
                    <h4 className="text-sm font-semibold text-gray-900 mb-2">Assessment Details</h4>
                    <div>
                      <p className="text-xs text-gray-600">Assessment ID</p>
                      <p className="text-sm text-gray-900 font-medium">{selectedNotification.assessmentId}</p>
                    </div>
                  </div>
                )}

                {selectedNotification.trainingDate && (
                  <div className="p-4 bg-purple-50 border border-purple-200 rounded-lg">
                    <h4 className="text-sm font-semibold text-gray-900 mb-2">Training Information</h4>
                    <div className="space-y-2">
                      <div>
                        <p className="text-xs text-gray-600">Date</p>
                        <p className="text-sm text-gray-900 font-medium">{selectedNotification.trainingDate}</p>
                      </div>
                      {selectedNotification.trainingTopic && (
                        <div>
                          <p className="text-xs text-gray-600">Topic</p>
                          <p className="text-sm text-gray-900 font-medium">{selectedNotification.trainingTopic}</p>
                        </div>
                      )}
                    </div>
                  </div>
                )}

                {selectedNotification.equipmentType && (
                  <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                    <h4 className="text-sm font-semibold text-gray-900 mb-2">Equipment Details</h4>
                    <div>
                      <p className="text-xs text-gray-600">Equipment</p>
                      <p className="text-sm text-gray-900 font-medium">{selectedNotification.equipmentType}</p>
                    </div>
                  </div>
                )}

                <div className="flex gap-2 pt-4 border-t border-gray-200">
                  <Button 
                    className="flex-1 bg-teal-500 hover:bg-teal-600 text-white"
                    onClick={() => {
                      // Handle action based on notification type
                      setIsDetailOpen(false);
                    }}
                  >
                    Take Action
                  </Button>
                  {selectedNotification.status === "unread" && (
                    <Button 
                      variant="outline"
                      className="border-gray-300 text-gray-700 hover:bg-gray-100"
                      onClick={(e) => {
                        e.stopPropagation();
                        handleMarkAsRead(e, selectedNotification.id);
                      }}
                    >
                      Mark as Read
                    </Button>
                  )}
                  {selectedNotification.farmerName && (
                    <Button variant="outline" className="border-gray-300 text-gray-700 hover:bg-gray-100">
                      <Phone className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { getUserId, getPhoneNumber, getEmail } from "@/services/authAPI";
import { getUserById, updateUserProfile, getUserProfile } from "@/services/usersAPI";
import { useToast } from "@/hooks/use-toast";
import { 
  User, 
  MapPin, 
  Mail, 
  Phone, 
  Shield, 
  Key, 
  Bell, 
  Globe,
  Save,
  Eye,
  EyeOff,
  Upload,
  Camera,
  Award,
  Calendar,
  Map,
  GraduationCap
} from "lucide-react";

export default function AssessorProfileSettings() {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("profile");
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  // Get logged-in assessor data from localStorage
  const assessorId = getUserId() || "";
  const assessorPhone = getPhoneNumber() || "";
  const assessorEmail = getEmail() || "";

  const [profileData, setProfileData] = useState({
    fullName: assessorEmail || assessorPhone || "Assessor",
    assessorId: assessorId || "",
    email: assessorEmail || "",
    phone: assessorPhone || "",
    address: "",
    specialization: "",
    experience: "",
    licenseNumber: "",
    certificationDate: "",
    bio: ""
  });

  // Load user data from localStorage and API on component mount
  useEffect(() => {
    // Update profile data with real user information from localStorage
    setProfileData(prev => ({
      ...prev,
      fullName: assessorEmail || assessorPhone || "Assessor",
      assessorId: assessorId || "",
      email: assessorEmail || "",
      phone: assessorPhone || "",
    }));

    // Fetch full user profile from API if userId is available
    const loadUserProfile = async () => {
      if (!assessorId) {
        setLoading(false);
        return;
      }
      
      setLoading(true);
      try {
        // Try to get user profile first (current user's own profile)
        let userData: any;
        try {
          userData = await getUserProfile();
        } catch (err) {
          // If getUserProfile fails, try getUserById
          userData = await getUserById(assessorId);
        }
        
        const user = userData.data || userData;
        
        if (user) {
          // Update profile with full user data
          setProfileData(prev => ({
            ...prev,
            fullName: `${user.firstName || ''} ${user.lastName || ''}`.trim() || user.email || user.phoneNumber || assessorEmail || assessorPhone || "Assessor",
            assessorId: user._id || user.id || assessorId || "",
            email: user.email || assessorEmail || "",
            phone: user.phoneNumber || assessorPhone || "",
            address: user.assessorProfile?.address || user.address || user.province || user.district || prev.address || "",
            specialization: user.assessorProfile?.specialization || prev.specialization || "",
            experience: user.assessorProfile?.experienceYears ? `${user.assessorProfile.experienceYears} years` : prev.experience || "",
            licenseNumber: user.assessorProfile?.licenseNumber || prev.licenseNumber || "",
            certificationDate: user.assessorProfile?.certificationDate || prev.certificationDate || "",
            bio: user.assessorProfile?.bio || prev.bio || "",
          }));

          // Load work preferences from assessor profile
          if (user.assessorProfile) {
            setWorkData(prev => ({
              ...prev,
              assignedRegion: user.assessorProfile.assignedRegion || user.province || user.district || prev.assignedRegion || "",
              maxAssessmentsPerDay: user.assessorProfile.maxAssessmentsPerDay?.toString() || prev.maxAssessmentsPerDay || "3",
              preferredWorkingHours: user.assessorProfile.preferredWorkingHours || prev.preferredWorkingHours || "08:00-17:00",
              vehicleType: user.assessorProfile.vehicleType || prev.vehicleType || "",
              equipment: user.assessorProfile.equipment || prev.equipment || [],
              languages: user.assessorProfile.languages || prev.languages || [],
            }));
          }
        }
      } catch (err: any) {
        console.error('Failed to load user profile:', err);
        toast({
          title: 'Error loading profile',
          description: err.message || 'Failed to load profile data',
          variant: 'destructive'
        });
      } finally {
        setLoading(false);
      }
    };

    loadUserProfile();
  }, [assessorId, assessorEmail, assessorPhone]);

  const [workData, setWorkData] = useState({
    assignedRegion: "",
    maxAssessmentsPerDay: "3",
    preferredWorkingHours: "08:00-17:00",
    vehicleType: "",
    equipment: [] as string[],
    languages: [] as string[]
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [securityData, setSecurityData] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
    twoFactorEnabled: false,
    sessionTimeout: "30"
  });

  const [notificationSettings, setNotificationSettings] = useState({
    emailNotifications: true,
    smsNotifications: true,
    pushNotifications: true,
    assignmentAlerts: true,
    dueDateReminders: true,
    trainingAlerts: true,
    equipmentAlerts: false,
    performanceReports: true,
    weatherAlerts: true
  });

  const handleProfileUpdate = (field: string, value: string) => {
    setProfileData(prev => ({ ...prev, [field]: value }));
  };

  const handleWorkUpdate = (field: string, value: string) => {
    setWorkData(prev => ({ ...prev, [field]: value }));
  };

  const handleSecurityUpdate = (field: string, value: string | boolean) => {
    setSecurityData(prev => ({ ...prev, [field]: value }));
  };

  const handleNotificationUpdate = (field: string, value: boolean) => {
    setNotificationSettings(prev => ({ ...prev, [field]: value }));
  };

  const handleSaveChanges = async () => {
    if (!assessorId) {
      toast({
        title: 'Error',
        description: 'User ID not found. Please log in again.',
        variant: 'destructive'
      });
      return;
    }

    setSaving(true);
    try {
      // Prepare update data
      const updateData: any = {
        firstName: profileData.fullName.split(' ')[0] || '',
        lastName: profileData.fullName.split(' ').slice(1).join(' ') || '',
        email: profileData.email,
        phoneNumber: profileData.phone,
        address: profileData.address,
        assessorProfile: {
          address: profileData.address,
          specialization: profileData.specialization,
          experienceYears: profileData.experience ? parseInt(profileData.experience.replace(' years', '')) : undefined,
          licenseNumber: profileData.licenseNumber,
          certificationDate: profileData.certificationDate,
          bio: profileData.bio,
          assignedRegion: workData.assignedRegion,
          maxAssessmentsPerDay: parseInt(workData.maxAssessmentsPerDay) || 3,
          preferredWorkingHours: workData.preferredWorkingHours,
          vehicleType: workData.vehicleType,
          equipment: workData.equipment,
          languages: workData.languages,
        }
      };

      // Remove undefined values
      Object.keys(updateData).forEach(key => {
        if (updateData[key] === undefined || updateData[key] === '') {
          delete updateData[key];
        }
      });

      Object.keys(updateData.assessorProfile).forEach(key => {
        if (updateData.assessorProfile[key] === undefined || updateData.assessorProfile[key] === '') {
          delete updateData.assessorProfile[key];
        }
      });

      await updateUserProfile(updateData);

      toast({
        title: 'Success',
        description: 'Profile updated successfully',
      });

      // Reload profile data
      const userData: any = await getUserProfile().catch(() => getUserById(assessorId));
      const user = userData.data || userData;
      if (user) {
        setProfileData(prev => ({
          ...prev,
          fullName: `${user.firstName || ''} ${user.lastName || ''}`.trim() || user.email || user.phoneNumber || assessorEmail || assessorPhone || "Assessor",
          email: user.email || assessorEmail || "",
          phone: user.phoneNumber || assessorPhone || "",
          address: user.assessorProfile?.address || user.address || prev.address || "",
          specialization: user.assessorProfile?.specialization || prev.specialization || "",
          experience: user.assessorProfile?.experienceYears ? `${user.assessorProfile.experienceYears} years` : prev.experience || "",
          licenseNumber: user.assessorProfile?.licenseNumber || prev.licenseNumber || "",
          certificationDate: user.assessorProfile?.certificationDate || prev.certificationDate || "",
          bio: user.assessorProfile?.bio || prev.bio || "",
        }));

        if (user.assessorProfile) {
          setWorkData(prev => ({
            ...prev,
            assignedRegion: user.assessorProfile.assignedRegion || user.province || user.district || prev.assignedRegion || "",
            maxAssessmentsPerDay: user.assessorProfile.maxAssessmentsPerDay?.toString() || prev.maxAssessmentsPerDay || "3",
            preferredWorkingHours: user.assessorProfile.preferredWorkingHours || prev.preferredWorkingHours || "08:00-17:00",
            vehicleType: user.assessorProfile.vehicleType || prev.vehicleType || "",
            equipment: user.assessorProfile.equipment || prev.equipment || [],
            languages: user.assessorProfile.languages || prev.languages || [],
          }));
        }
      }
    } catch (err: any) {
      console.error('Failed to update profile:', err);
      toast({
        title: 'Error updating profile',
        description: err.message || 'Failed to update profile',
        variant: 'destructive'
      });
    } finally {
      setSaving(false);
    }
  };

  const renderProfileTab = () => (
    <div className="space-y-6">
      <Card className="bg-white border border-gray-200 shadow-sm">
        <CardHeader className="border-b border-gray-200 bg-gray-50">
          <CardTitle className="text-base font-semibold text-gray-900">Personal Information</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 pt-6">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="fullName">Full Name</Label>
              <Input
                id="fullName"
                value={profileData.fullName}
                onChange={(e) => handleProfileUpdate('fullName', e.target.value)}
                className="bg-gray-50 border-gray-300 text-gray-900"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="assessorId">Assessor ID</Label>
              <Input
                id="assessorId"
                value={profileData.assessorId}
                disabled
                className="bg-gray-100 border-gray-300 text-gray-600"
              />
            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="email">Email Address</Label>
              <Input
                id="email"
                type="email"
                value={profileData.email}
                onChange={(e) => handleProfileUpdate('email', e.target.value)}
                className="bg-gray-50 border-gray-300 text-gray-900"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="phone">Phone Number</Label>
              <Input
                id="phone"
                value={profileData.phone}
                onChange={(e) => handleProfileUpdate('phone', e.target.value)}
                className="bg-gray-50 border-gray-300 text-gray-900"
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="address">Address</Label>
            <Input
              id="address"
              value={profileData.address}
              onChange={(e) => handleProfileUpdate('address', e.target.value)}
              className="bg-gray-50 border-gray-300 text-gray-900"
            />
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const renderWorkTab = () => (
    <div className="space-y-6">
      <Card className="bg-white border border-gray-200 shadow-sm">
        <CardHeader className="border-b border-gray-200 bg-gray-50">
          <CardTitle className="flex items-center text-gray-900 text-base font-semibold">
            <Map className="h-5 w-5 mr-2 text-gray-600" />
            Work Preferences
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 pt-6">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="assignedRegion">Assigned Region</Label>
              <Select value={workData.assignedRegion} onValueChange={(value) => handleWorkUpdate('assignedRegion', value)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
