                      <td className="py-4 px-6">
                        <div className="flex gap-2">
                          {monitoring.status === 'IN_PROGRESS' && (
                            <>
                              <Button
                                size="sm"
                                onClick={() => {
                                  setSelectedMonitoring(monitoring);
                                  setUpdateData({
