                                className="bg-blue-600 hover:bg-blue-700 text-white text-xs"
                              >
                                Update
                              </Button>
                              <Button
                                size="sm"
                                onClick={() => handleGenerateReport(monitoring._id)}
                                disabled={generateReportLoading}
                                className="bg-teal-600 hover:bg-teal-700 text-white text-xs"
                              >
