                  <Select
                    value={editUserData.sex}
                    onValueChange={(value) =>
                      setEditUserData({ ...editUserData, sex: value })
                    }
                  >
                    <SelectTrigger className={dashboardTheme.select}>
                      <SelectValue placeholder="Select sex" />
                    </SelectTrigger>
                    <SelectContent className={dashboardTheme.card}>
                      <SelectItem value="MALE">Male</SelectItem>
                      <SelectItem value="FEMALE">Female</SelectItem>
                      <SelectItem value="OTHER">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div>
                <Label
                  htmlFor="editActive"
                  className="text-gray-900 flex items-center gap-2"
                >
                  <input
                    id="editActive"
                    type="checkbox"
                    checked={editUserData.active}
                    onChange={(e) =>
                      setEditUserData({
                        ...editUserData,
                        active: e.target.checked,
                      })
                    }
                    className="w-4 h-4"
                  />
                  Active
                </Label>
              </div>

              {/* Role-specific Profile Fields */}

              {selectedUser.role === "ASSESSOR" && (
                <div className="space-y-4 mt-4 pt-4 border-t border-gray-300">
                  <h3 className="text-gray-900 font-semibold">
                    Assessor Profile
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label
                        htmlFor="editSpecialization"
                        className="text-gray-900"
                      >
                        Specialization
                      </Label>
                      <Input
                        id="editSpecialization"
                        value={editUserData.assessorProfile.specialization}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            assessorProfile: {
                              ...editUserData.assessorProfile,
                              specialization: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="Specialization"
                      />
                    </div>
                    <div>
                      <Label
                        htmlFor="editExperienceYears"
                        className="text-gray-900"
                      >
                        Experience Years
                      </Label>
                      <Input
                        id="editExperienceYears"
                        type="number"
                        value={editUserData.assessorProfile.experienceYears}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            assessorProfile: {
                              ...editUserData.assessorProfile,
                              experienceYears: parseInt(e.target.value) || 0,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="0"
                      />
                    </div>
                  </div>
                  <div>
                    <Label
                      htmlFor="editProfilePhotoUrl"
                      className="text-gray-900"
                    >
                      Profile Photo URL
                    </Label>
                    <Input
                      id="editProfilePhotoUrl"
                      value={editUserData.assessorProfile.profilePhotoUrl}
                      onChange={(e) =>
                        setEditUserData({
                          ...editUserData,
                          assessorProfile: {
                            ...editUserData.assessorProfile,
                            profilePhotoUrl: e.target.value,
                          },
                        })
                      }
                      className={`${dashboardTheme.input} border-gray-300`}
                      placeholder="https://example.com/photo.jpg"
                    />
                  </div>
                  <div>
                    <Label htmlFor="editAddress" className="text-gray-900">
                      Address
                    </Label>
                    <Input
                      id="editAddress"
                      value={editUserData.assessorProfile.address}
                      onChange={(e) =>
                        setEditUserData({
                          ...editUserData,
                          assessorProfile: {
                            ...editUserData.assessorProfile,
                            address: e.target.value,
                          },
                        })
                      }
                      className={`${dashboardTheme.input} border-gray-300`}
                      placeholder="Address"
                    />
                  </div>
                  <div>
                    <Label htmlFor="editBio" className="text-gray-900">
                      Bio
                    </Label>
                    <Textarea
                      id="editBio"
                      value={editUserData.assessorProfile.bio}
                      onChange={(e) =>
                        setEditUserData({
                          ...editUserData,
                          assessorProfile: {
                            ...editUserData.assessorProfile,
                            bio: e.target.value,
                          },
                        })
                      }
                      className={`${dashboardTheme.input} border-gray-300 min-h-[100px]`}
                      placeholder="Bio"
                    />
                  </div>
                </div>
              )}

              {selectedUser.role === "INSURER" && (
                <div className="space-y-4 mt-4 pt-4 border-t border-gray-300">
                  <h3 className="text-gray-900 font-semibold">
                    Insurer Profile
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label
                        htmlFor="editCompanyName"
                        className="text-gray-900"
                      >
                        Company Name
                      </Label>
                      <Input
                        id="editCompanyName"
                        value={editUserData.insurerProfile.companyName}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              companyName: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="Company Name"
                      />
                    </div>
                    <div>
                      <Label
                        htmlFor="editContactPerson"
                        className="text-gray-900"
                      >
                        Contact Person
                      </Label>
                      <Input
                        id="editContactPerson"
                        value={editUserData.insurerProfile.contactPerson}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              contactPerson: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="Contact Person"
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="editWebsite" className="text-gray-900">
                        Website
                      </Label>
                      <Input
                        id="editWebsite"
                        value={editUserData.insurerProfile.website}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              website: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="https://example.com"
                      />
                    </div>
                    <div>
                      <Label
                        htmlFor="editInsurerAddress"
                        className="text-gray-900"
                      >
                        Address
                      </Label>
                      <Input
                        id="editInsurerAddress"
                        value={editUserData.insurerProfile.address}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              address: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="Company Address"
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label
                        htmlFor="editLicenseNumber"
                        className="text-gray-900"
                      >
                        License Number
                      </Label>
                      <Input
                        id="editLicenseNumber"
                        value={editUserData.insurerProfile.licenseNumber}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              licenseNumber: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                        placeholder="License Number"
                      />
                    </div>
                    <div>
                      <Label
                        htmlFor="editRegistrationDate"
                        className="text-gray-900"
                      >
                        Registration Date
                      </Label>
                      <Input
                        id="editRegistrationDate"
                        type="date"
                        value={editUserData.insurerProfile.registrationDate}
                        onChange={(e) =>
                          setEditUserData({
                            ...editUserData,
                            insurerProfile: {
                              ...editUserData.insurerProfile,
                              registrationDate: e.target.value,
                            },
                          })
                        }
                        className={`${dashboardTheme.input} border-gray-300`}
                      />
                    </div>
                  </div>
                  <div>
                    <Label
                      htmlFor="editCompanyLogoUrl"
                      className="text-gray-900"
                    >
                      Company Logo URL
                    </Label>
                    <Input
                      id="editCompanyLogoUrl"
                      value={editUserData.insurerProfile.companyLogoUrl}
                      onChange={(e) =>
                        setEditUserData({
                          ...editUserData,
                          insurerProfile: {
                            ...editUserData.insurerProfile,
                            companyLogoUrl: e.target.value,
                          },
                        })
                      }
                      className={`${dashboardTheme.input} border-gray-300`}
                      placeholder="https://example.com/logo.png"
                    />
                  </div>
                  <div>
                    <Label
                      htmlFor="editCompanyDescription"
                      className="text-gray-900"
                    >
                      Company Description
                    </Label>
                    <Textarea
                      id="editCompanyDescription"
                      value={editUserData.insurerProfile.companyDescription}
                      onChange={(e) =>
                        setEditUserData({
                          ...editUserData,
                          insurerProfile: {
                            ...editUserData.insurerProfile,
                            companyDescription: e.target.value,
                          },
                        })
                      }
                      className={`${dashboardTheme.input} border-gray-300 min-h-[100px]`}
                      placeholder="Company description and overview"
                    />
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex justify-end gap-3 pt-4 border-t border-gray-800">
                <Button
                  variant="outline"
                  onClick={() => {
                    setShowEditUserDialog(false);
                    setSelectedUser(null);
                  }}
                  className="border-gray-300 text-gray-900 hover:bg-gray-100"
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleUpdateUser}
                  disabled={editingUser}
                  className="bg-red-600 hover:bg-red-700 text-gray-900"
                >
                  {editingUser ? (
                    <>
                      <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                      Updating...
                    </>
                  ) : (
                    <>
                      <Edit className="h-4 w-4 mr-2" />
                      Update User
                    </>
                  )}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Error Message */}
      {usersError && (
        <Card className={`${dashboardTheme.card} border-l-4 border-l-red-500`}>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <AlertTriangle className="h-5 w-5 text-red-400" />
                <p className="text-red-400">{usersError}</p>
              </div>
              <Button
                onClick={loadUsers}
                variant="outline"
                size="sm"
                className="border-gray-300 text-gray-900 hover:bg-gray-100"
              >
                <RefreshCw className="h-4 w-4 mr-2" />
                Retry
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* User Stats - Compact Design */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card
          className={`${dashboardTheme.card} p-4 hover:shadow-md transition-shadow`}
        >
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-xs font-medium text-gray-500 uppercase tracking-wide mb-1">
                Total Users
              </p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold text-gray-900">
                  {userStats.total.toLocaleString()}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1.5">All roles</p>
            </div>
            <div className="w-10 h-10 rounded-lg bg-blue-50 flex items-center justify-center">
              <Users className="h-5 w-5 text-blue-600" />
            </div>
          </div>
        </Card>

        <Card
          className={`${dashboardTheme.card} p-4 hover:shadow-md transition-shadow`}
        >
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-xs font-medium text-gray-500 uppercase tracking-wide mb-1">
                Active
              </p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold text-gray-900">
                  {userStats.active.toLocaleString()}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1.5">
                <span className="font-medium text-green-600">
                  {userStats.total > 0
                    ? ((userStats.active / userStats.total) * 100).toFixed(1)
                    : 0}
                  %
                </span>{" "}
                active rate
              </p>
            </div>
            <div className="w-10 h-10 rounded-lg bg-green-50 flex items-center justify-center">
              <CheckCircle className="h-5 w-5 text-green-600" />
            </div>
          </div>
        </Card>

        <Card
          className={`${dashboardTheme.card} p-4 hover:shadow-md transition-shadow`}
        >
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-xs font-medium text-gray-500 uppercase tracking-wide mb-1">
                Inactive
              </p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold text-gray-900">
                  {userStats.inactive.toLocaleString()}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1.5">Need attention</p>
            </div>
            <div className="w-10 h-10 rounded-lg bg-yellow-50 flex items-center justify-center">
              <AlertCircle className="h-5 w-5 text-yellow-600" />
            </div>
          </div>
        </Card>

        <Card
          className={`${dashboardTheme.card} p-4 hover:shadow-md transition-shadow`}
        >
          <div className="flex items-center justify-between">
            <div className="flex-1">
              <p className="text-xs font-medium text-gray-500 uppercase tracking-wide mb-1">
                New This Month
              </p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold text-gray-900">
                  {userStats.newThisMonth}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1.5">This month</p>
            </div>
            <div className="w-10 h-10 rounded-lg bg-purple-50 flex items-center justify-center">
              <TrendingUp className="h-5 w-5 text-purple-600" />
            </div>
          </div>
        </Card>
      </div>

      <Card className="bg-white border-gray-200 shadow-sm">
        <CardHeader className="border-b border-gray-200 bg-gray-50">
          <div className="flex items-center justify-between">
            <CardTitle className="text-xl font-semibold text-gray-900">
              All Users
            </CardTitle>
            <div className="flex items-center gap-3">
              <div className="text-sm text-gray-600">
                {filteredUsers.length}{" "}
                {filteredUsers.length === 1 ? "user" : "users"}
              </div>
              <Button
                className="bg-red-600 hover:bg-red-700"
                onClick={() => setShowAddUserDialog(true)}
              >
                <UserPlus className="h-4 w-4 mr-2" />
                Add User
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <div className="p-4 border-b border-gray-200 bg-white">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search users by name, email, or role..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-300 rounded-lg text-gray-900 placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent transition-all"
              />
            </div>
          </div>
          {usersLoading ? (
            <Card className={dashboardTheme.card}>
              <CardContent className="p-0">
                <TableSkeleton rows={5} columns={5} />
              </CardContent>
            </Card>
          ) : filteredUsers.length === 0 ? (
            <div className="flex items-center justify-center py-16">
              <div className="text-center">
                <Users className="h-16 w-16 mx-auto mb-4 text-gray-300" />
                <p className="text-gray-600 font-medium mb-1">No users found</p>
                <p className="text-sm text-gray-500 mb-4">
                  {searchQuery
                    ? "Try adjusting your search criteria"
                    : "No users available"}
                </p>
                {searchQuery && (
                  <Button
                    onClick={() => setSearchQuery("")}
                    variant="outline"
                    size="sm"
                    className="border-gray-300 text-gray-700 hover:bg-gray-50"
                  >
                    Clear Search
                  </Button>
                )}
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50 border-b border-gray-200">
                    <th className="text-left py-4 px-6 text-gray-700 font-semibold text-xs uppercase tracking-wider">
                      User
                    </th>
                    <th className="text-left py-4 px-6 text-gray-700 font-semibold text-xs uppercase tracking-wider">
                      Contact
                    </th>
                    <th className="text-left py-4 px-6 text-gray-700 font-semibold text-xs uppercase tracking-wider">
                      Role
                    </th>
                    <th className="text-left py-4 px-6 text-gray-700 font-semibold text-xs uppercase tracking-wider">
                      Location
                    </th>
                    <th className="text-left py-4 px-6 text-gray-700 font-semibold text-xs uppercase tracking-wider">
                      Status
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {filteredUsers
                    .filter((user) => user != null)
                    .map((user, index) => (
                      <tr
                        key={user?.id || user?._id || index}
                        className={`hover:bg-gray-50 transition-colors ${
                          index % 2 === 0 ? "bg-white" : "bg-gray-50/30"
                        }`}
                      >
                        <td className="py-4 px-6 whitespace-nowrap">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-gradient-to-br from-red-500 to-orange-600 rounded-full flex items-center justify-center text-white text-sm font-semibold shadow-sm">
                              {(() => {
                                const nameStr =
                                  typeof user.name === "string"
                                    ? user.name
                                    : typeof user.firstName === "string"
                                      ? user.firstName
                                      : typeof user.lastName === "string"
                                        ? user.lastName
                                        : "U";
                                return nameStr.charAt(0).toUpperCase();
                              })()}
                            </div>
                            <div>
                              <div className="text-sm font-semibold text-gray-900">
                                {(() => {
                                  if (typeof user.name === "string")
                                    return user.name;
                                  const firstName =
                                    typeof user.firstName === "string"
                                      ? user.firstName
                                      : "";
                                  const lastName =
                                    typeof user.lastName === "string"
                                      ? user.lastName
                                      : "";
                                  const fullName =
                                    `${firstName} ${lastName}`.trim();
                                  return fullName || "Unknown User";
                                })()}
                              </div>
                              <div className="text-xs text-gray-500 mt-0.5">
                                {user.userId || user.id || user._id || "N/A"}
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="py-4 px-6 whitespace-nowrap">
                          <div className="space-y-1">
                            <div className="text-sm text-gray-900 flex items-center gap-1.5">
                              <Mail className="h-3.5 w-3.5 text-gray-400" />
                              {typeof user.email === "string"
                                ? user.email
                                : "N/A"}
                            </div>
                            {user.phoneNumber &&
                              typeof user.phoneNumber === "string" && (
                                <div className="text-xs text-gray-600 flex items-center gap-1.5">
                                  <Phone className="h-3 w-3 text-gray-400" />
                                  {user.phoneNumber}
                                </div>
                              )}
                          </div>
                        </td>
                        <td className="py-4 px-6 whitespace-nowrap">
                          <Badge
                            className={`text-xs font-medium px-2.5 py-1 ${
                              user.role === "FARMER" || user.role === "Farmer"
                                ? "bg-green-100 text-green-700 border-green-300"
                                : user.role === "ASSESSOR" ||
                                    user.role === "Assessor"
                                  ? "bg-orange-100 text-orange-700 border-orange-300"
                                  : user.role === "INSURER" ||
                                      user.role === "Insurer"
                                    ? "bg-blue-100 text-blue-700 border-blue-300"
                                    : user.role === "GOVERNMENT" ||
                                        user.role === "Government"
                                      ? "bg-purple-100 text-purple-700 border-purple-300"
                                      : user.role === "ADMIN" ||
                                          user.role === "Admin"
                                        ? "bg-red-100 text-red-700 border-red-300"
                                        : "bg-gray-100 text-gray-700 border-gray-300"
                            } border`}
                          >
                            {typeof user.role === "string" ? user.role : "N/A"}
                          </Badge>
                        </td>
                        <td className="py-4 px-6 whitespace-nowrap">
                          <div className="text-sm text-gray-900">
                            {(() => {
                              // Safely extract location string from various possible structures
                              if (
                                typeof user.region === "string" &&
                                user.region
                              )
                                return user.region;
                              if (
                                typeof user.province === "string" &&
                                user.province
                              )
                                return user.province;
                              if (
                                typeof user.district === "string" &&
                                user.district
                              )
                                return user.district;
                              if (
                                typeof user.sector === "string" &&
                                user.sector
                              )
                                return user.sector;
                              if (
                                typeof user.location === "string" &&
                                user.location
                              )
                                return user.location;
                              return "N/A";
                            })()}
                          </div>
                        </td>
                        <td className="py-4 px-6 whitespace-nowrap">
                          <Badge
                            className={`text-xs font-medium px-2.5 py-1 border ${
                              user.active !== false
                                ? "bg-green-100 text-green-700 border-green-300"
                                : "bg-gray-100 text-gray-700 border-gray-300"
                            }`}
                          >
                            <span
                              className={`w-1.5 h-1.5 rounded-full mr-1.5 inline-block ${
                                user.active !== false
                                  ? "bg-green-500"
                                  : "bg-gray-400"
                              }`}
                            ></span>
                            {user.active !== false ? "Active" : "Inactive"}
                          </Badge>
                        </td>
                      </tr>
                    ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );

  // Financial Management Page
  const renderFinancialManagement = () => (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Financial Management
          </h1>
          <p className="text-sm text-gray-600 mt-1">
            Track platform revenue and commission earnings
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            onClick={loadAdminStatistics}
            variant="outline"
            className="border-gray-300 text-gray-900 hover:bg-gray-100"
            disabled={statsLoading}
          >
            <RefreshCw
              className={`h-4 w-4 mr-2 ${statsLoading ? "animate-spin" : ""}`}
            />
            Refresh
          </Button>
          <Button className="bg-red-600 hover:bg-red-700">
            <Download className="h-4 w-4 mr-2" />
            Export Report
          </Button>
        </div>
      </div>

      {/* Loading State */}
      {statsLoading && (
        <Card className={dashboardTheme.card}>
          <CardContent className="p-8 text-center">
            <img
              src="/loading.gif"
              alt="Loading"
              className="w-16 h-16 mx-auto"
            />
          </CardContent>
        </Card>
      )}

      {/* Error State */}
      {statsError && !statsLoading && (
        <Card className={`${dashboardTheme.card} border-l-4 border-l-red-500`}>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <AlertTriangle className="h-5 w-5 text-red-400" />
                <p className="text-red-400">{statsError}</p>
              </div>
              <Button
                onClick={loadAdminStatistics}
                variant="outline"
                size="sm"
                className="border-gray-300 text-gray-900 hover:bg-gray-100"
              >
                <RefreshCw className="h-4 w-4 mr-2" />
                Retry
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Policy Overview Section */}
      {policyOverview && !statsLoading && (
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Policy Overview
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Total Policies</p>
                <p className="text-2xl font-bold text-gray-900">
                  {policyOverview.totalPolicies ||
                    policyOverview.policies?.total ||
                    0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Active Policies</p>
                <p className="text-2xl font-bold text-gray-900">
                  {policyOverview.activePolicies ||
                    policyOverview.policies?.active ||
                    0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Total Premium</p>
                <p className="text-2xl font-bold text-gray-900">
                  RWF{" "}
                  {policyOverview.totalPremium
                    ? (policyOverview.totalPremium / 1000000).toFixed(1)
                    : policyOverview.policies?.totalPremium
                      ? (
                          policyOverview.policies.totalPremium / 1000000
                        ).toFixed(1)
                      : 0}
                  M
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Pending Claims</p>
                <p className="text-2xl font-bold text-gray-900">
                  {policyOverview.pendingClaims ||
                    policyOverview.policies?.pendingClaims ||
                    0}
                </p>
              </div>
            </div>
            {policyOverview.policies && (
              <div className="mt-4 text-sm text-gray-900/60">
                <pre className="bg-gray-50 border border-gray-200 p-4 rounded-lg overflow-auto text-gray-700">
                  {JSON.stringify(policyOverview.policies, null, 2)}
                </pre>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Claim Statistics Section */}
      {claimStats && !statsLoading && (
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <AlertTriangle className="h-5 w-5" />
              Claim Statistics
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Total Claims</p>
                <p className="text-2xl font-bold text-gray-900">
                  {claimStats.totalClaims || claimStats.claims?.total || 0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Pending Claims</p>
                <p className="text-2xl font-bold text-gray-900">
                  {claimStats.pendingClaims || claimStats.claims?.pending || 0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Approved Claims</p>
                <p className="text-2xl font-bold text-gray-900">
                  {claimStats.approvedClaims ||
                    claimStats.claims?.approved ||
                    0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-900/60 mb-1">Total Paid</p>
                <p className="text-2xl font-bold text-gray-900">
                  RWF{" "}
                  {claimStats.totalPaid
                    ? (claimStats.totalPaid / 1000000).toFixed(1)
                    : claimStats.claims?.totalPaid
                      ? (claimStats.claims.totalPaid / 1000000).toFixed(1)
                      : 0}
                  M
                </p>
              </div>
            </div>
            {claimStats.claims && (
              <div className="mt-4 text-sm text-gray-900/60">
                <pre className="bg-gray-50 border border-gray-200 p-4 rounded-lg overflow-auto text-gray-700">
                  {JSON.stringify(claimStats.claims, null, 2)}
                </pre>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      <div className="grid gap-6 md:grid-cols-4">
        <Card
          className={`${dashboardTheme.card} border-l-4 border-l-green-500`}
        >
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">
              Total Revenue
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">
              RWF{" "}
              {systemStats?.totalRevenue
                ? (systemStats.totalRevenue / 1000000).toFixed(1)
                : (financialData.totalRevenue / 1000000).toFixed(1)}
              M
            </div>
            <p className="text-xs text-green-400 mt-1">All-time earnings</p>
          </CardContent>
        </Card>
        <Card className={`${dashboardTheme.card} border-l-4 border-l-blue-500`}>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">
              This Month
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">
              RWF{" "}
              {systemStats?.monthlyRevenue
                ? (systemStats.monthlyRevenue / 1000000).toFixed(1)
                : (financialData.monthlyRevenue / 1000000).toFixed(1)}
              M
            </div>
            <p className="text-xs text-green-400 mt-1">
              +{systemStats?.revenueGrowth || financialData.growthRate}% growth
            </p>
          </CardContent>
        </Card>
        <Card
          className={`${dashboardTheme.card} border-l-4 border-l-purple-500`}
        >
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">
              Commission
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">
              RWF{" "}
              {systemStats?.commissionEarned
                ? (systemStats.commissionEarned / 1000).toFixed(0)
                : (financialData.commissionEarned / 1000).toFixed(0)}
              K
            </div>
            <p className="text-xs text-gray-900/60 mt-1">This month</p>
          </CardContent>
        </Card>
        <Card
          className={`${dashboardTheme.card} border-l-4 border-l-yellow-500`}
        >
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">Pending</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">
              RWF{" "}
              {systemStats?.pendingPayments
                ? (systemStats.pendingPayments / 1000).toFixed(0)
                : (financialData.pendingPayments / 1000).toFixed(0)}
              K
            </div>
            <p className="text-xs text-gray-900/60 mt-1">To be collected</p>
          </CardContent>
        </Card>
      </div>

      <Card className={dashboardTheme.card}>
        <CardHeader>
          <CardTitle className="text-gray-900">Revenue Trends</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={revenueTrends}>
                <defs>
                  <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10B981" stopOpacity={0.8} />
                    <stop offset="95%" stopColor="#10B981" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient
                    id="colorCommission"
                    x1="0"
                    y1="0"
                    x2="0"
                    y2="1"
                  >
                    <stop offset="5%" stopColor="#8B5CF6" stopOpacity={0.8} />
                    <stop offset="95%" stopColor="#8B5CF6" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                <XAxis dataKey="month" stroke="#9CA3AF" />
                <YAxis stroke="#9CA3AF" />
                <Tooltip
                  contentStyle={{
                    backgroundColor: "#1F2937",
                    border: "1px solid #374151",
                    borderRadius: "8px",
                  }}
                  labelStyle={{ color: "#F9FAFB" }}
                  formatter={(value: number) =>
                    `RWF ${(value / 1000000).toFixed(1)}M`
                  }
                />
                <Legend />
                <Area
                  type="monotone"
                  dataKey="revenue"
                  stroke="#10B981"
                  fillOpacity={1}
                  fill="url(#colorRevenue)"
                  name="Revenue"
                />
                <Area
                  type="monotone"
                  dataKey="commission"
                  stroke="#8B5CF6"
                  fillOpacity={1}
                  fill="url(#colorCommission)"
                  name="Commission"
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      <Card className={dashboardTheme.card}>
        <CardHeader>
          <CardTitle className="text-gray-900">
            Commission Rate Settings
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-gray-300">
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Type
                  </th>
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Rate
                  </th>
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Total Revenue
                  </th>
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Commission Earned
                  </th>
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Status
                  </th>
                  <th className="text-left py-3 px-4 text-gray-900/80 font-medium">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody>
                {commissionRates.map((item, idx) => (
                  <tr
                    key={idx}
                    className="border-b border-gray-800 hover:bg-gray-100/50"
                  >
                    <td className="py-3 px-4 text-gray-900 font-medium">
                      {item.type}
                    </td>
                    <td className="py-3 px-4">
                      <Badge className="bg-purple-600">{item.rate}%</Badge>
                    </td>
                    <td className="py-3 px-4 text-gray-900">
                      RWF {(item.revenue / 1000000).toFixed(1)}M
                    </td>
                    <td className="py-3 px-4 text-green-400 font-medium">
                      RWF {(item.commission / 1000000).toFixed(1)}M
                    </td>
                    <td className="py-3 px-4">
                      <Badge className="bg-green-600">{item.status}</Badge>
                    </td>
                    <td className="py-3 px-4">
                      <Button
                        variant="ghost"
                        size="sm"
                        className="text-gray-900/60 hover:text-gray-900"
                      >
                        <Edit className="h-4 w-4" />
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  // System Configuration Page
  const renderSystemConfig = () => (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold text-gray-900">
          System Configuration
        </h1>
        <p className="text-sm text-gray-600 mt-1">
          Configure platform settings and preferences
        </p>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Server className="h-5 w-5" />
              Server Settings
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {[
              { label: "Server Status", value: "Online", status: "success" },
              {
                label: "Database Size",
                value: `${systemMetrics.dbSize} GB`,
                status: "info",
              },
              { label: "API Version", value: "v2.4.1", status: "info" },
              {
                label: "Backup Status",
                value: "Last: 2 hours ago",
                status: "success",
              },
            ].map((item, idx) => (
              <div
                key={idx}
                className="flex items-center justify-between p-3 bg-gray-50 border border-gray-200 rounded-lg"
              >
                <span className="text-sm text-gray-900/80">{item.label}</span>
                <Badge
                  className={`${
                    item.status === "success"
                      ? "bg-green-600"
                      : item.status === "warning"
                        ? "bg-yellow-600"
                        : "bg-blue-600"
                  }`}
                >
                  {item.value}
                </Badge>
              </div>
            ))}
          </CardContent>
        </Card>

        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Database className="h-5 w-5" />
              Database Management
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <Button className="w-full bg-blue-600 hover:bg-blue-700">
              <RefreshCw className="h-4 w-4 mr-2" />
              Backup Database
            </Button>
            <Button className="w-full bg-green-600 hover:bg-green-700">
              <Upload className="h-4 w-4 mr-2" />
              Restore from Backup
            </Button>
            <Button className="w-full bg-purple-600 hover:bg-purple-700">
              <Download className="h-4 w-4 mr-2" />
              Export Data
            </Button>
            <Button
              variant="outline"
              className="w-full border-gray-300 text-gray-900 hover:bg-gray-100"
            >
              <Settings className="h-4 w-4 mr-2" />
              Database Settings
            </Button>
          </CardContent>
        </Card>

        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Lock className="h-5 w-5" />
              Security Settings
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {[
              { label: "Two-Factor Authentication", enabled: true },
              { label: "IP Whitelisting", enabled: true },
              { label: "SSL/TLS Encryption", enabled: true },
              { label: "Session Timeout", enabled: true },
            ].map((item, idx) => (
              <div
                key={idx}
                className="flex items-center justify-between p-3 bg-gray-50 border border-gray-200 rounded-lg"
              >
                <span className="text-sm text-gray-900/80">{item.label}</span>
                <div
                  className={`w-12 h-6 rounded-full ${item.enabled ? "bg-green-600" : "bg-gray-600"} relative cursor-pointer`}
                >
                  <div
                    className={`absolute w-5 h-5 bg-white rounded-full top-0.5 transition-all ${item.enabled ? "right-0.5" : "left-0.5"}`}
                  />
                </div>
              </div>
            ))}
          </CardContent>
        </Card>

        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Bell className="h-5 w-5" />
              Notification Settings
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {[
              { label: "System Alerts", enabled: true },
              { label: "Security Alerts", enabled: true },
              { label: "Performance Alerts", enabled: true },
              { label: "User Activity Alerts", enabled: false },
            ].map((item, idx) => (
              <div
                key={idx}
                className="flex items-center justify-between p-3 bg-gray-50 border border-gray-200 rounded-lg"
              >
                <span className="text-sm text-gray-900/80">{item.label}</span>
                <div
                  className={`w-12 h-6 rounded-full ${item.enabled ? "bg-red-600" : "bg-gray-600"} relative cursor-pointer`}
                >
                  <div
                    className={`absolute w-5 h-5 bg-white rounded-full top-0.5 transition-all ${item.enabled ? "right-0.5" : "left-0.5"}`}
                  />
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      </div>
    </div>
  );

  // Activity Logs Page
  const renderActivityLogs = () => (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Activity Logs</h1>
          <p className="text-sm text-gray-600 mt-1">
            Monitor all system activities and user actions
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            className="border-gray-300 text-gray-900 hover:bg-gray-100"
          >
            <Filter className="h-4 w-4 mr-2" />
            Filter
          </Button>
          <Button className="bg-red-600 hover:bg-red-700">
            <Download className="h-4 w-4 mr-2" />
            Export Logs
          </Button>
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-4">
        <Card className={`${dashboardTheme.card} border-l-4 border-l-blue-500`}>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">
              Total Events
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">15,247</div>
            <p className="text-xs text-gray-900/60 mt-1">Last 30 days</p>
          </CardContent>
        </Card>
        <Card
          className={`${dashboardTheme.card} border-l-4 border-l-green-500`}
        >
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">Success</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">14,892</div>
            <p className="text-xs text-green-400 mt-1">97.7% success rate</p>
          </CardContent>
        </Card>
        <Card
          className={`${dashboardTheme.card} border-l-4 border-l-yellow-500`}
        >
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">Warnings</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">298</div>
            <p className="text-xs text-gray-900/60 mt-1">Need review</p>
          </CardContent>
        </Card>
        <Card className={`${dashboardTheme.card} border-l-4 border-l-red-500`}>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-900/80">Errors</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-gray-900">57</div>
            <p className="text-xs text-red-400 mt-1">0.4% error rate</p>
          </CardContent>
        </Card>
      </div>

      <Card className={dashboardTheme.card}>
        <CardHeader>
          <CardTitle className="text-gray-900">Recent Activity</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {recentActivities.map((activity) => (
              <div
                key={activity.id}
                className={`p-4 rounded-lg border-l-4 ${
                  activity.severity === "success"
                    ? "bg-green-500/10 border-l-green-500"
                    : activity.severity === "warning"
                      ? "bg-yellow-500/10 border-l-yellow-500"
                      : activity.severity === "error"
                        ? "bg-red-500/10 border-l-red-500"
                        : "bg-blue-500/10 border-l-blue-500"
                }`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                      <Badge
                        className={`${
                          activity.severity === "success"
                            ? "bg-green-600"
                            : activity.severity === "warning"
                              ? "bg-yellow-600"
                              : activity.severity === "error"
                                ? "bg-red-600"
                                : "bg-blue-600"
                        }`}
                      >
                        {activity.type.toUpperCase()}
                      </Badge>
                      <span className="text-xs text-gray-900/60">
                        {activity.timestamp}
                      </span>
                    </div>
                    <h4 className="text-sm font-semibold text-gray-900 mb-1">
                      {activity.action}
                    </h4>
                    <p className="text-xs text-gray-900/70">
                      User: {activity.user} • {activity.details}
                    </p>
                  </div>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="text-gray-900/60 hover:text-gray-900"
                  >
                    <Eye className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );

  // Analytics Page
  const renderAnalytics = () => (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Platform Analytics
          </h1>
          <p className="text-sm text-gray-600 mt-1">
            Deep insights into platform performance and usage
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            className="border-gray-300 text-gray-900 hover:bg-gray-100"
          >
            <Calendar className="h-4 w-4 mr-2" />
            Last 30 Days
          </Button>
          <Button className="bg-red-600 hover:bg-red-700">
            <Download className="h-4 w-4 mr-2" />
            Export Analytics
          </Button>
        </div>
      </div>

      {/* Loading State */}
      {statsLoading && (
        <Card className={dashboardTheme.card}>
          <CardContent className="p-8 text-center">
            <img
              src="/loading.gif"
              alt="Loading"
              className="w-16 h-16 mx-auto"
            />
          </CardContent>
        </Card>
      )}

      {/* Error State */}
      {statsError && !statsLoading && (
        <Card className={`${dashboardTheme.card} border-l-4 border-l-red-500`}>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <AlertTriangle className="h-5 w-5 text-red-400" />
                <p className="text-red-400">{statsError}</p>
              </div>
              <Button
                onClick={loadAdminStatistics}
                variant="outline"
                size="sm"
                className="border-gray-300 text-gray-900 hover:bg-gray-100"
              >
                <RefreshCw className="h-4 w-4 mr-2" />
                Retry
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* System Statistics Section */}
      {!statsLoading && (
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Activity className="h-5 w-5" />
              System Statistics
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                <p className="text-sm text-gray-600 mb-1">Total Users</p>
                <p className="text-2xl font-bold text-gray-900">
                  {systemStats?.totalUsers ||
                    systemStats?.users?.total ||
                    analyticsUsers.length ||
                    0}
                </p>
              </div>
              <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
