                          if (insurer.firstName && insurer.lastName) {
                            return `${insurer.firstName} ${insurer.lastName}`;
                          }
                          if (insurer.firstName) return insurer.firstName;
                          if (insurer.lastName) return insurer.lastName;
                          if (typeof insurer.name === "string")
