  // Handle Insurance Request
  const handleRequestInsurance = async () => {
    if (!insuranceRequestDialog.farmId) return;

    setIsRequestingInsurance(true);
    try {
      await createInsuranceRequest(
        insuranceRequestDialog.farmId,
