                              ? "bg-green-100 text-green-700 border border-green-200"
                              : assessment.riskScore < 75 
                              ? "bg-yellow-100 text-yellow-700 border border-yellow-200"
                              : "bg-red-100 text-red-700 border border-red-200"
                          }`}>
                            {assessment.riskScore || "N/A"}
                          </Badge>
                        </td>
                        <td className="py-1 px-2 text-gray-700 text-xs">
                          {assessment.submittedAt || assessment.completedAt
                            ? new Date(assessment.submittedAt || assessment.completedAt).toLocaleDateString()
                            : "N/A"}
                        </td>
                        <td className="py-1 px-2">
                          <div className="flex items-center gap-1">
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => setApproveRejectDialog({ open: true, assessment, action: 'approve' })}
                              className="border-green-600 text-green-600 hover:bg-green-50 text-xs h-6 px-2"
                            >
                              <CheckCircle className="h-2.5 w-2.5 mr-0.5" />
                              Approve
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => setApproveRejectDialog({ open: true, assessment, action: 'reject' })}
                              className="border-red-600 text-red-600 hover:bg-red-50 text-xs h-6 px-2"
                            >
                              <AlertTriangle className="h-2.5 w-2.5 mr-0.5" />
                              Reject
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => setCreatePolicyDialog({ open: true, assessment })}
                              className="border-blue-600 text-blue-600 hover:bg-blue-50 text-xs h-6 px-2"
                            >
                              <Shield className="h-2.5 w-2.5 mr-0.5" />
                              Policy
                            </Button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );

  const [policyKey, setPolicyKey] = useState(0);

  const renderPage = () => {
    switch (activePage) {
      case "dashboard": return renderDashboard();
      case "insurance-requests": return renderInsuranceRequests();
      case "submitted-assessments": return renderSubmittedAssessments();
      case "risk-reviews": return <RiskReviewManagement />;
      case "claim-reviews": return <ClaimsTable />;
      case "claim-review-detail": return <ClaimReviewPage />;
      case "policy-management": return <PolicyManagement key={policyKey} onNavigateToCreate={() => setActivePage('create-policy')} />;
      case "create-policy": return <CreatePolicyPage onBack={() => { setActivePage('policy-management'); setPolicyKey(prev => prev + 1); }} onSuccess={() => { setActivePage('policy-management'); setPolicyKey(prev => prev + 1); }} />;
      case "risk-assessments": return <RiskAssessmentSystem />;
      case "notifications": return <InsurerNotifications />;
      case "profile-settings": return <InsurerProfileSettings />;
      default: return renderDashboard();
    }
  };

  const navigationItems = [
    { id: "dashboard", label: "Dashboard", icon: BarChart3 },
    { id: "insurance-requests", label: "Insurance Requests", icon: Shield },
    { id: "submitted-assessments", label: "Submitted Assessments", icon: CheckCircle },
    { id: "risk-reviews", label: "Risk Reviews", icon: Shield },
    { id: "claim-reviews", label: "Claim Reviews", icon: FileText },
    { id: "policy-management", label: "Policy Management", icon: CheckCircle },
    { id: "risk-assessments", label: "Risk Assessments", icon: AlertTriangle },
    { id: "notifications", label: "Notifications", icon: Bell },
    { id: "profile-settings", label: "Profile Settings", icon: Settings }
  ];

  // Get display name from profile if available
  const displayName = insurerProfile 
    ? (insurerProfile.firstName && insurerProfile.lastName 
        ? `${insurerProfile.firstName} ${insurerProfile.lastName}`.trim()
        : insurerProfile.name || insurerProfile.firstName || insurerProfile.lastName || insurerName)
    : insurerName;

  return (
    <DashboardLayout
      userType="insurer"
      userId={insurerId}
      userName={displayName}
      navigationItems={navigationItems}
      activePage={activePage}
      onPageChange={setActivePage}
      onLogout={() => {
        // Clear localStorage and redirect to login
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        localStorage.removeItem('userId');
        localStorage.removeItem('phoneNumber');
        localStorage.removeItem('email');
        window.location.href = '/role-selection';
      }}
    >
      {renderPage()}

      {/* Create Assessment Dialog */}
      <Dialog open={createAssessmentDialog.open} onOpenChange={(open) => {
        if (!open) {
          // Clear form when dialog closes
          setAssessorId("");
          setAssessmentNotes("");
          setAssessors([]);
        }
        setCreateAssessmentDialog({ ...createAssessmentDialog, open });
      }}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="text-gray-900">Create Assessment</DialogTitle>
            <DialogDescription className="text-gray-600">
              Assign an assessor to evaluate this insurance request
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 mt-4">
            {createAssessmentDialog.insuranceRequest && (
              <div className="bg-gray-50 p-4 rounded-lg space-y-2">
                <div className="text-sm">
                  <span className="text-gray-600">Farm: </span>
                  <span className="font-medium text-gray-900">
                    {(createAssessmentDialog.insuranceRequest.farmId || createAssessmentDialog.insuranceRequest.farm)?.name || "N/A"}
                  </span>
                </div>
                <div className="text-sm">
                  <span className="text-gray-600">Crop Type: </span>
                  <span className="font-medium text-gray-900">
                    {(createAssessmentDialog.insuranceRequest.farmId || createAssessmentDialog.insuranceRequest.farm)?.cropType || "N/A"}
                  </span>
                </div>
              </div>
            )}
            <div>
              <Label className="text-gray-700">Select Assessor *</Label>
              {assessorsLoading ? (
                <div className="flex items-center justify-center py-4">
                  <img src="/loading.gif" alt="Loading" className="w-12 h-12" />
                </div>
              ) : assessors.length === 0 ? (
                <div className="space-y-2">
                  <Input
                    value={assessorId}
                    onChange={(e) => setAssessorId(e.target.value)}
                    placeholder="Enter assessor ID manually"
                    className="mt-2 border-gray-300"
                    required
                  />
                  <p className="text-xs text-gray-500 mt-1">Could not load assessors list. Please enter assessor ID manually.</p>
                </div>
              ) : (
                <Select 
                  value={assessorId || undefined} 
                  onValueChange={setAssessorId}
                  required
                >
                  <SelectTrigger className="mt-2 border-gray-300">
                    <SelectValue placeholder="Select an assessor" />
                  </SelectTrigger>
                  <SelectContent>
                    {assessors.map((assessor: any) => {
                      const assessorIdValue = assessor._id || assessor.id;
                      if (!assessorIdValue) return null;
                      
                      const assessorName = assessor.firstName && assessor.lastName
                        ? `${assessor.firstName} ${assessor.lastName}`
                        : assessor.name || assessor.email || assessor.phoneNumber || 'Unknown Assessor';
                      
                      return (
                        <SelectItem key={assessorIdValue} value={assessorIdValue}>
                          {assessorName} {assessor.email ? `(${assessor.email})` : ''}
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              )}
            </div>
            <div>
              <Label className="text-gray-700">Notes (Optional)</Label>
              <Textarea
                value={assessmentNotes}
                onChange={(e) => setAssessmentNotes(e.target.value)}
                placeholder="Add any notes for the assessor..."
                className="mt-2 border-gray-300"
                rows={4}
              />
            </div>
            <div className="flex gap-3 justify-end">
              <Button
                variant="outline"
                onClick={() => {
                  setCreateAssessmentDialog({ open: false, insuranceRequest: null });
                  setAssessorId("");
                  setAssessmentNotes("");
                  setAssessors([]);
                }}
                className="border-gray-300 text-gray-700 hover:bg-gray-100"
              >
                Cancel
              </Button>
              <Button
                onClick={handleCreateAssessment}
                disabled={isCreatingAssessment || !assessorId}
                className="bg-green-600 hover:bg-green-700 text-white"
              >
                {isCreatingAssessment ? (
                  <>
                    <Clock className="h-4 w-4 mr-2 animate-spin" />
                    Creating...
                  </>
                ) : (
                  <>
                    <Shield className="h-4 w-4 mr-2" />
                    Create Assessment
                  </>
                )}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Approve/Reject Assessment Dialog */}
      <Dialog open={approveRejectDialog.open} onOpenChange={(open) => {
        if (!open) {
          setRejectionReason("");
        }
        setApproveRejectDialog({ ...approveRejectDialog, open });
      }}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="text-gray-900">
              {approveRejectDialog.action === 'approve' ? 'Approve Assessment' : 'Reject Assessment'}
            </DialogTitle>
            <DialogDescription className="text-gray-600">
              {approveRejectDialog.action === 'approve' 
                ? 'Are you sure you want to approve this assessment? You can create a policy after approval.'
                : 'Please provide a reason for rejecting this assessment.'}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 mt-4">
            {approveRejectDialog.assessment && (
              <div className="bg-gray-50 p-4 rounded-lg space-y-2">
                <div className="text-sm">
                  <span className="text-gray-600">Farm: </span>
                  <span className="font-medium text-gray-900">
                    {(approveRejectDialog.assessment.farmId || approveRejectDialog.assessment.farm)?.name || "N/A"}
                  </span>
                </div>
                <div className="text-sm">
                  <span className="text-gray-600">Crop Type: </span>
                  <span className="font-medium text-gray-900">
                    {(approveRejectDialog.assessment.farmId || approveRejectDialog.assessment.farm)?.cropType || "N/A"}
                  </span>
                </div>
                <div className="text-sm">
                  <span className="text-gray-600">Risk Score: </span>
                  <span className="font-medium text-gray-900">
                    {approveRejectDialog.assessment.riskScore || "N/A"}
                  </span>
                </div>
              </div>
            )}
            
            {approveRejectDialog.action === 'reject' && (
              <div>
                <Label htmlFor="rejectionReason" className="text-gray-900">Rejection Reason *</Label>
                <Textarea
                  id="rejectionReason"
                  value={rejectionReason}
                  onChange={(e) => setRejectionReason(e.target.value)}
                  placeholder="Enter reason for rejection..."
                  className="mt-1 min-h-[100px]"
                  required
                />
              </div>
            )}
            
            <div className="flex justify-end gap-2 pt-4">
              <Button
                variant="outline"
                onClick={() => {
                  setApproveRejectDialog({ open: false, assessment: null, action: null });
                  setRejectionReason("");
                }}
                className="border-gray-300 text-gray-900 hover:bg-gray-100"
              >
                Cancel
              </Button>
              {approveRejectDialog.action === 'approve' ? (
                <Button
                  onClick={handleApproveAssessment}
                  disabled={processingApproval}
                  className="bg-green-600 hover:bg-green-700 text-white"
                >
                  {processingApproval ? (
                    <>
                      <Clock className="h-4 w-4 mr-2 animate-spin" />
                      Approving...
                    </>
                  ) : (
                    <>
                      <CheckCircle className="h-4 w-4 mr-2" />
                      Approve Assessment
                    </>
                  )}
                </Button>
              ) : (
                <Button
                  onClick={handleRejectAssessment}
                  disabled={processingApproval || !rejectionReason.trim()}
                  className="bg-red-600 hover:bg-red-700 text-white"
                >
                  {processingApproval ? (
                    <>
                      <Clock className="h-4 w-4 mr-2 animate-spin" />
                      Rejecting...
                    </>
                  ) : (
                    <>
                      <AlertTriangle className="h-4 w-4 mr-2" />
                      Reject Assessment
                    </>
                  )}
                </Button>
              )}
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Create Policy Dialog */}
      <Dialog open={createPolicyDialog.open} onOpenChange={(open) =>
        setCreatePolicyDialog({ ...createPolicyDialog, open })
      }>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="text-gray-900">Create Policy from Assessment</DialogTitle>
            <DialogDescription className="text-gray-600">
              Create an insurance policy based on the submitted assessment
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 mt-4">
            {createPolicyDialog.assessment && (
              <div className="bg-gray-50 p-4 rounded-lg space-y-2">
                <div className="text-sm">
                  <span className="text-gray-600">Farm: </span>
                  <span className="font-medium text-gray-900">
                    {(createPolicyDialog.assessment.farmId || createPolicyDialog.assessment.farm)?.name || "N/A"}
                  </span>
                </div>
                <div className="text-sm">
                  <span className="text-gray-600">Risk Score: </span>
                  <span className="font-medium text-gray-900">
                    {createPolicyDialog.assessment.riskScore || "N/A"}
                  </span>
                </div>
              </div>
            )}
            <div>
              <Label className="text-gray-700">Coverage Level *</Label>
              <Select value={coverageLevel} onValueChange={(value: "BASIC" | "STANDARD" | "PREMIUM") => setCoverageLevel(value)}>
                <SelectTrigger className="mt-2 border-gray-300">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="BASIC">Basic</SelectItem>
                  <SelectItem value="STANDARD">Standard</SelectItem>
                  <SelectItem value="PREMIUM">Premium</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-gray-700">Start Date *</Label>
              <Input
                type="date"
                value={policyStartDate}
                onChange={(e) => setPolicyStartDate(e.target.value)}
                className="mt-2 border-gray-300"
                required
              />
            </div>
            <div>
              <Label className="text-gray-700">End Date *</Label>
              <Input
                type="date"
                value={policyEndDate}
                onChange={(e) => setPolicyEndDate(e.target.value)}
                className="mt-2 border-gray-300"
                required
              />
            </div>
            <div className="flex gap-3 justify-end">
              <Button
                variant="outline"
                onClick={() => {
                  setCreatePolicyDialog({ open: false, assessment: null });
                  setCoverageLevel("STANDARD");
                  setPolicyStartDate("");
                  setPolicyEndDate("");
                }}
                className="border-gray-300 text-gray-700 hover:bg-gray-100"
              >
                Cancel
              </Button>
              <Button
                onClick={handleCreatePolicy}
                disabled={isCreatingPolicy || !policyStartDate || !policyEndDate}
                className="bg-green-600 hover:bg-green-700 text-white"
              >
                {isCreatingPolicy ? (
                  <>
                    <Clock className="h-4 w-4 mr-2 animate-spin" />
                    Creating...
                  </>
                ) : (
                  <>
                    <Shield className="h-4 w-4 mr-2" />
                    Create Policy
                  </>
                )}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { approveClaim as approveClaimApi, rejectClaim as rejectClaimApi, getClaimById, getClaims } from "@/services/claimsApi";
import { useToast } from "@/hooks/use-toast";
import { 
  ArrowLeft,
  FileText, 
  User, 
  MapPin, 
  Calendar,
  DollarSign,
  Camera,
  Download,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Clock,
  Eye,
  MessageSquare,
  Phone,
  Mail,
  Building2,
  Crop,
  TrendingUp,
  Shield
} from "lucide-react";

export default function ClaimReviewPage() {
  const { toast } = useToast();
  const [selectedClaimId, setSelectedClaimId] = useState<string>("");
  const [claims, setClaims] = useState<any[]>([]);
  const [currentClaim, setCurrentClaim] = useState<any | null>(null);
  const [loading, setLoading] = useState(true);
  const [loadingClaim, setLoadingClaim] = useState(false);
  const [reviewDecision, setReviewDecision] = useState("");
  const [reviewComments, setReviewComments] = useState("");
  const [approvedAmount, setApprovedAmount] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Load claims list
  useEffect(() => {
    loadClaims();
  }, []);

  // Load specific claim when selected
  useEffect(() => {
    if (selectedClaimId) {
      loadClaimDetails(selectedClaimId);
    }
  }, [selectedClaimId]);

  const loadClaims = async () => {
    setLoading(true);
    try {
      const response: any = await getClaims(1, 100);
      let claimsData: any[] = [];
      
      if (Array.isArray(response)) {
        claimsData = response;
      } else if (response && typeof response === 'object') {
        claimsData = response.data || response.claims || [];
      }
      
      setClaims(claimsData);
      // Auto-select first pending claim if available
      const firstPending = claimsData.find((c: any) => c.status === 'pending_review' || c.status === 'pending');
      if (firstPending && !selectedClaimId) {
        setSelectedClaimId(firstPending._id || firstPending.id);
      }
    } catch (err: any) {
      console.error('Failed to load claims:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to load claims',
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const loadClaimDetails = async (claimId: string) => {
    setLoadingClaim(true);
    try {
      const response: any = await getClaimById(claimId);
      const claimData = response.data || response;
      setCurrentClaim(claimData);
    } catch (err: any) {
      console.error('Failed to load claim details:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to load claim details',
        variant: "destructive",
      });
    } finally {
      setLoadingClaim(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "pending_review": return "bg-yellow-100 text-yellow-800";
      case "approved": return "bg-green-100 text-green-800";
      case "rejected": return "bg-red-100 text-red-800";
      case "under_investigation": return "bg-blue-100 text-blue-800";
      default: return "bg-gray-100 text-gray-700 border border-gray-200";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "pending_review": return <Clock className="h-4 w-4" />;
      case "approved": return <CheckCircle className="h-4 w-4" />;
      case "rejected": return <XCircle className="h-4 w-4" />;
      case "under_investigation": return <AlertTriangle className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  const handleSubmitReview = async () => {
    if (!reviewDecision || !reviewComments) {
      toast({
        title: "Error",
        description: "Please provide both decision and comments",
        variant: "destructive",
      });
      return;
    }

    if (!selectedClaimId) {
      toast({
        title: "Error",
        description: "No claim selected",
        variant: "destructive",
      });
      return;
    }

    setIsSubmitting(true);
    try {
      if (reviewDecision === "approve") {
        const amount = approvedAmount ? parseFloat(approvedAmount) : undefined;
        await approveClaimApi(selectedClaimId, amount, reviewComments);
        toast({
          title: "Success",
          description: "Claim approved successfully",
          variant: "default",
        });
        // Reload claims
        loadClaims();
        if (selectedClaimId) {
          loadClaimDetails(selectedClaimId);
        }
      } else if (reviewDecision === "reject") {
        await rejectClaimApi(selectedClaimId, reviewComments);
        toast({
          title: "Success",
          description: "Claim rejected successfully",
          variant: "default",
        });
        // Reload claims
        loadClaims();
        if (selectedClaimId) {
          loadClaimDetails(selectedClaimId);
        }
      }
    } catch (err: any) {
      console.error('Failed to submit review:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to submit review',
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
    
    // Reset form
    setReviewDecision("");
    setReviewComments("");
    setApprovedAmount("");
  };

  const renderClaimSummary = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <FileText className="h-5 w-5 mr-2" />
          Claim Summary
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Claim ID</Label>
            <p className="text-lg font-semibold">{currentClaim?._id || currentClaim?.id || 'N/A'}</p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700 dark:text-gray-400">Status</Label>
            <div className="mt-1">
              <Badge className={getStatusColor(currentClaim?.status || "")}>
                {getStatusIcon(currentClaim?.status || "")}
                <span className="ml-1 capitalize">{currentClaim?.status?.replace('_', ' ')}</span>
              </Badge>
            </div>
          </div>
        </div>

        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700 dark:text-gray-400">Claim Amount</Label>
            <p className="text-lg font-semibold text-green-600">
              {(currentClaim?.amount || currentClaim?.claimAmount || 0).toLocaleString()} RWF
            </p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700 dark:text-gray-400">Filed Date</Label>
            <p className="text-lg">{currentClaim?.filedDate || currentClaim?.createdAt || 'N/A'}</p>
          </div>
        </div>

        <div>
          <Label className="text-sm font-medium text-gray-700 dark:text-gray-400">Description</Label>
          <p className="text-gray-900 mt-1">{currentClaim?.description || currentClaim?.lossDescription || 'No description available'}</p>
        </div>
      </CardContent>
    </Card>
  );

  const renderFarmerInfo = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <User className="h-5 w-5 mr-2" />
          Farmer Information
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Farmer Name</Label>
            <p className="text-lg font-semibold">
              {currentClaim?.farmer?.firstName && currentClaim?.farmer?.lastName
                ? `${currentClaim.farmer.firstName} ${currentClaim.farmer.lastName}`
                : currentClaim?.farmer?.name || currentClaim?.farmerName || 'Unknown Farmer'}
            </p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Farmer ID</Label>
            <p className="text-lg">{currentClaim?.farmerId || currentClaim?.farmer?._id || currentClaim?.farmer?.id || 'N/A'}</p>
          </div>
        </div>

        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Location</Label>
            <p className="text-gray-900">{currentClaim?.location || currentClaim?.farm?.location || 'N/A'}</p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Farm Size</Label>
            <p className="text-gray-900">{currentClaim?.farmSize || currentClaim?.farm?.size || 'N/A'} {currentClaim?.farmSize ? 'hectares' : ''}</p>
          </div>
        </div>

        <div className="flex space-x-4">
          <Button variant="outline" size="sm">
            <Phone className="h-4 w-4 mr-2" />
            Call Farmer
          </Button>
          <Button variant="outline" size="sm">
            <Mail className="h-4 w-4 mr-2" />
            Send Email
          </Button>
        </div>
      </CardContent>
    </Card>
  );

  const renderPolicyInfo = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <Shield className="h-5 w-5 mr-2" />
          Policy Information
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Policy ID</Label>
            <p className="text-lg font-semibold">{currentClaim?.policyId}</p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Crop Type</Label>
            <p className="text-lg">{currentClaim?.cropType}</p>
          </div>
        </div>

        <div className="grid gap-4 md:grid-cols-3">
          <div>
            <Label className="text-sm font-medium text-gray-700">Coverage</Label>
            <p className="text-lg font-semibold text-blue-600">
              {(currentClaim?.policy?.coverageAmount || currentClaim?.policy?.coverage || currentClaim?.policyDetails?.coverage || 0).toLocaleString()} RWF
            </p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Premium</Label>
            <p className="text-lg">{(currentClaim?.policy?.premiumAmount || currentClaim?.policy?.premium || currentClaim?.policyDetails?.premium || 0).toLocaleString()} RWF</p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Deductible</Label>
            <p className="text-lg">{(currentClaim?.policy?.deductible || currentClaim?.policyDetails?.deductible || 0).toLocaleString()} RWF</p>
          </div>
        </div>

        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Policy Start</Label>
            <p className="text-gray-900">{currentClaim?.policy?.startDate || currentClaim?.policy?.validityPeriod?.start || currentClaim?.policyDetails?.startDate || 'N/A'}</p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Policy End</Label>
            <p className="text-gray-900">{currentClaim?.policy?.endDate || currentClaim?.policy?.validityPeriod?.end || currentClaim?.policy?.validityPeriod || currentClaim?.policyDetails?.endDate || 'N/A'}</p>
          </div>
        </div>
      </CardContent>
    </Card>
  );

  const renderAssessmentInfo = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <TrendingUp className="h-5 w-5 mr-2" />
          Assessment Information
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <Label className="text-sm font-medium text-gray-700">Assessor</Label>
            <p className="text-lg font-semibold">
              {currentClaim?.assessor?.firstName && currentClaim?.assessor?.lastName
                ? `${currentClaim.assessor.firstName} ${currentClaim.assessor.lastName}`
                : currentClaim?.assessor?.name || currentClaim?.assessorName || 'Unassigned'}
            </p>
          </div>
          <div>
            <Label className="text-sm font-medium text-gray-700">Assessment Date</Label>
            <p className="text-lg">{currentClaim?.assessmentDate || currentClaim?.assessment?.date || currentClaim?.createdAt || 'N/A'}</p>
          </div>
        </div>

        <div>
          <Label className="text-sm font-medium text-gray-700">Assessment Notes</Label>
          <p className="text-gray-900 mt-1">{currentClaim?.assessmentNotes || currentClaim?.assessment?.notes || currentClaim?.notes || 'No assessment notes available'}</p>
        </div>

        <div className="flex space-x-4">
          <Button variant="outline" size="sm">
            <Phone className="h-4 w-4 mr-2" />
            Call Assessor
          </Button>
          <Button variant="outline" size="sm">
            <MessageSquare className="h-4 w-4 mr-2" />
            Message Assessor
          </Button>
        </div>
      </CardContent>
    </Card>
  );

  const renderPhotos = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <Camera className="h-5 w-5 mr-2" />
          Field Photos
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {currentClaim?.photos && Array.isArray(currentClaim.photos) && currentClaim.photos.length > 0 ? (
            currentClaim.photos.map((photo: any, index: number) => (
              <div key={photo.id || photo._id || index} className="space-y-2">
                <div className="aspect-video bg-gray-100 rounded-lg overflow-hidden">
                  <img 
                    src={photo.url || photo.photoUrl || photo.src || '/api/placeholder/400/300'} 
                    alt={photo.description || photo.alt || 'Claim photo'}
                    className="w-full h-full object-cover hover:scale-105 transition-transform cursor-pointer"
                  />
                </div>
                <p className="text-sm text-gray-700 text-center">{photo.description || 'Claim photo'}</p>
              </div>
            ))
          ) : currentClaim?.damagePhotos && Array.isArray(currentClaim.damagePhotos) && currentClaim.damagePhotos.length > 0 ? (
            currentClaim.damagePhotos.map((photoUrl: string, index: number) => (
              <div key={index} className="space-y-2">
                <div className="aspect-video bg-gray-100 rounded-lg overflow-hidden">
                  <img 
                    src={photoUrl || '/api/placeholder/400/300'} 
                    alt="Claim photo"
                    className="w-full h-full object-cover hover:scale-105 transition-transform cursor-pointer"
                  />
                </div>
                <p className="text-sm text-gray-700 text-center">Damage photo {index + 1}</p>
              </div>
            ))
          ) : (
            <p className="text-gray-500 col-span-full text-center py-8">No photos available</p>
          )}
        </div>
      </CardContent>
    </Card>
  );

  const renderDocuments = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <FileText className="h-5 w-5 mr-2" />
          Supporting Documents
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {currentClaim?.documents && Array.isArray(currentClaim.documents) && currentClaim.documents.length > 0 ? (
            currentClaim.documents.map((doc: any, index: number) => (
              <div key={doc.id || doc._id || index} className="flex items-center justify-between p-3 border rounded-lg">
                <div className="flex items-center space-x-3">
                  <FileText className="h-5 w-5 text-gray-400" />
                  <div>
                    <p className="font-medium text-white">{doc.name || doc.fileName || 'Document'}</p>
                    <p className="text-sm text-gray-500">{doc.type || 'File'} • {doc.size || 'N/A'}</p>
                  </div>
                </div>
                <Button variant="outline" size="sm">
                  <Download className="h-4 w-4 mr-2" />
                  Download
                </Button>
              </div>
            ))
          ) : (
            <p className="text-gray-500 text-center py-8">No documents available</p>
          )}
        </div>
      </CardContent>
    </Card>
  );

  const renderReviewForm = () => (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center">
          <CheckCircle className="h-5 w-5 mr-2" />
          Claim Review Decision
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="reviewDecision">Decision</Label>
          <Select value={reviewDecision} onValueChange={setReviewDecision}>
            <SelectTrigger>
              <SelectValue placeholder="Select decision" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="approved">Approve Claim</SelectItem>
              <SelectItem value="rejected">Reject Claim</SelectItem>
              <SelectItem value="partial_approval">Partial Approval</SelectItem>
              <SelectItem value="requires_more_info">Requires More Information</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {reviewDecision === "partial_approval" && (
          <div className="space-y-2">
            <Label htmlFor="approvedAmount">Approved Amount (RWF)</Label>
            <Input
              id="approvedAmount"
              type="number"
              value={approvedAmount}
              onChange={(e) => setApprovedAmount(e.target.value)}
              placeholder="Enter approved amount"
            />
          </div>
        )}

        <div className="space-y-2">
          <Label htmlFor="reviewComments">Review Comments</Label>
          <Textarea
            id="reviewComments"
            value={reviewComments}
            onChange={(e) => setReviewComments(e.target.value)}
            placeholder="Provide detailed comments about your decision..."
            rows={4}
          />
        </div>

        <div className="flex space-x-4">
          <Button 
            onClick={handleSubmitReview}
            disabled={isSubmitting || !reviewDecision || !reviewComments}
            className="bg-green-600 hover:bg-green-700"
          >
            {isSubmitting ? "Submitting..." : "Submit Review"}
          </Button>
          <Button variant="outline">
            Save as Draft
          </Button>
        </div>
      </CardContent>
    </Card>
  );

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4">
        <Button 
          variant="ghost" 
          onClick={() => window.history.back()}
          className="text-gray-600 hover:text-gray-700 mb-2"
        >
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Claims
        </Button>
        <h1 className="text-2xl font-bold text-gray-900">Claim Review</h1>
        <p className="text-sm text-gray-600 mt-1">Review and make decisions on insurance claims</p>
      </div>
        
      <div className="flex items-center space-x-2">
          {loading ? (
            <div className="text-gray-500">Loading claims...</div>
          ) : (
            <Select value={selectedClaimId} onValueChange={setSelectedClaimId}>
              <SelectTrigger className="w-48">
                <SelectValue placeholder="Select a claim" />
              </SelectTrigger>
              <SelectContent>
                {claims.length === 0 ? (
                  <SelectItem value="none" disabled>No claims available</SelectItem>
                ) : (
                  claims.map((claim: any) => (
                    <SelectItem key={claim._id || claim.id} value={claim._id || claim.id}>
                      {claim._id || claim.id} - {claim.farmer?.firstName && claim.farmer?.lastName
                        ? `${claim.farmer.firstName} ${claim.farmer.lastName}`
                        : claim.farmer?.name || claim.farmerName || 'Unknown Farmer'}
                    </SelectItem>
                  ))
                )}
              </SelectContent>
            </Select>
          )}
      </div>

      {/* Loading State */}
      {loadingClaim ? (
        <div className="flex items-center justify-center py-12">
          <div className="text-center">
            <Clock className="h-12 w-12 animate-spin text-blue-500 mx-auto mb-4" />
            <p className="text-gray-500">Loading claim details...</p>
          </div>
        </div>
      ) : !currentClaim ? (
        <div className="flex items-center justify-center py-12">
          <div className="text-center">
            <FileText className="h-12 w-12 mx-auto mb-4 text-white/40" />
            <p className="text-gray-500">Please select a claim to review</p>
          </div>
        </div>
      ) : (
        <>
          {/* Alert for pending review */}
          {(currentClaim?.status === "pending_review" || currentClaim?.status === "pending") && (
            <Alert>
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription>
                This claim is pending review. Please review all information and make a decision.
              </AlertDescription>
            </Alert>
          )}

          {/* Main Content Grid */}
          <div className="grid gap-6 lg:grid-cols-3">
            {/* Left Column - Claim Details */}
            <div className="lg:col-span-2 space-y-6">
              {renderClaimSummary()}
              {renderFarmerInfo()}
              {renderPolicyInfo()}
              {renderAssessmentInfo()}
              {renderPhotos()}
              {renderDocuments()}
            </div>

            {/* Right Column - Review Form */}
            <div className="space-y-6">
              {renderReviewForm()}
              
              {/* Quick Actions */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg">Quick Actions</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3">
                  <Button variant="outline" className="w-full justify-start">
                    <Eye className="h-4 w-4 mr-2" />
                    View Full Assessment Report
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <MapPin className="h-4 w-4 mr-2" />
                    View Field Location
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <Calendar className="h-4 w-4 mr-2" />
                    Schedule Follow-up Visit
                  </Button>
                  <Button variant="outline" className="w-full justify-start">
                    <MessageSquare className="h-4 w-4 mr-2" />
                    Contact All Parties
                  </Button>
                </CardContent>
              </Card>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { getClaims } from "@/services/claimsApi";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { 
  ChevronLeft, 
  ChevronRight,
  Eye,
  User,
  MapPin,
  Calendar,
  DollarSign,
  AlertTriangle,
  CheckCircle,
  Clock,
  Phone,
  Mail,
  FileText
} from "lucide-react";

interface Claim {
  id: string;
  farmerId: string;
  farmerName: string;
  policyId: string;
  cropType: string;
  claimAmount: number;
  status: string;
  filedDate: string;
  incidentDate: string;
  description: string;
  location: string;
  assessorId: string;
  assessorName: string;
  priority: string;
}

export default function ClaimsCarousel() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [claims, setClaims] = useState<Claim[]>([]);
  const [loading, setLoading] = useState(true);

  // Load claims from API
  useEffect(() => {
    loadClaims();
  }, []);

  const loadClaims = async () => {
    setLoading(true);
    try {
      const response: any = await getClaims(1, 100);
      let claimsData: any[] = [];
      
      if (Array.isArray(response)) {
        claimsData = response;
      } else if (response && typeof response === 'object') {
        claimsData = response.data || response.claims || [];
      }
      
      // Map API response to Claim interface
      const mappedClaims: Claim[] = claimsData.map((claim: any) => ({
        id: claim._id || claim.id || '',
        farmerId: claim.farmerId || claim.farmer?._id || claim.farmer?.id || '',
        farmerName: claim.farmer?.firstName && claim.farmer?.lastName 
          ? `${claim.farmer.firstName} ${claim.farmer.lastName}` 
          : claim.farmer?.name || claim.farmerName || 'Unknown Farmer',
        policyId: claim.policyId || claim.policy?._id || claim.policy?.id || '',
        cropType: claim.cropType || claim.policy?.cropType || 'Unknown',
        claimAmount: claim.amount || claim.claimAmount || 0,
        status: claim.status || 'pending_review',
        filedDate: claim.filedDate || claim.createdAt || new Date().toISOString().split('T')[0],
        incidentDate: claim.incidentDate || claim.incidentDate || new Date().toISOString().split('T')[0],
        description: claim.description || claim.lossDescription || '',
        location: claim.location || claim.farm?.location || 'Unknown',
        assessorId: claim.assessorId || claim.assessor?._id || claim.assessor?.id || '',
        assessorName: claim.assessor?.firstName && claim.assessor?.lastName
          ? `${claim.assessor.firstName} ${claim.assessor.lastName}`
          : claim.assessor?.name || claim.assessorName || 'Unassigned',
        priority: claim.priority || 'medium',
      }));
      
      setClaims(mappedClaims);
    } catch (err: any) {
      console.error('Failed to load claims:', err);
      setClaims([]);
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "pending_review": return "bg-yellow-100 text-yellow-800";
      case "approved": return "bg-green-100 text-green-800";
      case "rejected": return "bg-red-100 text-red-800";
      case "under_investigation": return "bg-blue-100 text-blue-800";
      default: return "bg-gray-100 text-white/90";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "pending_review": return <Clock className="h-4 w-4" />;
      case "approved": return <CheckCircle className="h-4 w-4" />;
      case "rejected": return <AlertTriangle className="h-4 w-4" />;
      case "under_investigation": return <Eye className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "high": return "bg-red-100 text-red-800";
      case "medium": return "bg-yellow-100 text-yellow-800";
      case "low": return "bg-green-100 text-green-800";
      default: return "bg-gray-100 text-white/90";
    }
  };

  const nextClaim = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === claims.length - 1 ? 0 : prevIndex + 1
    );
  };

  const prevClaim = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === 0 ? claims.length - 1 : prevIndex - 1
    );
  };

  const goToClaim = (index: number) => {
    setCurrentIndex(index);
  };

  const currentClaim = claims[currentIndex];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white">Claims Review</h2>
          <p className="text-white/70">Browse through claims for review and decision making</p>
        </div>
        <div className="flex items-center space-x-2">
          <Badge variant="outline" className="bg-blue-50 text-blue-700">
            {currentIndex + 1} of {claims.length}
          </Badge>
        </div>
      </div>

      {/* Carousel Container */}
      <div className="relative">
        {/* Navigation Arrows */}
        <Button
          variant="outline"
          size="sm"
          className="absolute left-4 top-1/2 transform -translate-y-1/2 z-10 bg-white shadow-lg"
          onClick={prevClaim}
        >
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          size="sm"
          className="absolute right-4 top-1/2 transform -translate-y-1/2 z-10 bg-white shadow-lg"
          onClick={nextClaim}
        >
          <ChevronRight className="h-4 w-4" />
        </Button>

        {/* Claim Card */}
        <Card className="mx-12 shadow-lg">
          <CardHeader>
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div>
                  <CardTitle className="text-xl">{currentClaim?.id || 'N/A'}</CardTitle>
                  <p className="text-sm text-white/70">Filed on {currentClaim?.filedDate || 'N/A'}</p>
                </div>
                <div className="flex items-center space-x-2">
                  <Badge className={getPriorityColor(currentClaim?.priority || 'medium')}>
                    {currentClaim?.priority || 'medium'} priority
                  </Badge>
                  <Badge className={getStatusColor(currentClaim?.status || 'pending')}>
                    {getStatusIcon(currentClaim?.status || 'pending')}
                    <span className="ml-1 capitalize">{(currentClaim?.status || 'pending').replace('_', ' ')}</span>
                  </Badge>
                </div>
              </div>
            </div>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Claim Overview */}
            <div className="grid gap-6 md:grid-cols-2">
              {/* Left Column - Claim Details */}
              <div className="space-y-4">
                <div className="bg-gray-50 p-4 rounded-lg">
                  <h3 className="font-semibold text-white mb-3">Claim Information</h3>
                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-white/70">Claim Amount:</span>
                      <span className="font-semibold text-green-600">
                        {(currentClaim?.claimAmount || 0).toLocaleString()} RWF
                      </span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/70">Policy ID:</span>
                      <span className="font-medium">{currentClaim?.policyId || 'N/A'}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/70">Crop Type:</span>
                      <span className="font-medium">{currentClaim?.cropType || 'N/A'}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/70">Incident Date:</span>
                      <span className="font-medium">{currentClaim?.incidentDate || 'N/A'}</span>
                    </div>
                  </div>
                </div>

                <div className="bg-blue-50 p-4 rounded-lg">
                  <h3 className="font-semibold text-white mb-3">Farmer Information</h3>
                  <div className="space-y-2">
                    <div className="flex items-center space-x-2">
                      <User className="h-4 w-4 text-gray-500" />
                      <span className="font-medium">{currentClaim?.farmerName || 'Unknown Farmer'}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <FileText className="h-4 w-4 text-gray-500" />
                      <span className="text-sm text-white/70">ID: {currentClaim?.farmerId || 'N/A'}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <MapPin className="h-4 w-4 text-gray-500" />
                      <span className="text-sm text-white/70">{currentClaim?.location || 'N/A'}</span>
                    </div>
                  </div>
                  <div className="flex space-x-2 mt-3">
                    <Button size="sm" variant="outline">
                      <Phone className="h-3 w-3 mr-1" />
                      Call
                    </Button>
                    <Button size="sm" variant="outline">
                      <Mail className="h-3 w-3 mr-1" />
                      Email
                    </Button>
                  </div>
                </div>
              </div>

              {/* Right Column - Assessment & Actions */}
              <div className="space-y-4">
                <div className="bg-orange-50 p-4 rounded-lg">
                  <h3 className="font-semibold text-white mb-3">Assessment Information</h3>
                  <div className="space-y-2">
                    <div className="flex items-center space-x-2">
                      <User className="h-4 w-4 text-gray-500" />
                      <span className="font-medium">{currentClaim?.assessorName || 'Unassigned'}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <FileText className="h-4 w-4 text-gray-500" />
                      <span className="text-sm text-white/70">ID: {currentClaim?.assessorId || 'N/A'}</span>
                    </div>
                  </div>
                  <div className="mt-3">
                    <Button size="sm" variant="outline">
                      <Phone className="h-3 w-3 mr-1" />
                      Contact Assessor
                    </Button>
                  </div>
                </div>

                <div className="bg-gray-50 p-4 rounded-lg">
                  <h3 className="font-semibold text-white mb-3">Description</h3>
                  <p className="text-sm text-white/80 leading-relaxed">
                    {currentClaim?.description || 'No description available'}
                  </p>
                </div>
              </div>
            </div>

            {/* Action Buttons */}
            <div className="flex justify-center space-x-4 pt-4 border-t">
              <Button 
                className="bg-blue-600 hover:bg-blue-700"
                onClick={() => {
                  // Navigate to detailed claim review page
                  if (currentClaim?.id) {
                    window.location.href = `/claim-review/${currentClaim.id}`;
                  }
                }}
              >
                <Eye className="h-4 w-4 mr-2" />
                Review Full Details
              </Button>
              <Button variant="outline">
                <FileText className="h-4 w-4 mr-2" />
                View Documents
              </Button>
              <Button variant="outline">
                <MapPin className="h-4 w-4 mr-2" />
                View Location
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Dots Indicator */}
      <div className="flex justify-center space-x-2">
        {claims.map((_, index) => (
          <button
            key={index}
            onClick={() => goToClaim(index)}
            className={`w-3 h-3 rounded-full transition-colors ${
              index === currentIndex 
                ? "bg-blue-600" 
                : "bg-gray-300 hover:bg-gray-400"
            }`}
          />
        ))}
      </div>

      {/* Quick Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-yellow-600">
              {claims.filter(c => c.status === 'pending_review').length}
            </div>
            <p className="text-sm text-white/70">Pending Review</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-blue-600">
              {claims.filter(c => c.status === 'under_investigation').length}
            </div>
            <p className="text-sm text-white/70">Under Investigation</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-green-600">
              {claims.filter(c => c.status === 'approved').length}
            </div>
            <p className="text-sm text-white/70">Approved</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-red-600">
              {claims.filter(c => c.status === 'rejected').length}
            </div>
            <p className="text-sm text-white/70">Rejected</p>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import ClaimDetailView from "./ClaimDetailView";
import claimsApiService, { getClaims, approveClaim as approveClaimApi, rejectClaim as rejectClaimApi, assignAssessor as assignAssessorApi } from "@/services/claimsApi";
import { useToast } from "@/hooks/use-toast";
import { 
  Search,
  Filter,
  Eye,
  User,
  MapPin,
  Calendar,
  DollarSign,
  AlertTriangle,
  CheckCircle,
  Clock,
  Phone,
  Mail,
  FileText,
  ChevronDown,
  ChevronUp
} from "lucide-react";

interface Claim {
  id: string;
  farmerId: string;
  farmerName: string;
  policyId: string;
  cropType: string;
  claimAmount: number;
  status: string;
  filedDate: string;
  incidentDate: string;
  description: string;
  location: string;
  assessorId: string;
  assessorName: string;
  priority: string;
}

export default function ClaimsTable() {
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [priorityFilter, setPriorityFilter] = useState("all");
  const [expandedPriority, setExpandedPriority] = useState<string | null>(null);
  const [selectedClaim, setSelectedClaim] = useState<Claim | null>(null);
  const [claims, setClaims] = useState<Claim[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Load claims from API
  useEffect(() => {
    loadClaims();
  }, []);

  const loadClaims = async () => {
    setLoading(true);
    setError(null);
    try {
      // Try different pagination strategies to handle API inconsistencies
      let response: any = null;
      let claimsData: any[] = [];
      
      // Strategy 1: Try page 1 first
      console.log('Trying page 1 for claims...');
      response = await getClaims(1, 100);
      console.log('Claims API Response (page 1):', response);
      
      // Extract claims from response - handle multiple response structures
      // Response structure: { success: true, message: '...', data: Array(0) }
      if (response?.success && Array.isArray(response.data)) {
        // Direct array in data property (non-paginated)
        claimsData = response.data;
        console.log('Extracted claims from response.data (direct array):', claimsData);
      } else if (response?.success && response?.data?.items) {
        // Paginated response: { success: true, data: { items: [], ... } }
        claimsData = Array.isArray(response.data.items) ? response.data.items : [];
        console.log('Extracted claims from response.data.items (paginated):', claimsData);
      } else if (response?.success && response?.data?.data) {
        // Nested data structure: { success: true, data: { data: [] } }
        claimsData = Array.isArray(response.data.data) ? response.data.data : [];
        console.log('Extracted claims from response.data.data:', claimsData);
      } else if (Array.isArray(response)) {
        claimsData = response;
      } else if (Array.isArray(response?.data)) {
        claimsData = response.data;
      } else if (Array.isArray(response?.items)) {
        claimsData = response.items;
      } else if (Array.isArray(response?.results)) {
        claimsData = response.results;
      } else if (response?.data?.claims && Array.isArray(response.data.claims)) {
        claimsData = response.data.claims;
      } else if (response?.claims && Array.isArray(response.claims)) {
        claimsData = response.claims;
      }
      
      // Strategy 2: If page 1 returned empty items but totalItems > 0, try page 0
      if (claimsData.length === 0 && (response?.data?.totalItems > 0 || response?.data?.totalPages > 0)) {
        console.log('Page 1 returned empty items but totalItems > 0, trying page 0...');
        response = await getClaims(0, 100);
        console.log('Claims API Response (page 0):', response);
        
        if (response?.success && Array.isArray(response.data)) {
          claimsData = response.data;
        } else if (response?.success && response?.data?.items) {
          claimsData = Array.isArray(response.data.items) ? response.data.items : [];
        } else if (response?.success && response?.data?.data) {
          claimsData = Array.isArray(response.data.data) ? response.data.data : [];
        } else if (Array.isArray(response)) {
          claimsData = response;
        } else if (Array.isArray(response?.data)) {
          claimsData = response.data;
        }
      }
      
      // Strategy 3: Try with larger page size if still empty
      if (claimsData.length === 0 && (response?.data?.totalItems > 0 || response?.data?.totalPages > 0)) {
        console.log('Trying with larger page size (500)...');
        response = await getClaims(0, 500);
        
        if (response?.success && Array.isArray(response.data)) {
          claimsData = response.data;
        } else if (response?.success && response?.data?.items) {
          claimsData = Array.isArray(response.data.items) ? response.data.items : [];
        } else if (response?.success && response?.data?.data) {
          claimsData = Array.isArray(response.data.data) ? response.data.data : [];
        }
      }
      
      // Strategy 4: Check if data structure has claims at a different location
      if (claimsData.length === 0 && response?.success) {
        console.warn('⚠️ Claims API returned success but no claims found in expected locations.');
        console.warn('Full response structure:', JSON.stringify(response, null, 2));
        
        // Check all possible locations for claims data
        if (response?.data && typeof response.data === 'object') {
          const possibleKeys = ['claims', 'items', 'results', 'content', 'data'];
          for (const key of possibleKeys) {
            if (Array.isArray(response.data[key])) {
              claimsData = response.data[key];
              console.log(`Found claims array at response.data.${key}:`, claimsData);
              break;
            }
          }
        }
      }
      
      console.log('Final extracted claims data:', claimsData);
      
      // Map API response to Claim interface
      const mappedClaims: Claim[] = claimsData.map((claim: any) => ({
        id: claim._id || claim.id || '',
        farmerId: claim.farmerId || claim.farmer?._id || claim.farmer?.id || '',
        farmerName: claim.farmer?.firstName && claim.farmer?.lastName 
          ? `${claim.farmer.firstName} ${claim.farmer.lastName}` 
          : claim.farmer?.name || claim.farmerName || 'Unknown Farmer',
        policyId: claim.policyId || claim.policy?._id || claim.policy?.id || '',
        cropType: claim.cropType || claim.policy?.cropType || 'Unknown',
        claimAmount: claim.amount || claim.claimAmount || 0,
        status: claim.status || 'pending_review',
        filedDate: claim.filedDate || claim.createdAt || new Date().toISOString().split('T')[0],
        incidentDate: claim.incidentDate || claim.incidentDate || new Date().toISOString().split('T')[0],
        description: claim.description || claim.lossDescription || '',
        location: claim.location || claim.farm?.location || 'Unknown',
        assessorId: claim.assessorId || claim.assessor?._id || claim.assessor?.id || '',
        assessorName: claim.assessor?.firstName && claim.assessor?.lastName
          ? `${claim.assessor.firstName} ${claim.assessor.lastName}`
          : claim.assessor?.name || claim.assessorName || 'Unassigned',
        priority: claim.priority || 'medium',
      }));
      
      setClaims(mappedClaims);
    } catch (err: any) {
      console.error('Failed to load claims:', err);
      setError(err.message || 'Failed to load claims');
      toast({
        title: "Error",
        description: err.message || 'Failed to load claims',
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };


  const getStatusColor = (status: string) => {
    switch (status) {
      case "pending_review": return "bg-yellow-100 text-yellow-800";
      case "approved": return "bg-green-100 text-green-800";
      case "rejected": return "bg-red-100 text-red-800";
      case "under_investigation": return "bg-blue-100 text-blue-800";
      default: return "bg-gray-100 text-gray-700 border border-gray-200";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "pending_review": return <Clock className="h-3 w-3" />;
      case "approved": return <CheckCircle className="h-3 w-3" />;
      case "rejected": return <AlertTriangle className="h-3 w-3" />;
      case "under_investigation": return <Eye className="h-3 w-3" />;
      default: return <Clock className="h-3 w-3" />;
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "high": return "bg-red-100 text-red-800 border-red-200";
      case "medium": return "bg-yellow-100 text-yellow-800 border-yellow-200";
      case "low": return "bg-green-100 text-green-800 border-green-200";
      default: return "bg-gray-100 text-gray-700 border border-gray-200";
    }
  };

  const handleViewClaim = (claim: Claim) => {
    setSelectedClaim(claim);
  };

  const handleBackToList = () => {
    setSelectedClaim(null);
  };

  const handleApproveClaim = async (claimId: string, approvedAmount?: number, notes?: string) => {
    try {
      await approveClaimApi(claimId, approvedAmount, notes);
      toast({
        title: "Success",
        description: "Claim approved successfully",
        variant: "default",
      });
      // Reload claims
      loadClaims();
      setSelectedClaim(null);
    } catch (err: any) {
      console.error('Failed to approve claim:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to approve claim',
        variant: "destructive",
      });
    }
  };

  const handleRejectClaim = async (claimId: string, reason: string) => {
    try {
      await rejectClaimApi(claimId, reason);
      toast({
        title: "Success",
        description: "Claim rejected successfully",
        variant: "default",
      });
      // Reload claims
      loadClaims();
      setSelectedClaim(null);
    } catch (err: any) {
      console.error('Failed to reject claim:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to reject claim',
        variant: "destructive",
      });
    }
  };

  const handleAssignAssessor = async (claimId: string, assessorId: string) => {
    try {
      await assignAssessorApi(claimId, assessorId);
      toast({
        title: "Success",
        description: "Assessor assigned successfully",
        variant: "default",
      });
      // Reload claims
      loadClaims();
    } catch (err: any) {
      console.error('Failed to assign assessor:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to assign assessor',
        variant: "destructive",
      });
    }
  };

  const getPriorityIcon = (priority: string) => {
    switch (priority) {
      case "high": return <AlertTriangle className="h-4 w-4" />;
      case "medium": return <Clock className="h-4 w-4" />;
      case "low": return <CheckCircle className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  // Filter claims
  const filteredClaims = claims.filter(claim => {
    const matchesSearch = claim.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         claim.farmerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         claim.cropType.toLowerCase().includes(searchTerm.toLowerCase());
    
    const matchesStatus = statusFilter === "all" || claim.status === statusFilter;
    const matchesPriority = priorityFilter === "all" || claim.priority === priorityFilter;
    
    return matchesSearch && matchesStatus && matchesPriority;
  });

  // Group claims by priority
  const groupedClaims = {
    high: filteredClaims.filter(claim => claim.priority === "high"),
    medium: filteredClaims.filter(claim => claim.priority === "medium"),
    low: filteredClaims.filter(claim => claim.priority === "low")
  };

  const togglePriority = (priority: string) => {
    setExpandedPriority(expandedPriority === priority ? null : priority);
  };

  const renderClaimCard = (claim: Claim) => (
    <Card key={claim.id} className={`${dashboardTheme.card} cursor-pointer border-l-4 border-l-blue-400`}>
      <CardContent className="p-4">
        <div className="flex items-start justify-between mb-3">
          <div>
            <h3 className="font-semibold text-gray-900">{claim.id}</h3>
            <p className="text-sm text-gray-600">{claim.farmerName}</p>
          </div>
          <div className="flex items-center space-x-2">
            <Badge className={getStatusColor(claim.status)}>
              {getStatusIcon(claim.status)}
              <span className="ml-1 text-xs">{claim.status.replace('_', ' ')}</span>
            </Badge>
          </div>
        </div>

        <div className="space-y-2 mb-3">
          <div className="flex items-center justify-between text-sm">
            <span className="text-gray-600">Amount:</span>
            <span className="font-semibold text-green-600">
              {claim.claimAmount.toLocaleString()} RWF
            </span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="text-gray-600">Crop:</span>
            <span className="font-medium text-gray-900">{claim.cropType}</span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="text-gray-600">Filed:</span>
            <span className="font-medium text-gray-900">{claim.filedDate}</span>
          </div>
        </div>

        <div className="flex items-center justify-between text-xs text-gray-500 mb-3">
          <div className="flex items-center">
            <MapPin className="h-3 w-3 mr-1" />
            {claim.location}
          </div>
          <div className="flex items-center">
            <User className="h-3 w-3 mr-1" />
            {claim.assessorName}
          </div>
        </div>

        <div className="flex space-x-2">
          <Button 
            size="sm" 
            className="flex-1 bg-blue-600 hover:bg-blue-700"
            onClick={() => handleViewClaim(claim)}
          >
            <Eye className="h-3 w-3 mr-1" />
            Review
          </Button>
          <Button size="sm" variant="outline">
            <Phone className="h-3 w-3" />
          </Button>
        </div>
      </CardContent>
    </Card>
  );

  const renderPrioritySection = (priority: string, claims: Claim[]) => {
    if (claims.length === 0) return null;

    const priorityLabels = {
      high: "High Priority",
      medium: "Medium Priority", 
      low: "Low Priority"
    };

    const isExpanded = expandedPriority === priority;

    return (
      <div key={priority} className="mb-6">
        <Card className={`${dashboardTheme.card} mb-4`}>
          <CardHeader 
            className="cursor-pointer"
            onClick={() => togglePriority(priority)}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${getPriorityColor(priority)}`}>
                  {getPriorityIcon(priority)}
                </div>
                <div>
                  <CardTitle className="text-lg">{priorityLabels[priority as keyof typeof priorityLabels]}</CardTitle>
                  <p className="text-sm text-gray-600">{claims.length} claims</p>
                </div>
              </div>
              <div className="flex items-center space-x-2">
                <Badge className={getPriorityColor(priority)}>
                  {claims.length}
                </Badge>
                {isExpanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
              </div>
            </div>
          </CardHeader>
        </Card>

        {isExpanded && (
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {claims.map(renderClaimCard)}
          </div>
        )}
      </div>
    );
  };

  // Show detailed view if a claim is selected
  if (selectedClaim) {
    return (
      <ClaimDetailView
        claim={selectedClaim}
        onBack={handleBackToList}
        onApprove={handleApproveClaim}
        onReject={handleRejectClaim}
      />
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold text-gray-900">Claims Review</h1>
        <p className="text-sm text-gray-600 mt-1">Review and manage insurance claims by priority</p>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-500" />
                <Input
                  placeholder="Search claims by ID, farmer name, or crop type..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
            <div className="flex gap-2">
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-40">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="pending_review">Pending Review</SelectItem>
                  <SelectItem value="under_investigation">Under Investigation</SelectItem>
                  <SelectItem value="approved">Approved</SelectItem>
                  <SelectItem value="rejected">Rejected</SelectItem>
                </SelectContent>
              </Select>
              <Select value={priorityFilter} onValueChange={setPriorityFilter}>
                <SelectTrigger className="w-40">
                  <SelectValue placeholder="Priority" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Priority</SelectItem>
                  <SelectItem value="high">High Priority</SelectItem>
                  <SelectItem value="medium">Medium Priority</SelectItem>
                  <SelectItem value="low">Low Priority</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Priority Sections */}
      {Object.entries(groupedClaims).map(([priority, claims]) => 
        renderPrioritySection(priority, claims)
      )}

      {/* Empty State */}
      {filteredClaims.length === 0 && (
        <Card>
          <CardContent className="p-8 text-center">
            <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No claims found</h3>
            <p className="text-gray-600">Try adjusting your search or filter criteria.</p>
          </CardContent>
        </Card>
      )}

      {/* Quick Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-red-600">
              {groupedClaims.high.length}
            </div>
            <p className="text-sm text-gray-600">High Priority</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-yellow-600">
              {groupedClaims.medium.length}
            </div>
            <p className="text-sm text-gray-600">Medium Priority</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-green-600">
              {groupedClaims.low.length}
            </div>
            <p className="text-sm text-gray-600">Low Priority</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <div className="text-2xl font-bold text-blue-600">
              {filteredClaims.length}
            </div>
            <p className="text-sm text-gray-600">Total Claims</p>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { createPolicyFromAssessment } from "@/services/policiesApi";
import assessmentsApiService from "@/services/assessmentsApi";
import { useToast } from "@/hooks/use-toast";
import { 
  ArrowLeft,
  Save,
  FileText,
  AlertCircle
} from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface CreatePolicyPageProps {
  onBack: () => void;
  onSuccess?: () => void;
}

export default function CreatePolicyPage({ onBack, onSuccess }: CreatePolicyPageProps) {
  const { toast } = useToast();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [assessments, setAssessments] = useState<any[]>([]);
  const [assessmentsLoading, setAssessmentsLoading] = useState(false);

  const [formData, setFormData] = useState({
    assessmentId: "",
    coverageLevel: "STANDARD" as "BASIC" | "STANDARD" | "PREMIUM",
    startDate: "",
    endDate: "",
  });

  // Load submitted assessments on component mount
  useEffect(() => {
    loadSubmittedAssessments();
    
    // Set default dates
    const today = new Date();
    const nextYear = new Date();
    nextYear.setFullYear(today.getFullYear() + 1);
    setFormData(prev => ({
      ...prev,
      startDate: today.toISOString().split('T')[0],
      endDate: nextYear.toISOString().split('T')[0]
    }));
  }, []);

  const loadSubmittedAssessments = async () => {
    setAssessmentsLoading(true);
    try {
      // Try different pagination strategies to handle API inconsistencies
      let response: any = null;
      let assessmentsArray: any[] = [];
      
      // Strategy 1: Try page 1 first
      console.log('Loading submitted assessments for policy creation...');
      response = await assessmentsApiService.getAssessments(1, 100);
      console.log('Assessments API Response:', response);
      
      // Extract assessments from response
      if (response?.success && response?.data?.items) {
        assessmentsArray = Array.isArray(response.data.items) ? response.data.items : [];
      } else if (Array.isArray(response)) {
        assessmentsArray = response;
      } else if (Array.isArray(response?.data)) {
        assessmentsArray = response.data;
      } else if (Array.isArray(response?.items)) {
        assessmentsArray = response.items;
      } else if (Array.isArray(response?.results)) {
        assessmentsArray = response.results;
      }
      
      // Filter to only SUBMITTED assessments
      const submittedAssessments = assessmentsArray.filter((assessment: any) => {
        const status = (assessment.status || '').toUpperCase();
        return status === 'SUBMITTED';
      });
      
      setAssessments(submittedAssessments);
      console.log('Loaded submitted assessments:', submittedAssessments);
      
      if (submittedAssessments.length === 0) {
        toast({
          title: 'No Submitted Assessments',
          description: 'There are no submitted assessments available. Please wait for an assessor to submit an assessment first.',
          variant: 'default'
        });
      }
    } catch (err: any) {
      console.error('Failed to load assessments:', err);
      toast({
        title: 'Error',
        description: err.message || 'Failed to load submitted assessments',
        variant: 'destructive'
      });
    } finally {
      setAssessmentsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.assessmentId || !formData.startDate || !formData.endDate) {
      toast({
        title: "Validation Error",
        description: "Please fill in all required fields",
        variant: "destructive",
      });
      return;
    }

    setIsSubmitting(true);
    try {
      // Format dates to ISO format (YYYY-MM-DDTHH:mm:ssZ)
      const startDateISO = new Date(formData.startDate + 'T00:00:00Z').toISOString();
      const endDateISO = new Date(formData.endDate + 'T23:59:59Z').toISOString();
      
      console.log('Creating policy from assessment:', {
        assessmentId: formData.assessmentId,
        coverageLevel: formData.coverageLevel,
        startDate: startDateISO,
        endDate: endDateISO
      });
      
      await createPolicyFromAssessment(
        formData.assessmentId,
        formData.coverageLevel,
        startDateISO,
        endDateISO
      );
      
      toast({
        title: "Success",
        description: "Policy created successfully from assessment",
        variant: "default",
      });
      
      if (onSuccess) {
        onSuccess();
      }
      onBack();
    } catch (err: any) {
      console.error('Failed to create policy:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to create policy',
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const selectedAssessment = assessments.find((a: any) => 
    (a._id || a.id) === formData.assessmentId
  );

  const getRiskLevelBadge = (riskScore: number | undefined) => {
    if (!riskScore && riskScore !== 0) return null;
    if (riskScore <= 30) {
      return <Badge className="bg-green-100 text-green-700">Low Risk</Badge>;
    } else if (riskScore <= 70) {
      return <Badge className="bg-yellow-100 text-yellow-700">Medium Risk</Badge>;
    } else {
      return <Badge className="bg-red-100 text-red-700">High Risk</Badge>;
    }
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Create New Policy</h1>
          <p className="text-sm text-gray-600 mt-1">Create a policy from a submitted assessment</p>
        </div>
        <Button variant="outline" onClick={onBack}>
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Policies
        </Button>
      </div>

      {/* Form */}
      <Card>
        <CardHeader>
          <CardTitle>Policy Information</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <Label htmlFor="assessmentId">Select Assessment *</Label>
              {assessmentsLoading ? (
                <div className="text-sm text-gray-500">Loading submitted assessments...</div>
              ) : assessments.length === 0 ? (
                <div className="border border-gray-300 rounded-lg p-4 bg-gray-50">
                  <div className="flex items-center gap-2 text-gray-600">
                    <AlertCircle className="h-5 w-5" />
                    <p>No submitted assessments available. Please wait for an assessor to submit an assessment first.</p>
                  </div>
                </div>
              ) : (
                <>
                  <Select 
                    value={formData.assessmentId || undefined} 
                    onValueChange={(value) => setFormData({...formData, assessmentId: value})}
                    required
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select a submitted assessment" />
                    </SelectTrigger>
                    <SelectContent>
                      {assessments.map((assessment: any) => {
                        const assessmentId = assessment._id || assessment.id;
                        if (!assessmentId) return null;
                        
                        const farmerName = assessment.farmerId?.firstName && assessment.farmerId?.lastName
                          ? `${assessment.farmerId.firstName} ${assessment.farmerId.lastName}`
                          : assessment.farmerId?.name || assessment.farmerName || 'Unknown Farmer';
                        
                        const farmName = assessment.farmId?.name || assessment.farmName || 'Unknown Farm';
                        const cropType = assessment.cropType || assessment.farmId?.cropType || 'Unknown';
                        const riskScore = assessment.riskScore;
                        
                        return (
                          <SelectItem key={assessmentId} value={assessmentId}>
                            <div className="flex items-center justify-between w-full">
                              <span className="font-medium">{farmerName} - {farmName}</span>
                              {getRiskLevelBadge(riskScore)}
                            </div>
                          </SelectItem>
                        );
                      })}
                    </SelectContent>
                  </Select>
                  
                  {selectedAssessment && (
                    <div className="mt-3 p-4 bg-blue-50 border border-blue-200 rounded-lg">
                      <h4 className="font-semibold text-blue-900 mb-2 flex items-center gap-2">
                        <FileText className="h-4 w-4" />
                        Assessment Details
                      </h4>
                      <div className="grid grid-cols-2 gap-2 text-sm text-blue-800">
                        <div>
                          <span className="font-medium">Farmer:</span>{' '}
                          {selectedAssessment.farmerId?.firstName && selectedAssessment.farmerId?.lastName
                            ? `${selectedAssessment.farmerId.firstName} ${selectedAssessment.farmerId.lastName}`
                            : selectedAssessment.farmerId?.name || selectedAssessment.farmerName || 'Unknown'}
                        </div>
                        <div>
                          <span className="font-medium">Farm:</span>{' '}
                          {selectedAssessment.farmId?.name || selectedAssessment.farmName || 'Unknown'}
                        </div>
                        <div>
                          <span className="font-medium">Crop Type:</span>{' '}
                          {selectedAssessment.cropType || selectedAssessment.farmId?.cropType || 'Unknown'}
                        </div>
                        <div>
                          <span className="font-medium">Risk Score:</span>{' '}
                          {selectedAssessment.riskScore !== undefined ? selectedAssessment.riskScore : 'N/A'}
                          {getRiskLevelBadge(selectedAssessment.riskScore)}
                        </div>
                      </div>
                    </div>
                  )}
                </>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="coverageLevel">Coverage Level *</Label>
              <Select 
                value={formData.coverageLevel} 
                onValueChange={(value: "BASIC" | "STANDARD" | "PREMIUM") => 
                  setFormData({...formData, coverageLevel: value})
                }
                required
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select coverage level" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="BASIC">Basic Coverage</SelectItem>
                  <SelectItem value="STANDARD">Standard Coverage</SelectItem>
                  <SelectItem value="PREMIUM">Premium Coverage</SelectItem>
                </SelectContent>
              </Select>
              <p className="text-xs text-gray-500 mt-1">
                Coverage level determines the extent of protection and premium rates
              </p>
            </div>

            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="startDate">Start Date *</Label>
                <Input
                  id="startDate"
                  type="date"
                  value={formData.startDate}
                  onChange={(e) => setFormData({...formData, startDate: e.target.value})}
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="endDate">End Date *</Label>
                <Input
                  id="endDate"
                  type="date"
                  value={formData.endDate}
                  onChange={(e) => setFormData({...formData, endDate: e.target.value})}
                  required
                />
              </div>
            </div>

            <div className="flex justify-end space-x-3 pt-4 border-t">
              <Button type="button" variant="outline" onClick={onBack} disabled={isSubmitting}>
                Cancel
              </Button>
              <Button 
                type="submit" 
                disabled={isSubmitting || assessments.length === 0} 
                className="bg-green-600 hover:bg-green-700"
              >
                <Save className="h-4 w-4 mr-2" />
                {isSubmitting ? "Creating..." : "Create Policy"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Bell, 
  Search, 
  Filter,
  CheckCircle,
  AlertTriangle,
  Info,
  Clock,
  User,
  FileText,
  DollarSign,
  Settings
} from "lucide-react";

export default function InsurerNotifications() {
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");

  // Notifications will be loaded from API in the future
  const notifications: any[] = [];

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case "risk_assessment": return <FileText className="h-5 w-5" />;
      case "claim_submitted": return <AlertTriangle className="h-5 w-5" />;
      case "payment_due": return <DollarSign className="h-5 w-5" />;
      case "assessment_completed": return <CheckCircle className="h-5 w-5" />;
      case "system_alert": return <Settings className="h-5 w-5" />;
      default: return <Info className="h-5 w-5" />;
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case "high": return "bg-red-400/20 text-red-400";
      case "medium": return "bg-yellow-400/20 text-yellow-400";
      case "low": return "bg-green-400/20 text-green-400";
      default: return "bg-gray-400/20 text-gray-400";
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case "risk_assessment": return "bg-blue-400/20 text-blue-400";
      case "claim_submitted": return "bg-orange-400/20 text-orange-400";
      case "payment_due": return "bg-purple-400/20 text-purple-400";
      case "assessment_completed": return "bg-green-400/20 text-green-400";
      case "system_alert": return "bg-gray-800/20 text-white";
      default: return "bg-gray-800/20 text-white";
    }
  };

  const filteredNotifications = notifications.filter(notification => {
    const matchesSearch = notification.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         notification.message.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         notification.farmerName?.toLowerCase().includes(searchTerm.toLowerCase());
    
    const matchesType = filterType === "all" || notification.type === filterType;
    const matchesStatus = filterStatus === "all" || notification.status === filterStatus;
    
    return matchesSearch && matchesType && matchesStatus;
  });

  const unreadCount = notifications.filter(n => n.status === "unread").length;

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold text-gray-900">Notifications</h1>
        <p className="text-sm text-gray-600 mt-1">Stay updated with system activities and alerts</p>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
                <Input
                  placeholder="Search notifications..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
            <div className="flex gap-2">
              <Select value={filterType} onValueChange={setFilterType}>
                <SelectTrigger className="w-40">
                  <SelectValue placeholder="Type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Types</SelectItem>
                  <SelectItem value="risk_assessment">Risk Assessment</SelectItem>
                  <SelectItem value="claim_submitted">Claim Submitted</SelectItem>
                  <SelectItem value="payment_due">Payment Due</SelectItem>
                  <SelectItem value="assessment_completed">Assessment Completed</SelectItem>
                  <SelectItem value="system_alert">System Alert</SelectItem>
                </SelectContent>
              </Select>
              <Select value={filterStatus} onValueChange={setFilterStatus}>
                <SelectTrigger className="w-32">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="unread">Unread</SelectItem>
                  <SelectItem value="read">Read</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Notifications List */}
      <div className="space-y-4">
        {filteredNotifications.length === 0 ? (
          <Card>
            <CardContent className="p-8 text-center">
              <Bell className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-700 mb-2">No notifications found</h3>
              <p className="text-gray-600">Try adjusting your search or filter criteria.</p>
            </CardContent>
          </Card>
        ) : (
          filteredNotifications.map((notification) => (
            <Card key={notification.id} className={`${dashboardTheme.card} transition-all duration-200 ${
              notification.status === "unread" ? "border-l-4 border-l-green-500 bg-green-600/30" : ""
            }`}>
              <CardContent className="p-6">
                <div className="flex items-start space-x-4">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                    notification.status === "unread" ? "bg-green-400/20 text-green-400" : "bg-gray-800/20 text-gray-400"
                  }`}>
                    {getNotificationIcon(notification.type)}
                  </div>
                  
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-2">
                      <h3 className="text-lg font-medium text-white">
                        {notification.title}
                      </h3>
                      <div className="flex items-center space-x-2">
                        <Badge className={getPriorityColor(notification.priority)}>
                          {notification.priority}
                        </Badge>
                        <Badge className={getTypeColor(notification.type)}>
                          {notification.type.replace('_', ' ')}
                        </Badge>
                      </div>
                    </div>
                    
                    <p className="text-white/80 mb-3">
                      {notification.message}
                    </p>
                    
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-4 text-sm text-white/60">
                        <div className="flex items-center">
                          <Clock className="h-4 w-4 mr-1" />
                          {notification.timestamp}
                        </div>
                        {notification.farmerName && (
                          <div className="flex items-center">
                            <User className="h-4 w-4 mr-1" />
                            {notification.farmerName} ({notification.farmerId})
                          </div>
                        )}
                      </div>
                      
                      <div className="flex items-center space-x-2">
                        {notification.status === "unread" && (
                          <Button size="sm" variant="outline">
                            Mark as Read
                          </Button>
                        )}
                        <Button size="sm" variant="outline">
                          View Details
                        </Button>
                      </div>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { useToast } from "@/hooks/use-toast";
import { getUserProfile } from "@/services/usersAPI";
import { getUserId, getPhoneNumber, getEmail } from "@/services/authAPI";
import {
  User,
  Shield,
  Key,
  Save,
  Eye,
  EyeOff
} from "lucide-react";

export default function InsurerProfileSettings() {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("profile");
  const [loading, setLoading] = useState(true);
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const insurerId = getUserId() || "";
  const insurerPhone = getPhoneNumber() || "";
  const insurerEmail = getEmail() || "";

  const [profileData, setProfileData] = useState({
    email: "",
    phone: "",
    companyName: "",
    contactPerson: "",
    insurerId: ""
  });

  useEffect(() => {
    const loadUserProfile = async () => {
      if (!insurerId) {
        setLoading(false);
        return;
      }

      setLoading(true);
      try {
        const response: any = await getUserProfile();
        const user = response.data || response;

        if (user) {
          setProfileData({
            email: user.email || insurerEmail || "",
            phone: user.phoneNumber || insurerPhone || "",
            companyName: user.insurerProfile?.companyName || "",
            contactPerson: user.insurerProfile?.contactPerson || "",
            insurerId: user._id || user.id || insurerId || ""
          });
        }
      } catch (err: any) {
        console.error('Failed to load user profile:', err);
        // Set basic data from localStorage
        setProfileData(prev => ({
          ...prev,
          email: insurerEmail || "",
          phone: insurerPhone || "",
          insurerId: insurerId || ""
        }));
        toast({
          title: "Warning",
          description: "Could not load full profile. Using basic information.",
          variant: "default",
        });
      } finally {
        setLoading(false);
      }
    };

    loadUserProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [insurerId]);

  const [securityData, setSecurityData] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
    twoFactorEnabled: true,
    sessionTimeout: "30"
  });

  const handleProfileUpdate = (field: string, value: string) => {
    setProfileData(prev => ({ ...prev, [field]: value }));
  };

  const handleSecurityUpdate = (field: string, value: string | boolean) => {
    setSecurityData(prev => ({ ...prev, [field]: value }));
  };

  const renderProfileTab = () => (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <User className="h-5 w-5 mr-2" />
            Company Information
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="companyName">Company Name</Label>
              <Input
                id="companyName"
                value={profileData.companyName}
                onChange={(e) => handleProfileUpdate('companyName', e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="insurerId">Insurer ID</Label>
              <Input
                id="insurerId"
                value={profileData.insurerId}
                disabled
                className="bg-gray-50"
              />
            </div>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-2">
              <Label htmlFor="contactPerson">Contact Person</Label>
              <Input
                id="contactPerson"
                value={profileData.contactPerson}
                onChange={(e) => handleProfileUpdate('contactPerson', e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Email Address</Label>
              <Input
                id="email"
                type="email"
                value={profileData.email}
                onChange={(e) => handleProfileUpdate('email', e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="phone">Phone Number</Label>
            <Input
              id="phone"
              value={profileData.phone}
              onChange={(e) => handleProfileUpdate('phone', e.target.value)}
            />
          </div>
        </CardContent>
      </Card>

    </div>
  );

  const renderSecurityTab = () => (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <Key className="h-5 w-5 mr-2" />
            Change Password
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="currentPassword">Current Password</Label>
            <div className="relative">
              <Input
                id="currentPassword"
                type={showCurrentPassword ? "text" : "password"}
                value={securityData.currentPassword}
                onChange={(e) => handleSecurityUpdate('currentPassword', e.target.value)}
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => setShowCurrentPassword(!showCurrentPassword)}
              >
                {showCurrentPassword ? (
                  <EyeOff className="h-4 w-4 text-gray-400" />
                ) : (
                  <Eye className="h-4 w-4 text-gray-400" />
                )}
              </Button>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="newPassword">New Password</Label>
            <div className="relative">
              <Input
                id="newPassword"
                type={showNewPassword ? "text" : "password"}
                value={securityData.newPassword}
                onChange={(e) => handleSecurityUpdate('newPassword', e.target.value)}
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => setShowNewPassword(!showNewPassword)}
              >
                {showNewPassword ? (
                  <EyeOff className="h-4 w-4 text-gray-400" />
                ) : (
                  <Eye className="h-4 w-4 text-gray-400" />
                )}
              </Button>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="confirmPassword">Confirm New Password</Label>
            <div className="relative">
              <Input
                id="confirmPassword"
                type={showConfirmPassword ? "text" : "password"}
                value={securityData.confirmPassword}
                onChange={(e) => handleSecurityUpdate('confirmPassword', e.target.value)}
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
              >
                {showConfirmPassword ? (
                  <EyeOff className="h-4 w-4 text-gray-400" />
                ) : (
                  <Eye className="h-4 w-4 text-gray-400" />
                )}
              </Button>
            </div>
          </div>

          <Button className="bg-blue-600 hover:bg-blue-700">
            Update Password
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <Shield className="h-5 w-5 mr-2" />
            Security Settings
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <h4 className="font-medium text-white">Two-Factor Authentication</h4>
              <p className="text-sm text-white/70">Add an extra layer of security to your account</p>
            </div>
            <Switch
              checked={securityData.twoFactorEnabled}
              onCheckedChange={(checked) => handleSecurityUpdate('twoFactorEnabled', checked)}
            />
          </div>

          <Separator />

          <div className="space-y-2">
            <Label htmlFor="sessionTimeout">Session Timeout (minutes)</Label>
            <Select value={securityData.sessionTimeout} onValueChange={(value) => handleSecurityUpdate('sessionTimeout', value)}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="15">15 minutes</SelectItem>
                <SelectItem value="30">30 minutes</SelectItem>
                <SelectItem value="60">1 hour</SelectItem>
                <SelectItem value="120">2 hours</SelectItem>
                <SelectItem value="480">8 hours</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold text-gray-900">Profile Settings</h1>
        <p className="text-sm text-gray-600 mt-1">Manage your account settings and preferences</p>
      </div>

      {/* Tabs */}
      <div className="border-b border-gray-200">
        <nav className="-mb-px flex space-x-8">
          {[
            { id: "profile", label: "Profile", icon: User },
            { id: "security", label: "Security", icon: Shield }
          ].map((tab) => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === tab.id
                    ? "border-blue-500 text-gray-700"
                    : "border-transparent text-gray-600 hover:text-gray-700 hover:border-gray-300"
                }`}
              >
                <Icon className="h-4 w-4 mr-2" />
                {tab.label}
              </button>
            );
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="pt-6">
        {activeTab === "profile" && renderProfileTab()}
        {activeTab === "security" && renderSecurityTab()}
      </div>

      {/* Save Button */}
      <div className="flex justify-end pt-6 border-t">
        <Button className="bg-blue-600 hover:bg-blue-700">
          <Save className="h-4 w-4 mr-2" />
          Save Changes
        </Button>
      </div>
    </div>
  );
}

