        <div className="min-h-[400px]">
          {activeTab === "overview" && renderOverview()}
          {activeTab === "claims" && renderClaimsHistory()}
          {activeTab === "payments" && renderPayments()}
          {activeTab === "documents" && renderDocuments()}
        </div>
      </div>
    </DashboardLayout>
  );
}

import { useState } from "react";
