  FileText,
  TrendingUp,
  BarChart3,
  Phone,
  Mail,
  Building2
} from "lucide-react";

interface Policy {
  id: string;
  farmerId: string;
  farmerName: string;
  cropType: string;
  coverageAmount: number;
  premiumAmount: number;
  startDate: string;
  endDate: string;
  status: "active" | "pending" | "expired" | "cancelled";
  location: string;
  farmSize: number;
  riskLevel: "low" | "medium" | "high";
  deductible: number;
  createdAt: string;
  phoneNumber?: string;
  email?: string;
  address?: string;
  policyType?: string;
  renewalDate?: string;
  lastPaymentDate?: string;
  nextPaymentDate?: string;
  claimsCount?: number;
  totalClaimsPaid?: number;
}

interface PolicyDetailsViewProps {
  policy: Policy;
  onBack: () => void;
  onEdit: (policy: Policy) => void;
  onDelete: (policyId: string) => void;
}

export default function PolicyDetailsView({ policy, onBack, onEdit, onDelete }: PolicyDetailsViewProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedPolicy, setEditedPolicy] = useState<Policy>(policy);

  const getStatusColor = (status: string) => {
    switch (status) {
      case "active": return "bg-green-100 text-green-800";
      case "pending": return "bg-yellow-100 text-yellow-800";
      case "expired": return "bg-red-100 text-red-800";
      case "cancelled": return "bg-gray-100 text-white/90";
      default: return "bg-gray-100 text-white/90";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "active": return <CheckCircle className="h-4 w-4" />;
      case "pending": return <Clock className="h-4 w-4" />;
      case "expired": return <AlertTriangle className="h-4 w-4" />;
      case "cancelled": return <X className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  const getRiskLevelColor = (level: string) => {
    switch (level) {
      case "low": return "bg-green-100 text-green-800";
      case "medium": return "bg-yellow-100 text-yellow-800";
      case "high": return "bg-red-100 text-red-800";
      default: return "bg-gray-100 text-white/90";
    }
  };

  const handleSave = () => {
    // Here you would typically save the changes to your backend
    setIsEditing(false);
    onEdit(editedPolicy);
  };

  const handleCancel = () => {
    setEditedPolicy(policy);
    setIsEditing(false);
  };

  // Claims and payments will be loaded from API in the future
  const mockClaims: any[] = [];
  const mockPayments: any[] = [];

  return (
    <div className="space-y-6">
