                <DollarSign className="h-6 w-6 text-green-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Risk Level</p>
                <p className="text-2xl font-bold text-white capitalize">
                  {policy.riskLevel}
                </p>
              </div>
              <div className="w-12 h-12 bg-orange-100 rounded-lg flex items-center justify-center">
                <AlertTriangle className="h-6 w-6 text-orange-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Claims Filed</p>
                <p className="text-2xl font-bold text-white">
                  {policy.claimsCount || 0}
                </p>
              </div>
              <div className="w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center">
                <FileText className="h-6 w-6 text-purple-600" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Detailed Information Tabs */}
      <Tabs defaultValue="overview" className="space-y-6">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="overview">Overview</TabsTrigger>
          <TabsTrigger value="farmer">Farmer Details</TabsTrigger>
          <TabsTrigger value="claims">Claims History</TabsTrigger>
          <TabsTrigger value="payments">Payment History</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="space-y-6">
          <div className="grid gap-6 lg:grid-cols-2">
            {/* Policy Information */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center">
                  <Shield className="h-5 w-5 mr-2" />
                  Policy Information
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Policy ID</Label>
                    <Input value={isEditing ? editedPolicy.id : policy.id} disabled />
                  </div>
                  <div className="space-y-2">
                    <Label>Policy Type</Label>
                    <Input value={isEditing ? editedPolicy.policyType || "Crop Insurance" : policy.policyType || "Crop Insurance"} 
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, policyType: e.target.value})} 
                           disabled={!isEditing} />
                  </div>
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Start Date</Label>
                    <Input type="date" 
                           value={isEditing ? editedPolicy.startDate : policy.startDate}
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, startDate: e.target.value})}
                           disabled={!isEditing} />
                  </div>
                  <div className="space-y-2">
                    <Label>End Date</Label>
                    <Input type="date" 
                           value={isEditing ? editedPolicy.endDate : policy.endDate}
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, endDate: e.target.value})}
                           disabled={!isEditing} />
                  </div>
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Coverage Amount (RWF)</Label>
                    <Input type="number" 
                           value={isEditing ? editedPolicy.coverageAmount : policy.coverageAmount}
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, coverageAmount: parseFloat(e.target.value)})}
                           disabled={!isEditing} />
                  </div>
                  <div className="space-y-2">
                    <Label>Premium Amount (RWF)</Label>
                    <Input type="number" 
                           value={isEditing ? editedPolicy.premiumAmount : policy.premiumAmount}
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, premiumAmount: parseFloat(e.target.value)})}
                           disabled={!isEditing} />
                  </div>
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Deductible (RWF)</Label>
                    <Input type="number" 
                           value={isEditing ? editedPolicy.deductible : policy.deductible}
                           onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, deductible: parseFloat(e.target.value)})}
                           disabled={!isEditing} />
                  </div>
                  <div className="space-y-2">
                    <Label>Risk Level</Label>
                    <Select value={isEditing ? editedPolicy.riskLevel : policy.riskLevel}
                            onValueChange={(value) => isEditing && setEditedPolicy({...editedPolicy, riskLevel: value as "low" | "medium" | "high"})}
                            disabled={!isEditing}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="low">Low Risk</SelectItem>
                        <SelectItem value="medium">Medium Risk</SelectItem>
                        <SelectItem value="high">High Risk</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Crop Information */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center">
                  <Crop className="h-5 w-5 mr-2" />
                  Crop Information
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <Label>Crop Type</Label>
                  <Select value={isEditing ? editedPolicy.cropType : policy.cropType}
                          onValueChange={(value) => isEditing && setEditedPolicy({...editedPolicy, cropType: value})}
                          disabled={!isEditing}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="maize">Maize</SelectItem>
                      <SelectItem value="rice">Rice</SelectItem>
                      <SelectItem value="potatoes">Potatoes</SelectItem>
                      <SelectItem value="beans">Beans</SelectItem>
                      <SelectItem value="wheat">Wheat</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Farm Size (hectares)</Label>
                  <Input type="number" 
                         value={isEditing ? editedPolicy.farmSize : policy.farmSize}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, farmSize: parseFloat(e.target.value)})}
                         disabled={!isEditing} />
                </div>

                <div className="space-y-2">
                  <Label>Location</Label>
                  <Input value={isEditing ? editedPolicy.location : policy.location}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, location: e.target.value})}
                         disabled={!isEditing} />
                </div>

                <div className="space-y-2">
                  <Label>Policy Status</Label>
                  <Select value={isEditing ? editedPolicy.status : policy.status}
                          onValueChange={(value) => isEditing && setEditedPolicy({...editedPolicy, status: value as Policy["status"]})}
                          disabled={!isEditing}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="active">Active</SelectItem>
                      <SelectItem value="pending">Pending</SelectItem>
                      <SelectItem value="expired">Expired</SelectItem>
                      <SelectItem value="cancelled">Cancelled</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="farmer" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center">
                <User className="h-5 w-5 mr-2" />
                Farmer Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Farmer ID</Label>
                  <Input value={isEditing ? editedPolicy.farmerId : policy.farmerId}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, farmerId: e.target.value})}
                         disabled={!isEditing} />
                </div>
                <div className="space-y-2">
                  <Label>Farmer Name</Label>
                  <Input value={isEditing ? editedPolicy.farmerName : policy.farmerName}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, farmerName: e.target.value})}
                         disabled={!isEditing} />
                </div>
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Phone Number</Label>
                  <Input value={isEditing ? editedPolicy.phoneNumber || "" : policy.phoneNumber || ""}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, phoneNumber: e.target.value})}
                         disabled={!isEditing} />
                </div>
                <div className="space-y-2">
                  <Label>Email</Label>
                  <Input type="email" 
                         value={isEditing ? editedPolicy.email || "" : policy.email || ""}
                         onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, email: e.target.value})}
                         disabled={!isEditing} />
                </div>
              </div>

              <div className="space-y-2">
                <Label>Address</Label>
                <Textarea value={isEditing ? editedPolicy.address || "" : policy.address || ""}
                          onChange={(e) => isEditing && setEditedPolicy({...editedPolicy, address: e.target.value})}
                          disabled={!isEditing}
                          rows={3} />
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="claims" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center">
                <FileText className="h-5 w-5 mr-2" />
                Claims History
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {mockClaims.map((claim) => (
                  <div key={claim.id} className="flex items-center justify-between p-4 border rounded-lg">
                    <div className="flex items-center space-x-4">
                      <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                        <FileText className="h-5 w-5 text-blue-600" />
                      </div>
                      <div>
                        <p className="font-medium">{claim.id}</p>
                        <p className="text-sm text-gray-500">{claim.description}</p>
                        <p className="text-xs text-gray-400">{claim.date}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="font-medium">{claim.amount.toLocaleString()} RWF</p>
                      <Badge className={claim.status === "approved" ? "bg-green-100 text-green-800" : "bg-yellow-100 text-yellow-800"}>
                        {claim.status}
                      </Badge>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="payments" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center">
                <DollarSign className="h-5 w-5 mr-2" />
                Payment History
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {mockPayments.map((payment) => (
                  <div key={payment.id} className="flex items-center justify-between p-4 border rounded-lg">
                    <div className="flex items-center space-x-4">
                      <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
                        <DollarSign className="h-5 w-5 text-green-600" />
                      </div>
                      <div>
                        <p className="font-medium">{payment.id}</p>
                        <p className="text-sm text-gray-500 capitalize">{payment.type} payment</p>
                        <p className="text-xs text-gray-400">{payment.date}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="font-medium">{payment.amount.toLocaleString()} RWF</p>
                      <Badge className={payment.status === "completed" ? "bg-green-100 text-green-800" : "bg-yellow-100 text-yellow-800"}>
                        {payment.status}
                      </Badge>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Danger Zone */}
      <Card className="border-red-200">
        <CardHeader>
          <CardTitle className="text-red-600">Danger Zone</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between">
            <div>
              <h3 className="font-medium">Delete Policy</h3>
              <p className="text-sm text-gray-500">Once deleted, this policy cannot be recovered.</p>
            </div>
            <Button variant="destructive" onClick={() => onDelete(policy.id)}>
              <Trash2 className="h-4 w-4 mr-2" />
              Delete Policy
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import PolicyDetailsView from "./PolicyDetailsView";
import { getPolicies, getPolicyById, updatePolicy as updatePolicyApi, deletePolicy as deletePolicyApi } from "@/services/policiesApi";
import { useToast } from "@/hooks/use-toast";
import { 
  Plus,
  Search,
  Filter,
  Edit,
  Trash2,
  Eye,
  Download,
  Upload,
  Shield,
  User,
  MapPin,
  Calendar,
  DollarSign,
  AlertTriangle,
  CheckCircle,
  Clock,
  X
} from "lucide-react";

interface Policy {
  id: string;
  farmerId: string;
  farmerName: string;
  cropType: string;
  coverageAmount: number;
  premiumAmount: number;
  startDate: string;
  endDate: string;
  status: "active" | "pending" | "expired" | "cancelled";
  location: string;
  farmSize: number;
  riskLevel: "low" | "medium" | "high";
  deductible: number;
  createdAt: string;
}

interface PolicyManagementProps {
  onNavigateToCreate?: () => void;
}

export default function PolicyManagement({ onNavigateToCreate }: PolicyManagementProps = {}) {
  const { toast } = useToast();
  const [policies, setPolicies] = useState<Policy[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [cropFilter, setCropFilter] = useState("all");
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [selectedPolicy, setSelectedPolicy] = useState<Policy | null>(null);
  const [viewMode, setViewMode] = useState<"table" | "grid">("table");
  const [viewingPolicy, setViewingPolicy] = useState<Policy | null>(null);

  // Load policies from API
  useEffect(() => {
    loadPolicies();
  }, []);

  const loadPolicies = async () => {
    setLoading(true);
    setError(null);
    try {
      const response: any = await getPolicies(1, 100);
      let policiesData: any[] = [];
      
      if (Array.isArray(response)) {
        policiesData = response;
      } else if (response && typeof response === 'object') {
        policiesData = response.data || response.policies || [];
      }
      
      // Map API response to Policy interface
      const mappedPolicies: Policy[] = policiesData.map((policy: any) => ({
        id: policy._id || policy.id || '',
        farmerId: policy.farmerId || policy.farmer?._id || policy.farmer?.id || '',
        farmerName: policy.farmer?.firstName && policy.farmer?.lastName 
          ? `${policy.farmer.firstName} ${policy.farmer.lastName}` 
          : policy.farmer?.name || policy.farmerName || 'Unknown Farmer',
        cropType: policy.cropType || 'Unknown',
        coverageAmount: policy.coverageAmount || policy.coverage || 0,
        premiumAmount: policy.premiumAmount || policy.premium || 0,
        startDate: policy.startDate || policy.validityPeriod?.start || new Date().toISOString().split('T')[0],
        endDate: policy.endDate || policy.validityPeriod?.end || policy.validityPeriod || new Date().toISOString().split('T')[0],
        status: (policy.status || 'pending').toLowerCase() as "active" | "pending" | "expired" | "cancelled",
        location: policy.location || policy.farm?.location || 'Unknown',
        farmSize: policy.farmSize || policy.farm?.size || 0,
        riskLevel: (policy.riskLevel || 'medium').toLowerCase() as "low" | "medium" | "high",
        deductible: policy.deductible || 0,
        createdAt: policy.createdAt || policy.created || new Date().toISOString().split('T')[0],
      }));
      
      setPolicies(mappedPolicies);
    } catch (err: any) {
      console.error('Failed to load policies:', err);
      setError(err.message || 'Failed to load policies');
      toast({
        title: "Error",
        description: err.message || 'Failed to load policies',
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };


  // Form state for edit
  const [formData, setFormData] = useState({
    farmerId: "",
    farmerName: "",
    cropType: "",
    coverageAmount: "",
    premiumAmount: "",
    startDate: "",
    endDate: "",
    location: "",
    farmSize: "",
    riskLevel: "low",
    deductible: ""
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case "active": return "bg-green-100 text-green-800";
      case "pending": return "bg-yellow-100 text-yellow-800";
      case "expired": return "bg-red-100 text-red-800";
      case "cancelled": return "bg-gray-700 text-white";
      default: return "bg-gray-700 text-white";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "active": return <CheckCircle className="h-4 w-4" />;
      case "pending": return <Clock className="h-4 w-4" />;
      case "expired": return <AlertTriangle className="h-4 w-4" />;
      case "cancelled": return <X className="h-4 w-4" />;
      default: return <Clock className="h-4 w-4" />;
    }
  };

  const getRiskLevelColor = (level: string) => {
    switch (level) {
      case "low": return "bg-green-100 text-green-800";
      case "medium": return "bg-yellow-100 text-yellow-800";
      case "high": return "bg-red-100 text-red-800";
      default: return "bg-gray-700 text-white";
    }
  };

  const filteredPolicies = policies.filter(policy => {
    const matchesSearch = policy.farmerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         policy.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         policy.farmerId.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === "all" || policy.status === statusFilter;
    const matchesCrop = cropFilter === "all" || policy.cropType === cropFilter;
    
    return matchesSearch && matchesStatus && matchesCrop;
  });


  const handleEditPolicy = async () => {
    if (!selectedPolicy) return;

    try {
      const updateData = {
        coverageAmount: parseFloat(formData.coverageAmount),
        premium: parseFloat(formData.premiumAmount),
        endDate: formData.endDate,
        status: selectedPolicy.status,
        notes: formData.location ? `Location: ${formData.location}` : undefined,
      };

      await updatePolicyApi(selectedPolicy.id, updateData);
      
      toast({
        title: "Success",
        description: "Policy updated successfully",
        variant: "default",
      });
      
      // Reload policies
      loadPolicies();
      setIsEditDialogOpen(false);
      setSelectedPolicy(null);
      resetForm();
    } catch (err: any) {
      console.error('Failed to update policy:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to update policy',
        variant: "destructive",
      });
    }
  };

  const handleDeletePolicy = async (policyId: string) => {
    if (!confirm('Are you sure you want to delete this policy?')) {
      return;
    }

    try {
      await deletePolicyApi(policyId);
      
      toast({
        title: "Success",
        description: "Policy deleted successfully",
        variant: "default",
      });
      
      // Reload policies
      loadPolicies();
    } catch (err: any) {
      console.error('Failed to delete policy:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to delete policy',
        variant: "destructive",
      });
    }
  };

  const handleUpdateStatus = async (policyId: string, newStatus: Policy["status"]) => {
    try {
      await updatePolicyApi(policyId, { status: newStatus });
      
      toast({
        title: "Success",
        description: "Policy status updated successfully",
        variant: "default",
      });
      
      // Reload policies
      loadPolicies();
    } catch (err: any) {
      console.error('Failed to update policy status:', err);
      toast({
        title: "Error",
        description: err.message || 'Failed to update policy status',
        variant: "destructive",
      });
    }
  };

  const openEditDialog = (policy: Policy) => {
    setSelectedPolicy(policy);
    setFormData({
      farmerId: policy.farmerId,
      farmerName: policy.farmerName,
      cropType: policy.cropType,
      coverageAmount: policy.coverageAmount.toString(),
      premiumAmount: policy.premiumAmount.toString(),
      startDate: policy.startDate,
      endDate: policy.endDate,
      location: policy.location,
      farmSize: policy.farmSize.toString(),
      riskLevel: policy.riskLevel,
      deductible: policy.deductible.toString()
    });
    setIsEditDialogOpen(true);
  };

  const handleViewPolicy = (policy: Policy) => {
    setViewingPolicy(policy);
  };

  const handleBackToList = () => {
    setViewingPolicy(null);
  };

  const handleEditFromDetails = (updatedPolicy: Policy) => {
    setPolicies(policies.map(policy => 
      policy.id === updatedPolicy.id ? updatedPolicy : policy
    ));
  };

  const handleCreateClick = () => {
    if (onNavigateToCreate) {
      onNavigateToCreate();
    }
  };

  const renderEditPolicyForm = () => (
    <div className="space-y-4">
      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-2">
          <Label htmlFor="edit-cropType">Crop Type</Label>
          <Select value={formData.cropType} onValueChange={(value) => setFormData({...formData, cropType: value})}>
            <SelectTrigger>
              <SelectValue placeholder="Select crop type" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="maize">Maize</SelectItem>
              <SelectItem value="rice">Rice</SelectItem>
              <SelectItem value="potatoes">Potatoes</SelectItem>
              <SelectItem value="beans">Beans</SelectItem>
              <SelectItem value="wheat">Wheat</SelectItem>
            </SelectContent>
          </Select>
        </div>
        <div className="space-y-2">
          <Label htmlFor="edit-farmSize">Farm Size (hectares)</Label>
          <Input
            id="edit-farmSize"
            type="number"
            value={formData.farmSize}
            onChange={(e) => setFormData({...formData, farmSize: e.target.value})}
            placeholder="Enter farm size"
          />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-2">
          <Label htmlFor="edit-coverageAmount">Coverage Amount (RWF)</Label>
          <Input
            id="edit-coverageAmount"
            type="number"
            value={formData.coverageAmount}
            onChange={(e) => setFormData({...formData, coverageAmount: e.target.value})}
            placeholder="Enter coverage amount"
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="edit-premiumAmount">Premium Amount (RWF)</Label>
          <Input
            id="edit-premiumAmount"
            type="number"
            value={formData.premiumAmount}
            onChange={(e) => setFormData({...formData, premiumAmount: e.target.value})}
            placeholder="Enter premium amount"
          />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-2">
          <Label htmlFor="edit-startDate">Start Date</Label>
          <Input
            id="edit-startDate"
            type="date"
            value={formData.startDate}
            onChange={(e) => setFormData({...formData, startDate: e.target.value})}
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="edit-endDate">End Date</Label>
          <Input
            id="edit-endDate"
            type="date"
            value={formData.endDate}
            onChange={(e) => setFormData({...formData, endDate: e.target.value})}
          />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-2">
          <Label htmlFor="edit-location">Location</Label>
          <Input
            id="edit-location"
            value={formData.location}
            onChange={(e) => setFormData({...formData, location: e.target.value})}
            placeholder="Enter location"
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="edit-riskLevel">Risk Level</Label>
          <Select value={formData.riskLevel} onValueChange={(value) => setFormData({...formData, riskLevel: value})}>
            <SelectTrigger>
              <SelectValue placeholder="Select risk level" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="low">Low Risk</SelectItem>
              <SelectItem value="medium">Medium Risk</SelectItem>
              <SelectItem value="high">High Risk</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="edit-deductible">Deductible (RWF)</Label>
        <Input
          id="edit-deductible"
          type="number"
          value={formData.deductible}
          onChange={(e) => setFormData({...formData, deductible: e.target.value})}
          placeholder="Enter deductible amount"
        />
      </div>
    </div>
  );

  // If viewing a specific policy, show the details view
  if (viewingPolicy) {
    return (
      <PolicyDetailsView
        policy={viewingPolicy}
        onBack={handleBackToList}
        onEdit={handleEditFromDetails}
        onDelete={handleDeletePolicy}
      />
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-4 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Policy Management</h1>
          <p className="text-sm text-gray-600 mt-1">Manage insurance policies for farmers</p>
        </div>
        <div className="flex items-center space-x-3">
          <Button
            variant="outline"
            onClick={() => setViewMode(viewMode === "table" ? "grid" : "table")}
          >
            {viewMode === "table" ? "Grid View" : "Table View"}
          </Button>
          <Button className="bg-blue-600 hover:bg-blue-700" onClick={handleCreateClick}>
                <Plus className="h-4 w-4 mr-2" />
                Create Policy
              </Button>
        </div>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="p-6">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
                <Input
                  placeholder="Search policies by farmer name, ID, or policy ID..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
            <div className="flex gap-3">
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-40">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="pending">Pending</SelectItem>
                  <SelectItem value="expired">Expired</SelectItem>
                  <SelectItem value="cancelled">Cancelled</SelectItem>
                </SelectContent>
              </Select>
              <Select value={cropFilter} onValueChange={setCropFilter}>
                <SelectTrigger className="w-40">
                  <SelectValue placeholder="Crop Type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Crops</SelectItem>
                  <SelectItem value="maize">Maize</SelectItem>
                  <SelectItem value="rice">Rice</SelectItem>
                  <SelectItem value="potatoes">Potatoes</SelectItem>
                  <SelectItem value="beans">Beans</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Error Message */}
      {error && (
        <Card className="bg-red-900/20 border-red-700">
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <AlertTriangle className="h-5 w-5 text-red-400" />
                <p className="text-red-400">{error}</p>
              </div>
              <Button
                onClick={loadPolicies}
                variant="outline"
                size="sm"
                className="border-gray-700 text-white hover:bg-gray-800"
              >
                Retry
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Stats Cards */}
      <div className="grid gap-6 md:grid-cols-4">
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Total Policies</p>
                <p className="text-2xl font-bold text-white">{policies.length}</p>
              </div>
              <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center">
                <Shield className="h-6 w-6 text-blue-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Active Policies</p>
                <p className="text-2xl font-bold text-white">{policies.filter(p => p.status === 'active').length}</p>
              </div>
              <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center">
                <CheckCircle className="h-6 w-6 text-green-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Pending Policies</p>
                <p className="text-2xl font-bold text-white">{policies.filter(p => p.status === 'pending').length}</p>
              </div>
              <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center">
                <Clock className="h-6 w-6 text-yellow-600" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-white/70">Total Coverage</p>
                <p className="text-2xl font-bold text-white">
                  {(policies.reduce((sum, p) => sum + p.coverageAmount, 0) / 1000000).toFixed(1)}M RWF
                </p>
              </div>
              <div className="w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center">
                <DollarSign className="h-6 w-6 text-purple-600" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Policies Table */}
      <Card>
        <CardHeader>
          <CardTitle>Policies ({filteredPolicies.length})</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <div className="text-center">
                <Clock className="h-12 w-12 animate-spin text-blue-500 mx-auto mb-4" />
                <p className="text-white/60">Loading policies...</p>
              </div>
            </div>
          ) : filteredPolicies.length === 0 ? (
            <div className="flex items-center justify-center py-12">
              <div className="text-center">
                <Shield className="h-12 w-12 mx-auto mb-4 text-white/40" />
                <p className="text-white/60">No policies found</p>
                {searchTerm || statusFilter !== "all" || cropFilter !== "all" ? (
                  <Button
                    variant="outline"
                    onClick={() => {
                      setSearchTerm("");
                      setStatusFilter("all");
                      setCropFilter("all");
                    }}
                    className="mt-4"
                  >
                    Clear Filters
                  </Button>
                ) : null}
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b">
                    <th className="text-left p-3 font-medium">Policy ID</th>
                    <th className="text-left p-3 font-medium">Farmer</th>
                    <th className="text-left p-3 font-medium">Crop</th>
                    <th className="text-left p-3 font-medium">Coverage</th>
                    <th className="text-left p-3 font-medium">Premium</th>
                    <th className="text-left p-3 font-medium">Status</th>
                    <th className="text-left p-3 font-medium">Risk</th>
                    <th className="text-left p-3 font-medium">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredPolicies.map((policy) => (
                  <tr key={policy.id} className="border-b hover:bg-gray-50">
                    <td className="p-3 font-medium">{policy.id}</td>
                    <td className="p-3">
                      <div>
                        <div className="font-medium">{policy.farmerName}</div>
                        <div className="text-sm text-gray-500">{policy.farmerId}</div>
                      </div>
                    </td>
                    <td className="p-3">{policy.cropType}</td>
                    <td className="p-3">{policy.coverageAmount.toLocaleString()} RWF</td>
                    <td className="p-3">{policy.premiumAmount.toLocaleString()} RWF</td>
                    <td className="p-3">
                      <Badge className={getStatusColor(policy.status)}>
                        {getStatusIcon(policy.status)}
                        <span className="ml-1 capitalize">{policy.status}</span>
                      </Badge>
                    </td>
                    <td className="p-3">
                      <Badge className={getRiskLevelColor(policy.riskLevel)}>
                        {policy.riskLevel} risk
                      </Badge>
                    </td>
                    <td className="p-3">
                      <div className="flex items-center space-x-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleViewPolicy(policy)}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => openEditDialog(policy)}
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleDeletePolicy(policy.id)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                        <Select
                          value={policy.status}
                          onValueChange={(value) => handleUpdateStatus(policy.id, value as Policy["status"])}
                        >
                          <SelectTrigger className="w-24 h-8">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="active">Active</SelectItem>
                            <SelectItem value="pending">Pending</SelectItem>
                            <SelectItem value="expired">Expired</SelectItem>
                            <SelectItem value="cancelled">Cancelled</SelectItem>
                          </SelectContent>
                        </Select>
                      </div>
                    </td>
                  </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Edit Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Edit Policy - {selectedPolicy?.id}</DialogTitle>
          </DialogHeader>
          {renderEditPolicyForm()}
          <div className="flex justify-end space-x-3 pt-4">
            <Button variant="outline" onClick={() => setIsEditDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleEditPolicy}>
              Update Policy
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Satellite,
  TrendingUp,
  TrendingDown,
  Activity,
  CloudRain,
  Leaf,
  MapPin,
  RefreshCw,
  AlertCircle,
  CheckCircle,
  Loader2,
} from "lucide-react";
import {
  LineChart,
  Line,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";

// Use environment variable for easy deployment across different environments
const API_BASE_URL = `${import.meta.env.VITE_API_URL || "http://localhost:3000"}/api/v1/satellite`;

interface StatisticsResult {
  scene_id: string;
  view_id: string;
  date: string;
  cloud: number;
  notes: string[];
  q1: number;
  q3: number;
  max: number;
  min: number;
  p10: number;
  p90: number;
  std: number;
  median: number;
  average: number;
  variance: number;
}

interface TaskResponse {
  status: string;
  task_id: string;
  req_id: string;
  task_timeout: number;
}

interface TaskStatusResponse {
  errors?: Array<{
    scene_id: string;
    view_id: string;
    date: string;
    error: string;
    notes: string[];
  }>;
  result?: StatisticsResult[];
}

// Sample Rwanda farm coordinates (Nyagatare District - major agricultural area)
const DEFAULT_COORDINATES = [
  [30.32, -1.3],
  [30.35, -1.3],
  [30.35, -1.28],
  [30.32, -1.28],
  [30.32, -1.3],
];

export default function SatelliteStatistics() {
  const [loading, setLoading] = useState(false);
  const [taskId, setTaskId] = useState<string | null>(null);
  const [statistics, setStatistics] = useState<StatisticsResult[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [selectedIndex, setSelectedIndex] = useState("NDVI");
  const [dateStart, setDateStart] = useState("2024-09-01");
  const [dateEnd, setDateEnd] = useState("2024-10-08");

  // Available indices
  const indices = [
    { value: "NDVI", label: "NDVI (Vegetation Health)" },
    { value: "RECI", label: "RECI (Red-Edge Chlorophyll)" },
    { value: "MSAVI", label: "MSAVI (Soil Adjusted)" },
    { value: "EVI", label: "EVI (Enhanced Vegetation)" },
    { value: "NDMI", label: "NDMI (Moisture)" },
    { value: "SAVI", label: "SAVI (Soil Adjusted)" },
  ];

  // Create statistics task
  const createTask = async () => {
    setLoading(true);
    setError(null);

    try {
      const requestBody = {
        type: "mt_stats",
        params: {
          bm_type: [selectedIndex],
          date_start: dateStart,
          date_end: dateEnd,
          geometry: {
            type: "Polygon",
            coordinates: [DEFAULT_COORDINATES],
          },
          reference: `insurer_${Date.now()}`,
          sensors: ["Sentinel-2"],
          max_cloud_cover_in_aoi: 30,
          exclude_cover_pixels: true,
          cloud_masking_level: 2,
          limit: 20,
        },
      };

      const response = await fetch(`${API_BASE_URL}/task`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(requestBody),
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.statusText}`);
      }

      const data: TaskResponse = await response.json();
      setTaskId(data.task_id);

      // Start polling for results
      pollTaskStatus(data.task_id);
    } catch (err: any) {
      setError(err.message || "Failed to create task");
      setLoading(false);
    }
  };

  // Poll task status
  const pollTaskStatus = async (id: string) => {
    const maxAttempts = 30;
    let attempts = 0;

    const poll = async () => {
      try {
        const response = await fetch(`${API_BASE_URL}/task/${id}`);

        if (!response.ok) {
          throw new Error(`API Error: ${response.statusText}`);
        }

        const data: TaskStatusResponse = await response.json();

        if (data.result && data.result.length > 0) {
          setStatistics(
            data.result.sort(
              (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
            ),
          );
          setLoading(false);
          return;
        }

        if (data.errors && data.errors.length > 0) {
          setError(data.errors[0].error);
          setLoading(false);
          return;
        }

        attempts++;
        if (attempts < maxAttempts) {
          setTimeout(poll, 3000); // Poll every 3 seconds
        } else {
          setError("Task timeout - please try again");
          setLoading(false);
        }
      } catch (err: any) {
        setError(err.message || "Failed to fetch task status");
        setLoading(false);
      }
    };

    poll();
  };

  // Calculate summary statistics
  const getSummaryStats = () => {
    if (statistics.length === 0) return null;

    const latestData = statistics[statistics.length - 1];
    const previousData =
      statistics.length > 1 ? statistics[statistics.length - 2] : null;

    const avgChange = previousData
      ? ((latestData.average - previousData.average) / previousData.average) *
        100
      : 0;

    return {
      latest: latestData,
      avgChange,
      totalScenes: statistics.length,
      avgCloudCover:
        statistics.reduce((sum, s) => sum + s.cloud, 0) / statistics.length,
      overallAvg:
        statistics.reduce((sum, s) => sum + s.average, 0) / statistics.length,
      overallStd:
        statistics.reduce((sum, s) => sum + s.std, 0) / statistics.length,
    };
  };

  const summaryStats = getSummaryStats();

  // Format chart data
  const chartData = statistics.map((stat) => ({
    date: new Date(stat.date).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
    }),
    average: parseFloat(stat.average.toFixed(4)),
    median: parseFloat(stat.median.toFixed(4)),
    max: parseFloat(stat.max.toFixed(4)),
    min: parseFloat(stat.min.toFixed(4)),
    std: parseFloat(stat.std.toFixed(4)),
    cloud: stat.cloud,
  }));

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-900/20 to-indigo-900/20 border border-blue-700/30 rounded-2xl p-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold mb-2 text-white flex items-center gap-3">
              <Satellite className="h-7 w-7 text-blue-400" />
              Satellite-Based Crop Analytics
            </h1>
            <p className="text-blue-400">
              Real-time vegetation indices and soil moisture data from
              Sentinel-2 satellite imagery
            </p>
          </div>
          <Badge className="bg-green-400/20 text-green-400 border-green-400/30 px-4 py-2">
            <Activity className="h-4 w-4 mr-2" />
            Live Data
          </Badge>
        </div>
      </div>

      {/* Controls */}
      <Card className={dashboardTheme.card}>
        <CardHeader>
          <CardTitle className="text-white">Analysis Parameters</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 md:grid-cols-4">
            <div>
              <Label htmlFor="index" className="text-white/80">
                Vegetation Index
              </Label>
              <Select value={selectedIndex} onValueChange={setSelectedIndex}>
                <SelectTrigger className={dashboardTheme.select}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-gray-800 border-gray-700">
                  {indices.map((idx) => (
                    <SelectItem
                      key={idx.value}
                      value={idx.value}
                      className="text-white hover:bg-white/10"
                    >
                      {idx.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="start-date" className="text-white/80">
                Start Date
              </Label>
              <Input
                id="start-date"
                type="date"
                value={dateStart}
                onChange={(e) => setDateStart(e.target.value)}
                className={dashboardTheme.input}
              />
            </div>

            <div>
              <Label htmlFor="end-date" className="text-white/80">
                End Date
              </Label>
              <Input
                id="end-date"
                type="date"
                value={dateEnd}
                onChange={(e) => setDateEnd(e.target.value)}
                className={dashboardTheme.input}
              />
            </div>

            <div className="flex items-end">
              <Button
                onClick={createTask}
                disabled={loading}
                className={`${dashboardTheme.buttonPrimary} w-full`}
              >
                {loading ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Processing...
                  </>
                ) : (
                  <>
                    <RefreshCw className="h-4 w-4 mr-2" />
                    Fetch Data
                  </>
                )}
              </Button>
            </div>
          </div>

          {error && (
            <div className="mt-4 p-4 bg-red-500/20 border border-red-500/30 rounded-lg flex items-start gap-3">
              <AlertCircle className="h-5 w-5 text-red-400 flex-shrink-0 mt-0.5" />
              <div>
                <p className="text-red-400 font-medium">Error</p>
                <p className="text-red-300 text-sm">{error}</p>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Summary Stats */}
      {summaryStats && (
        <div className="grid gap-6 md:grid-cols-4">
          <Card className={`${dashboardTheme.card} border-green-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Latest {selectedIndex}
                  </p>
                  <p className="text-2xl font-bold text-white">
                    {summaryStats.latest.average.toFixed(4)}
                  </p>
                  <div className="flex items-center gap-2 mt-1">
                    {summaryStats.avgChange >= 0 ? (
                      <TrendingUp className="h-4 w-4 text-green-400" />
                    ) : (
                      <TrendingDown className="h-4 w-4 text-red-400" />
                    )}
                    <span
                      className={`text-sm ${summaryStats.avgChange >= 0 ? "text-green-400" : "text-red-400"}`}
                    >
                      {Math.abs(summaryStats.avgChange).toFixed(2)}%
                    </span>
                  </div>
                </div>
                <div className="w-12 h-12 bg-green-400/20 rounded-lg flex items-center justify-center">
                  <Leaf className="h-6 w-6 text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-blue-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Total Scenes
                  </p>
                  <p className="text-2xl font-bold text-white">
                    {summaryStats.totalScenes}
                  </p>
                  <p className="text-sm text-white/60 mt-1">Analyzed</p>
                </div>
                <div className="w-12 h-12 bg-blue-400/20 rounded-lg flex items-center justify-center">
                  <Satellite className="h-6 w-6 text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-cyan-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Avg Cloud Cover
                  </p>
                  <p className="text-2xl font-bold text-white">
                    {summaryStats.avgCloudCover.toFixed(1)}%
                  </p>
                  <p className="text-sm text-white/60 mt-1">
                    {summaryStats.avgCloudCover < 20
                      ? "Excellent"
                      : summaryStats.avgCloudCover < 40
                        ? "Good"
                        : "Fair"}
                  </p>
                </div>
                <div className="w-12 h-12 bg-cyan-400/20 rounded-lg flex items-center justify-center">
                  <CloudRain className="h-6 w-6 text-cyan-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-purple-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Std Deviation
                  </p>
                  <p className="text-2xl font-bold text-white">
                    {summaryStats.overallStd.toFixed(4)}
                  </p>
                  <p className="text-sm text-white/60 mt-1">Variability</p>
                </div>
                <div className="w-12 h-12 bg-purple-400/20 rounded-lg flex items-center justify-center">
                  <Activity className="h-6 w-6 text-purple-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Charts */}
      {statistics.length > 0 && (
        <div className="grid gap-6 lg:grid-cols-2">
          {/* Time Series Chart */}
          <Card className={dashboardTheme.card}>
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <TrendingUp className="h-5 w-5 text-green-400" />
                {selectedIndex} Trends Over Time
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient
                        id="avgGradient"
                        x1="0"
                        y1="0"
                        x2="0"
                        y2="1"
                      >
                        <stop
                          offset="5%"
                          stopColor="#10B981"
                          stopOpacity={0.4}
                        />
                        <stop
                          offset="95%"
                          stopColor="#10B981"
                          stopOpacity={0.1}
                        />
                      </linearGradient>
                      <linearGradient
                        id="medianGradient"
                        x1="0"
                        y1="0"
                        x2="0"
                        y2="1"
                      >
                        <stop
                          offset="5%"
                          stopColor="#3B82F6"
                          stopOpacity={0.4}
                        />
                        <stop
                          offset="95%"
                          stopColor="#3B82F6"
                          stopOpacity={0.1}
                        />
                      </linearGradient>
                    </defs>
                    <CartesianGrid
                      strokeDasharray="3 3"
                      stroke="#374151"
                      opacity={0.3}
                    />
                    <XAxis
                      dataKey="date"
                      stroke="#9CA3AF"
                      fontSize={11}
                      tickLine={false}
                    />
                    <YAxis stroke="#9CA3AF" fontSize={11} tickLine={false} />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: "rgba(31, 41, 55, 0.95)",
                        border: "1px solid rgba(75, 85, 99, 0.3)",
                        borderRadius: "12px",
                        color: "#fff",
                      }}
                    />
                    <Legend />
                    <Area
                      type="monotone"
                      dataKey="average"
                      stroke="#10B981"
                      fill="url(#avgGradient)"
                      strokeWidth={2}
                      name="Average"
                    />
                    <Area
                      type="monotone"
                      dataKey="median"
                      stroke="#3B82F6"
                      fill="url(#medianGradient)"
                      strokeWidth={2}
                      name="Median"
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          {/* Variability Chart */}
          <Card className={dashboardTheme.card}>
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <Activity className="h-5 w-5 text-purple-400" />
                Data Variability (Min/Max/Std Dev)
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={chartData}>
                    <CartesianGrid
                      strokeDasharray="3 3"
                      stroke="#374151"
                      opacity={0.3}
                    />
                    <XAxis
                      dataKey="date"
                      stroke="#9CA3AF"
                      fontSize={11}
                      tickLine={false}
                    />
                    <YAxis stroke="#9CA3AF" fontSize={11} tickLine={false} />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: "rgba(31, 41, 55, 0.95)",
                        border: "1px solid rgba(75, 85, 99, 0.3)",
                        borderRadius: "12px",
                        color: "#fff",
                      }}
                    />
                    <Legend />
                    <Line
                      type="monotone"
                      dataKey="max"
                      stroke="#EF4444"
                      strokeWidth={2}
                      dot={{ r: 3 }}
                      name="Maximum"
                    />
                    <Line
                      type="monotone"
                      dataKey="min"
                      stroke="#3B82F6"
                      strokeWidth={2}
                      dot={{ r: 3 }}
                      name="Minimum"
                    />
                    <Line
                      type="monotone"
                      dataKey="std"
                      stroke="#8B5CF6"
                      strokeWidth={2}
                      dot={{ r: 3 }}
                      name="Std Deviation"
                    />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Detailed Statistics Table */}
      {statistics.length > 0 && (
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-white">
              Detailed Scene Statistics
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-700/30">
                    <th className="text-left py-3 px-4 text-white/80 font-medium">
                      Date
                    </th>
                    <th className="text-left py-3 px-4 text-white/80 font-medium">
                      Scene ID
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Average
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Median
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Min
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Max
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Std Dev
                    </th>
                    <th className="text-right py-3 px-4 text-white/80 font-medium">
                      Cloud %
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {statistics.map((stat, idx) => (
                    <tr
                      key={idx}
                      className="border-b border-gray-800/30 hover:bg-gray-800/20"
                    >
                      <td className="py-3 px-4 text-white/70">
                        {new Date(stat.date).toLocaleDateString()}
                      </td>
                      <td className="py-3 px-4 text-white/60 text-sm font-mono">
                        {stat.scene_id.substring(0, 20)}...
                      </td>
                      <td className="py-3 px-4 text-right text-white font-medium">
                        {stat.average.toFixed(4)}
                      </td>
                      <td className="py-3 px-4 text-right text-white/70">
                        {stat.median.toFixed(4)}
                      </td>
                      <td className="py-3 px-4 text-right text-blue-400">
                        {stat.min.toFixed(4)}
                      </td>
                      <td className="py-3 px-4 text-right text-red-400">
                        {stat.max.toFixed(4)}
                      </td>
                      <td className="py-3 px-4 text-right text-purple-400">
                        {stat.std.toFixed(4)}
                      </td>
                      <td className="py-3 px-4 text-right">
                        <Badge
                          className={
                            stat.cloud < 20
                              ? "bg-green-400/20 text-green-400"
                              : stat.cloud < 40
                                ? "bg-yellow-400/20 text-yellow-400"
                                : "bg-red-400/20 text-red-400"
                          }
                        >
                          {stat.cloud.toFixed(1)}%
                        </Badge>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Empty State */}
      {statistics.length === 0 && !loading && (
        <Card className={dashboardTheme.card}>
          <CardContent className="py-16">
            <div className="text-center">
              <Satellite className="h-16 w-16 text-white/20 mx-auto mb-4" />
              <h3 className="text-xl font-semibold text-white mb-2">
                No Data Available
              </h3>
              <p className="text-white/60 mb-6">
                Select parameters and click "Fetch Data" to load satellite
                imagery statistics
              </p>
              <div className="flex items-center justify-center gap-2 text-sm text-white/50">
                <MapPin className="h-4 w-4" />
                <span>Monitoring: Nyagatare District, Rwanda</span>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { dashboardTheme } from "@/utils/dashboardTheme";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Cloud,
  CloudRain,
  CloudSnow,
  Sun,
  Wind,
  Droplets,
  Thermometer,
  Eye,
  Gauge,
  RefreshCw,
  AlertCircle,
  Loader2,
  MapPin,
} from "lucide-react";
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
  Area,
  AreaChart,
} from "recharts";

// Use environment variable for easy deployment across different environments
const API_BASE_URL = `${import.meta.env.VITE_API_URL || "http://localhost:3000"}/api/v1/satellite`;

interface WeatherData {
  dt: number;
  dt_txt: string;
  main: {
    temp: number;
    feels_like: number;
    temp_min: number;
    temp_max: number;
    pressure: number;
    humidity: number;
  };
  weather: Array<{
    id: number;
    main: string;
    description: string;
    icon: string;
  }>;
  clouds: {
    all: number;
  };
  wind: {
    speed: number;
    deg: number;
  };
  visibility: number;
  pop: number; // Probability of precipitation
  rain?: {
    "3h": number;
  };
  snow?: {
    "3h": number;
  };
}

interface WeatherResponse {
  list: WeatherData[];
  city: {
    name: string;
    country: string;
    coord: {
      lat: number;
      lon: number;
    };
  };
}

// Sample Rwanda coordinates (Nyagatare District)
const DEFAULT_LAT = -1.3;
const DEFAULT_LON = 30.32;

export default function WeatherForecast() {
  const [loading, setLoading] = useState(false);
  const [weather, setWeather] = useState<WeatherData[]>([]);
  const [cityInfo, setCityInfo] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);
  const [latitude, setLatitude] = useState(DEFAULT_LAT.toString());
  const [longitude, setLongitude] = useState(DEFAULT_LON.toString());

  // Fetch weather forecast
  const fetchWeather = async () => {
    setLoading(true);
    setError(null);

    try {
      const lat = parseFloat(latitude);
      const lon = parseFloat(longitude);

      // Create a small polygon around the point (approximately 0.01 degree buffer)
      const buffer = 0.01;
      const requestBody = {
        geometry: {
          type: "Polygon",
          coordinates: [
            [
              [lon - buffer, lat + buffer],
              [lon + buffer, lat + buffer],
              [lon + buffer, lat - buffer],
              [lon - buffer, lat - buffer],
              [lon - buffer, lat + buffer],
            ],
          ],
        },
      };

      const response = await fetch(`${API_BASE_URL}/weather`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(requestBody),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || `API Error: ${response.statusText}`);
      }

      const data = await response.json();

      // Transform EOS API response to our format
      if (Array.isArray(data) && data.length > 0) {
        const transformedData = data.flatMap((dayData: any) => {
          const date = dayData.Date;
          const times = [
            "02h",
            "05h",
            "08h",
            "11h",
            "14h",
            "17h",
            "20h",
            "23h",
          ];

          return times.map((time, index) => ({
            dt:
              new Date(`${date}T${time.replace("h", ":00:00")}`).getTime() /
              1000,
            dt_txt: `${date} ${time}`,
            main: {
              temp: (dayData.Temp_air_max + dayData.Temp_air_min) / 2,
              feels_like: (dayData.Temp_air_max + dayData.Temp_air_min) / 2 - 2,
              temp_min: dayData.Temp_land_min,
              temp_max: dayData.Temp_land_max,
              pressure: 1013, // Default value
              humidity: dayData.Rel_humidity,
            },
            weather: [
              {
                id: 800,
                main:
                  dayData.Snow_depth > 0
                    ? "Snow"
                    : dayData.Rain[time] > 0.5
                      ? "Rain"
                      : "Clear",
                description:
                  dayData.Snow_depth > 0
                    ? "snow"
                    : dayData.Rain[time] > 0.5
                      ? "rain"
                      : "clear sky",
                icon: "01d",
              },
            ],
            clouds: {
              all: dayData.Rain[time] > 0 ? 75 : 20,
            },
            wind: {
              speed: dayData.Windspeed[time],
              deg: 0,
            },
            visibility: 10000,
            pop:
              dayData.Rain[time] > 0 ? Math.min(dayData.Rain[time] / 10, 1) : 0,
            rain:
              dayData.Rain[time] > 0 ? { "3h": dayData.Rain[time] } : undefined,
          }));
        });

        setWeather(transformedData);
        setCityInfo({
          name: "AOI",
          country: "RW",
          coord: { lat, lon },
        });
      } else {
        throw new Error("Invalid response format from API");
      }

      setLoading(false);
    } catch (err: any) {
      setError(err.message || "Failed to fetch weather data");
      setLoading(false);
    }
  };

  // Get weather icon
  const getWeatherIcon = (weatherMain: string) => {
    switch (weatherMain.toLowerCase()) {
      case "clear":
        return <Sun className="h-8 w-8 text-yellow-400" />;
      case "clouds":
        return <Cloud className="h-8 w-8 text-gray-400" />;
      case "rain":
      case "drizzle":
        return <CloudRain className="h-8 w-8 text-blue-400" />;
      case "snow":
        return <CloudSnow className="h-8 w-8 text-blue-200" />;
      default:
        return <Cloud className="h-8 w-8 text-gray-400" />;
    }
  };

  // Format chart data
  const chartData = weather.slice(0, 16).map((item) => ({
    time: new Date(item.dt * 1000).toLocaleString("en-US", {
      month: "short",
      day: "numeric",
      hour: "2-digit",
    }),
    temperature: Math.round(item.main.temp),
    feelsLike: Math.round(item.main.feels_like),
    humidity: item.main.humidity,
    windSpeed: Math.round(item.wind.speed * 3.6), // Convert m/s to km/h
    precipitation: Math.round((item.pop || 0) * 100),
    clouds: item.clouds.all,
  }));

  // Get current weather (first item)
  const currentWeather = weather[0];

  // Calculate daily averages
  const dailyData = weather.reduce((acc: any, item) => {
    const date = new Date(item.dt * 1000).toLocaleDateString();
    if (!acc[date]) {
      acc[date] = {
        temps: [],
        humidity: [],
        wind: [],
        rain: 0,
      };
    }
    acc[date].temps.push(item.main.temp);
    acc[date].humidity.push(item.main.humidity);
    acc[date].wind.push(item.wind.speed);
    if (item.rain) acc[date].rain += item.rain["3h"] || 0;
    return acc;
  }, {});

  const dailySummary = Object.entries(dailyData)
    .slice(0, 5)
    .map(([date, data]: [string, any]) => ({
      date: new Date(date).toLocaleDateString("en-US", {
        weekday: "short",
        month: "short",
        day: "numeric",
      }),
      avgTemp: Math.round(
        data.temps.reduce((a: number, b: number) => a + b, 0) /
          data.temps.length,
      ),
      maxTemp: Math.round(Math.max(...data.temps)),
      minTemp: Math.round(Math.min(...data.temps)),
      avgHumidity: Math.round(
        data.humidity.reduce((a: number, b: number) => a + b, 0) /
          data.humidity.length,
      ),
      maxWind: Math.round(Math.max(...data.wind) * 3.6),
      totalRain: Math.round(data.rain * 10) / 10,
    }));

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-900/20 to-cyan-900/20 border border-blue-700/30 rounded-2xl p-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold mb-2 text-white flex items-center gap-3">
              <CloudRain className="h-7 w-7 text-blue-400" />
              Weather Forecast
            </h1>
            <p className="text-blue-400">
              5-day weather forecast for agricultural risk assessment
            </p>
          </div>
          <Badge className="bg-blue-400/20 text-blue-400 border-blue-400/30 px-4 py-2">
            <Wind className="h-4 w-4 mr-2" />
            Live Data
          </Badge>
        </div>
      </div>

      {/* Controls */}
      <Card className={dashboardTheme.card}>
        <CardHeader>
          <CardTitle className="text-white">Location Coordinates</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 md:grid-cols-3">
            <div>
              <Label htmlFor="latitude" className="text-white/80">
                Latitude
              </Label>
              <Input
                id="latitude"
                type="number"
                step="0.01"
                value={latitude}
                onChange={(e) => setLatitude(e.target.value)}
                className={dashboardTheme.input}
                placeholder="-1.30"
              />
            </div>

            <div>
              <Label htmlFor="longitude" className="text-white/80">
                Longitude
              </Label>
              <Input
                id="longitude"
                type="number"
                step="0.01"
                value={longitude}
                onChange={(e) => setLongitude(e.target.value)}
                className={dashboardTheme.input}
                placeholder="30.32"
              />
            </div>

            <div className="flex items-end">
              <Button
                onClick={fetchWeather}
                disabled={loading}
                className={`${dashboardTheme.buttonPrimary} w-full`}
              >
                {loading ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Loading...
                  </>
                ) : (
                  <>
                    <RefreshCw className="h-4 w-4 mr-2" />
                    Get Forecast
                  </>
                )}
              </Button>
            </div>
          </div>

          {error && (
            <div className="mt-4 p-4 bg-red-500/20 border border-red-500/30 rounded-lg flex items-start gap-3">
              <AlertCircle className="h-5 w-5 text-red-400 flex-shrink-0 mt-0.5" />
              <div>
                <p className="text-red-400 font-medium">Error</p>
                <p className="text-red-300 text-sm">{error}</p>
              </div>
            </div>
          )}

          {cityInfo && (
            <div className="mt-4 flex items-center gap-2 text-white/70">
              <MapPin className="h-4 w-4" />
              <span>
                {cityInfo.name}, {cityInfo.country} (
                {cityInfo.coord.lat.toFixed(2)}, {cityInfo.coord.lon.toFixed(2)}
                )
              </span>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Current Weather */}
      {currentWeather && (
        <div className="grid gap-6 md:grid-cols-4">
          <Card className={`${dashboardTheme.card} border-blue-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Temperature
                  </p>
                  <p className="text-3xl font-bold text-white">
                    {Math.round(currentWeather.main.temp)}°C
                  </p>
                  <p className="text-sm text-white/60 mt-1">
                    Feels like {Math.round(currentWeather.main.feels_like)}°C
                  </p>
                </div>
                <Thermometer className="h-12 w-12 text-red-400" />
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-cyan-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">Humidity</p>
                  <p className="text-3xl font-bold text-white">
                    {currentWeather.main.humidity}%
                  </p>
                  <p className="text-sm text-white/60 mt-1">
                    {currentWeather.clouds.all}% Cloud Cover
                  </p>
                </div>
                <Droplets className="h-12 w-12 text-cyan-400" />
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-green-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">
                    Wind Speed
                  </p>
                  <p className="text-3xl font-bold text-white">
                    {Math.round(currentWeather.wind.speed * 3.6)} km/h
                  </p>
                  <p className="text-sm text-white/60 mt-1">
                    Direction {currentWeather.wind.deg}°
                  </p>
                </div>
                <Wind className="h-12 w-12 text-green-400" />
              </div>
            </CardContent>
          </Card>

          <Card className={`${dashboardTheme.card} border-purple-700/30`}>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-white/70">Condition</p>
                  <div className="flex items-center gap-2 mt-2">
                    {getWeatherIcon(currentWeather.weather[0].main)}
                    <p className="text-lg font-bold text-white capitalize">
                      {currentWeather.weather[0].description}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm text-white/60">Visibility</p>
                  <p className="text-lg font-semibold text-white">
                    {(currentWeather.visibility / 1000).toFixed(1)} km
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Charts */}
      {weather.length > 0 && (
        <div className="grid gap-6 lg:grid-cols-2">
          {/* Temperature Trend */}
          <Card className={dashboardTheme.card}>
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <Thermometer className="h-5 w-5 text-red-400" />
                Temperature Forecast (48h)
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient
                        id="tempGradient"
                        x1="0"
                        y1="0"
                        x2="0"
                        y2="1"
                      >
                        <stop
                          offset="5%"
                          stopColor="#EF4444"
                          stopOpacity={0.4}
                        />
                        <stop
                          offset="95%"
                          stopColor="#EF4444"
                          stopOpacity={0.1}
                        />
                      </linearGradient>
                    </defs>
                    <CartesianGrid
                      strokeDasharray="3 3"
                      stroke="#374151"
                      opacity={0.3}
                    />
                    <XAxis
                      dataKey="time"
                      stroke="#9CA3AF"
                      fontSize={10}
                      tickLine={false}
                    />
                    <YAxis
                      stroke="#9CA3AF"
                      fontSize={11}
                      tickLine={false}
                      label={{
                        value: "°C",
                        angle: -90,
                        position: "insideLeft",
                        fill: "#9CA3AF",
                      }}
                    />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: "rgba(31, 41, 55, 0.95)",
                        border: "1px solid rgba(75, 85, 99, 0.3)",
                        borderRadius: "12px",
                        color: "#fff",
                      }}
                    />
                    <Legend />
                    <Area
                      type="monotone"
                      dataKey="temperature"
                      stroke="#EF4444"
                      fill="url(#tempGradient)"
                      strokeWidth={2}
                      name="Temperature (°C)"
                    />
                    <Line
                      type="monotone"
                      dataKey="feelsLike"
                      stroke="#F59E0B"
                      strokeWidth={2}
                      dot={{ r: 2 }}
                      name="Feels Like (°C)"
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          {/* Precipitation & Humidity */}
          <Card className={dashboardTheme.card}>
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <CloudRain className="h-5 w-5 text-blue-400" />
                Precipitation & Humidity (48h)
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid
                      strokeDasharray="3 3"
                      stroke="#374151"
                      opacity={0.3}
                    />
                    <XAxis
                      dataKey="time"
                      stroke="#9CA3AF"
                      fontSize={10}
                      tickLine={false}
                    />
                    <YAxis
                      stroke="#9CA3AF"
                      fontSize={11}
                      tickLine={false}
                      label={{
                        value: "%",
                        angle: -90,
                        position: "insideLeft",
                        fill: "#9CA3AF",
                      }}
                    />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: "rgba(31, 41, 55, 0.95)",
                        border: "1px solid rgba(75, 85, 99, 0.3)",
                        borderRadius: "12px",
                        color: "#fff",
                      }}
                    />
                    <Legend />
                    <Bar
                      dataKey="precipitation"
                      fill="#3B82F6"
                      radius={[8, 8, 0, 0]}
                      name="Precipitation Probability (%)"
                    />
                    <Bar
                      dataKey="humidity"
                      fill="#06B6D4"
                      radius={[8, 8, 0, 0]}
                      name="Humidity (%)"
                    />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* 5-Day Summary */}
      {dailySummary.length > 0 && (
        <Card className={dashboardTheme.card}>
          <CardHeader>
            <CardTitle className="text-white">5-Day Forecast Summary</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-700/30">
                    <th className="text-left py-3 px-4 text-white/80 font-medium">
                      Date
                    </th>
                    <th className="text-center py-3 px-4 text-white/80 font-medium">
                      Avg Temp
                    </th>
                    <th className="text-center py-3 px-4 text-white/80 font-medium">
                      Min/Max
                    </th>
                    <th className="text-center py-3 px-4 text-white/80 font-medium">
                      Humidity
                    </th>
                    <th className="text-center py-3 px-4 text-white/80 font-medium">
                      Max Wind
                    </th>
                    <th className="text-center py-3 px-4 text-white/80 font-medium">
                      Rain
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {dailySummary.map((day, idx) => (
                    <tr
                      key={idx}
                      className="border-b border-gray-800/30 hover:bg-gray-800/20"
                    >
                      <td className="py-3 px-4 text-white font-medium">
                        {day.date}
                      </td>
                      <td className="py-3 px-4 text-center text-white">
                        {day.avgTemp}°C
                      </td>
                      <td className="py-3 px-4 text-center text-white/70">
                        {day.minTemp}° / {day.maxTemp}°
                      </td>
                      <td className="py-3 px-4 text-center text-cyan-400">
                        {day.avgHumidity}%
                      </td>
                      <td className="py-3 px-4 text-center text-green-400">
                        {day.maxWind} km/h
                      </td>
                      <td className="py-3 px-4 text-center">
                        <Badge
                          className={
                            day.totalRain > 5
                              ? "bg-blue-400/20 text-blue-400"
                              : day.totalRain > 0
                                ? "bg-blue-400/10 text-blue-300"
                                : "bg-gray-400/10 text-gray-400"
                          }
                        >
                          {day.totalRain} mm
                        </Badge>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Empty State */}
      {weather.length === 0 && !loading && (
        <Card className={dashboardTheme.card}>
          <CardContent className="py-16">
            <div className="text-center">
              <CloudRain className="h-16 w-16 text-white/20 mx-auto mb-4" />
              <h3 className="text-xl font-semibold text-white mb-2">
                No Weather Data
              </h3>
              <p className="text-white/60 mb-6">
                Enter coordinates and click "Get Forecast" to load weather data
              </p>
              <div className="flex items-center justify-center gap-2 text-sm text-white/50">
                <MapPin className="h-4 w-4" />
                <span>Default Location: Nyagatare District, Rwanda</span>
              </div>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { ReactNode, useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import CustomScrollbar from "@/components/ui/CustomScrollbar";
import { 
  BarChart3,
  FileText,
  AlertTriangle,
  CheckCircle,
  Bell,
  Settings,
  LogOut,
  Menu,
  X,
  Home,
  User,
  Shield,
  Building2,
  ChevronLeft,
  ChevronRight
} from "lucide-react";

interface DashboardLayoutProps {
  children: ReactNode;
  userType: "farmer" | "assessor" | "insurer" | "admin" | "government";
  userId: string;
  userName: string;
  navigationItems: Array<{
    id: string;
    label: string;
    icon: any;
    badge?: number;
  }>;
  activePage: string;
  onPageChange: (page: string) => void;
  onLogout: () => void;
}

export default function DashboardLayout({
  children,
  userType,
  userId,
  userName,
  navigationItems,
  activePage,
  onPageChange,
  onLogout
}: DashboardLayoutProps) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(() => {
    // Load collapsed state from localStorage
    const saved = localStorage.getItem('sidebarCollapsed');
    return saved === 'true';
  });
  const navigate = useNavigate();

  // Remove dark mode - use light theme
  useEffect(() => {
    document.documentElement.classList.remove('dark');
  }, []);

  // Save collapsed state to localStorage
  useEffect(() => {
    localStorage.setItem('sidebarCollapsed', String(sidebarCollapsed));
  }, [sidebarCollapsed]);

  const toggleSidebar = () => {
    setSidebarCollapsed(!sidebarCollapsed);
    // Dispatch custom event for same-tab listeners
    window.dispatchEvent(new Event('sidebarToggle'));
  };

  const handleLogout = () => {
    // Clear any stored authentication data
    localStorage.removeItem('userToken');
    localStorage.removeItem('userType');
    localStorage.removeItem('userId');
    localStorage.removeItem('userName');
    
    // Call the custom logout handler if provided
    if (onLogout) {
      onLogout();
    }
    
    // Navigate back to role selection
    navigate('/role-selection');
  };

  const getUserIcon = () => {
    switch (userType) {
      case "farmer": return <User className="h-6 w-6" />;
      case "assessor": return <img src="/assessor.webp" alt="Assessor" className="h-6 w-6 object-contain" />;
      case "insurer": return <Building2 className="h-6 w-6" />;
      case "admin": return <Settings className="h-6 w-6" />;
      case "government": return <BarChart3 className="h-6 w-6" />;
      default: return <User className="h-6 w-6" />;
    }
  };

  const getUserColor = () => {
    switch (userType) {
      case "farmer": return "bg-[rgba(20,40,75,1)]";
      case "assessor": return "bg-orange-600";
      case "insurer": return "bg-blue-600";
      case "admin": return "bg-purple-600";
      case "government": return "bg-indigo-600";
      default: return "bg-gray-600";
    }
  };

  const getSidebarTheme = () => {
    // Use light theme for sidebar
    return "from-white to-gray-50 border-gray-200";
  };

  const getMainContentTheme = () => {
    // Always use dark theme like Chainex dashboard
    return "";
  };

  const getNavigationColors = (itemIndex?: number) => {
    // Use consistent green color for assessor active state
    if (userType === "assessor") {
      return {
        activeBg: "bg-green-600",
        activeText: "text-white",
        activeBorder: "border-0",
        activeIcon: "text-green-100",
        hover: "hover:bg-green-50 hover:text-green-700"
      };
    }
    // Use primary color for other user types
    return {
      activeBg: "bg-[rgba(20,40,75,0.1)]",
      activeText: "text-[rgba(15,30,56,1)]",
      activeBorder: "border-0",
      activeIcon: "text-[rgba(20,40,75,1)]",
      hover: "hover:text-[rgba(20,40,75,1)]"
    };
  };

  const getUserLabel = () => {
    switch (userType) {
      case "farmer": return "Farmer";
      case "assessor": return "Assessor";
      case "insurer": return "Insurer";
      case "admin": return "Admin";
      case "government": return "Government";
      default: return "User";
    }
  };

  return (
     <div className="dashboard-layout min-h-screen bg-gray-50 flex relative">
      
      {/* Mobile sidebar overlay */}
      {sidebarOpen && (
        <div 
          className="fixed inset-0 z-40 bg-black/10 backdrop-blur-sm lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-50 bg-gradient-to-br ${getSidebarTheme()} backdrop-blur-xl border-r transform transition-all duration-300 ease-in-out lg:translate-x-0 ${
        sidebarOpen ? 'translate-x-0' : '-translate-x-full'
      } ${sidebarCollapsed ? 'lg:w-20' : 'lg:w-64'} w-64`}>
        <div className="flex flex-col h-full">
          {/* Mobile Close Button & Desktop Toggle */}
          <div className={`flex items-center border-b border-gray-200 ${sidebarCollapsed ? 'justify-center p-4' : 'justify-between p-4'}`}>
            {!sidebarCollapsed && (
              <div className="flex-1 min-w-0 lg:block hidden">
                <div className="flex items-center space-x-3 p-3 rounded-xl">
                  {userType === "assessor" ? (
                    <img src="/assessor.webp" alt="Assessor" className="w-10 h-10 rounded-full object-cover flex-shrink-0" />
                  ) : (
                    <div className={`w-10 h-10 ${getUserColor()} rounded-full flex items-center justify-center flex-shrink-0 overflow-hidden`}>
                      <div className="text-white">
                        {getUserIcon()}
                      </div>
                    </div>
                  )}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-gray-900 truncate">{userName}</p>
                    <p className="text-xs text-gray-600 truncate">{getUserLabel()}</p>
                  </div>
                </div>
              </div>
            )}
            {sidebarCollapsed && (
              <div className="flex items-center justify-center gap-2 w-full lg:block hidden">
                {userType === "assessor" ? (
                  <img src="/assessor.webp" alt="Assessor" className="w-10 h-10 rounded-full object-cover" />
                ) : (
                  <div className={`w-10 h-10 ${getUserColor()} rounded-full flex items-center justify-center overflow-hidden`}>
                    <div className="text-white">
                      {getUserIcon()}
                    </div>
                  </div>
                )}
                {/* Desktop Toggle Button - Next to icon when collapsed */}
                <Button
                  variant="ghost"
                  size="sm"
                  className="hover:bg-gray-100 text-gray-700 p-1 h-auto"
                  onClick={toggleSidebar}
                  title="Expand sidebar"
                >
                  <ChevronRight className="h-4 w-4" />
                </Button>
              </div>
            )}
            {!sidebarCollapsed && (
              <div className="flex items-center gap-2 lg:block hidden">
                {/* Desktop Toggle Button - Right side when expanded */}
                <Button
                  variant="ghost"
                  size="sm"
                  className="hover:bg-gray-100 text-gray-700"
                  onClick={toggleSidebar}
                  title="Collapse sidebar"
                >
                  <ChevronLeft className="h-4 w-4" />
                </Button>
              </div>
            )}
            {/* Mobile Close Button */}
            <Button
              variant="ghost"
              size="sm"
              className="hover:bg-gray-100 text-gray-700 lg:hidden"
              onClick={() => setSidebarOpen(false)}
            >
              <X className="h-4 w-4" />
            </Button>
          </div>

          {/* User Info - Mobile Only */}
          <div className="p-4 border-b border-gray-200 lg:hidden">
            <div className="flex items-center space-x-3 p-3 rounded-xl">
              {userType === "assessor" ? (
                <img src="/assessor.webp" alt="Assessor" className="w-10 h-10 rounded-full object-cover" />
              ) : (
                <div className={`w-10 h-10 ${getUserColor()} rounded-full flex items-center justify-center overflow-hidden`}>
                  <div className="text-white">
                    {getUserIcon()}
                  </div>
                </div>
              )}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-gray-900 truncate">{userName}</p>
                <p className="text-xs text-gray-600 truncate">{getUserLabel()}</p>
              </div>
            </div>
          </div>


          {/* Navigation */}
          <nav 
            className="flex-1 p-4 space-y-2 overflow-y-auto overflow-x-hidden [&::-webkit-scrollbar]:hidden [-ms-overflow-style:none] [scrollbar-width:none]"
          >
            <div className="h-full">
            {navigationItems.map((item, index) => {
              const Icon = item.icon;
              const isActive = activePage === item.id;
              const colors = getNavigationColors(index);
              
              return (
                <button
                  key={item.id}
                  onClick={() => {
                    onPageChange(item.id);
                    setSidebarOpen(false);
                  }}
                  className={`w-full flex items-center ${sidebarCollapsed ? 'justify-center px-2' : 'justify-between px-4'} py-4 text-sm font-medium transition-all duration-300 ease-in-out group relative ${
                    isActive
                      ? `${colors.activeBg} ${colors.activeText} shadow-sm ${colors.activeBorder}`
                      : `text-gray-700 ${colors.hover}`
                  }`}
                  title={sidebarCollapsed ? item.label : undefined}
                >
                  {sidebarCollapsed ? (
                    // Collapsed: Only icon
                    <div className="flex items-center justify-center relative">
                      <Icon className={`h-5 w-5 ${isActive ? colors.activeIcon : 'text-gray-600'}`} />
                      {item.badge && item.badge > 0 && (
                        <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white"></span>
                      )}
                    </div>
                  ) : (
                    // Expanded: Icon + label + badge
                    <>
                      <div className="flex items-center space-x-3">
                        <Icon className={`h-5 w-5 flex-shrink-0 ${isActive ? colors.activeIcon : 'text-gray-600'}`} />
                        <span>{item.label}</span>
                      </div>
                      {item.badge && item.badge > 0 && (
                        <Badge variant="secondary" className={`text-xs ${
                          isActive 
                            ? `${colors.activeBg} text-white`
                            : 'bg-[rgba(20,40,75,0.15)] text-[rgba(15,30,56,1)]'
                        }`}>
                          {item.badge}
                        </Badge>
                      )}
                    </>
                  )}
                </button>
              );
            })}
            </div>
          </nav>

          {/* Sidebar Footer */}
          <div className="p-4 border-t border-gray-200">
            <div className="flex items-center justify-center">
              {/* Logout Button */}
              <AlertDialog>
                <AlertDialogTrigger asChild>
                  <Button
                    variant="ghost"
                    className={`w-full ${sidebarCollapsed ? 'justify-center px-2' : 'justify-center'} hover:text-red-600 transition-all duration-300 text-gray-700`}
                    title={sidebarCollapsed ? "Logout" : undefined}
                  >
                    <LogOut className="h-4 w-4 flex-shrink-0" />
                    {!sidebarCollapsed && <span className="ml-2">Logout</span>}
                  </Button>
                </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Confirm Logout</AlertDialogTitle>
                  <AlertDialogDescription>
                    Are you sure you want to logout? You will be redirected to the role selection page.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleLogout}
                    className="bg-red-600 hover:bg-red-700"
                  >
                    Logout
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className={`flex-1 flex flex-col min-w-0 bg-gray-50 transition-all duration-300 ${
        sidebarCollapsed ? 'lg:ml-20' : 'lg:ml-64'
      }`}>
        {/* Mobile Menu Button */}
        <div className="lg:hidden fixed top-4 left-4 z-40">
          <Button
            variant="ghost"
            size="sm"
            className="bg-white backdrop-blur-sm hover:bg-gray-100 shadow-lg rounded-2xl border border-gray-200"
            onClick={() => setSidebarOpen(true)}
          >
            <Menu className="h-5 w-5 text-gray-700" />
          </Button>
        </div>

         {/* Page Content */}
         <main className="flex-1 overflow-auto bg-gray-50">
           <CustomScrollbar className="h-full">
             {children}
           </CustomScrollbar>
         </main>
      </div>
    </div>
  );
}

