        "Coordinate with local extension services"
      ],
      issuedAt: "2024-03-14T08:30:00Z",
      expiresAt: "2024-03-21T08:30:00Z",
      status: "active"
    }
  ];

  const notificationTemplates = [
    {
      id: "template_001",
      name: "Claim Approval",
      type: "claim_update",
      title: "Claim Approved - {claimId}",
      message: "Your claim {claimId} has been approved for RWF {amount}. Payment will be processed within 3-5 business days.",
      channels: ["sms", "email"]
    },
    {
      id: "template_002",
      name: "Payment Reminder",
      type: "payment_reminder",
      title: "Premium Payment Due",
      message: "Your insurance premium of RWF {amount} is due on {dueDate}. Pay via USSD *1828# or mobile app.",
      channels: ["sms", "whatsapp"]
    },
    {
      id: "template_003",
      name: "Disaster Alert",
      type: "disaster_alert",
      title: "Weather Alert - {region}",
      message: "{disasterType} warning for {region}. {affectedCount} farms may be affected. Take necessary precautions.",
      channels: ["sms", "whatsapp", "push"]
    },
    {
      id: "template_004",
      name: "Assessment Schedule",
      type: "assessment_schedule",
      title: "Field Assessment Scheduled",
      message: "Your field assessment is scheduled for {date} at {time}. Please ensure access to your farm.",
      channels: ["sms", "email"]
    }
  ];

  const userConfig: NotificationConfig = {
    id: "config_001",
    userId,
    userType,
    channels: {
      sms: true,
      email: true,
      whatsapp: true,
      push: true
    },
    preferences: {
      claimUpdates: true,
      paymentReminders: true,
      disasterAlerts: true,
      policyRenewals: true,
      assessmentSchedules: true
    },
    language: "en",
    timezone: "Africa/Kigali"
  };

  const handleChannelToggle = (channel: 'sms' | 'email' | 'whatsapp' | 'push', enabled: boolean) => {
    if (enabled) {
      setComposeNotification(prev => ({
        ...prev,
        channels: [...(prev.channels || []), channel]
      }));
    } else {
      setComposeNotification(prev => ({
        ...prev,
        channels: (prev.channels || []).filter(c => c !== channel)
      }));
    }
  };

  const handleTemplateSelect = (templateId: string) => {
    const template = notificationTemplates.find(t => t.id === templateId);
    if (template) {
      setComposeNotification(prev => ({
        ...prev,
        type: template.type as any,
        title: template.title,
        message: template.message,
        channels: template.channels as any[]
      }));
    }
  };

  const sendNotification = () => {
    // In real implementation, this would call the API
    console.log("Sending notification:", composeNotification);
    // Reset form
    setComposeNotification({
      type: 'claim_update',
      priority: 'medium',
      channels: ['sms'],
      recipients: [],
      message: '',
      title: ''
    });
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'critical': return 'bg-red-600';
      case 'high': return 'bg-orange-600';
      case 'medium': return 'bg-yellow-600';
      case 'low': return 'bg-green-600';
      default: return 'bg-gray-600';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'delivered': return 'text-green-600';
      case 'sent': return 'text-blue-600';
      case 'pending': return 'text-yellow-600';
      case 'failed': return 'text-red-600';
      default: return 'text-gray-600';
    }
  };

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'critical': return 'bg-red-600';
      case 'high': return 'bg-orange-600';
      case 'medium': return 'bg-yellow-600';
      case 'low': return 'bg-green-600';
      default: return 'bg-gray-600';
    }
  };

  const renderCompose = () => (
    <div className="space-y-6">
      {/* Template Selection */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Plus className="h-5 w-5" />
            <span>Quick Templates</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {notificationTemplates.map((template) => (
              <div
                key={template.id}
                className={`p-4 border rounded-lg cursor-pointer transition-all ${
                  selectedTemplate === template.id ? 'border-blue-500 bg-blue-50' : 'hover:shadow-md'
                }`}
                onClick={() => {
                  setSelectedTemplate(template.id);
                  handleTemplateSelect(template.id);
                }}
              >
                <h3 className="font-semibold">{template.name}</h3>
                <p className="text-sm text-white/80 mt-1">{template.title}</p>
                <div className="flex space-x-2 mt-2">
                  {template.channels.map((channel) => (
                    <Badge key={channel} variant="outline" className="text-xs">
                      {channel.toUpperCase()}
                    </Badge>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Notification Composer */}
      <Card>
        <CardHeader>
          <CardTitle>Compose Notification</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="notificationType">Notification Type</Label>
              <Select
                value={composeNotification.type || ''}
                onValueChange={(value) => setComposeNotification(prev => ({ ...prev, type: value as any }))}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="claim_update">Claim Update</SelectItem>
                  <SelectItem value="payment_reminder">Payment Reminder</SelectItem>
                  <SelectItem value="disaster_alert">Disaster Alert</SelectItem>
                  <SelectItem value="policy_renewal">Policy Renewal</SelectItem>
                  <SelectItem value="assessment_schedule">Assessment Schedule</SelectItem>
                  <SelectItem value="system_alert">System Alert</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="priority">Priority</Label>
              <Select
                value={composeNotification.priority || 'medium'}
                onValueChange={(value) => setComposeNotification(prev => ({ ...prev, priority: value as any }))}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select priority" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="low">Low</SelectItem>
                  <SelectItem value="medium">Medium</SelectItem>
                  <SelectItem value="high">High</SelectItem>
                  <SelectItem value="critical">Critical</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="title">Title</Label>
            <Input
              id="title"
              placeholder="Enter notification title"
              value={composeNotification.title || ''}
              onChange={(e) => setComposeNotification(prev => ({ ...prev, title: e.target.value }))}
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="message">Message</Label>
            <Textarea
              id="message"
              placeholder="Enter notification message"
              value={composeNotification.message || ''}
              onChange={(e) => setComposeNotification(prev => ({ ...prev, message: e.target.value }))}
              rows={4}
            />
            <p className="text-sm text-white/70">
              SMS limit: 160 characters | Current: {(composeNotification.message || '').length}
            </p>
          </div>

          <div className="space-y-4">
            <Label>Delivery Channels</Label>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="flex items-center space-x-2">
                <Switch
                  checked={composeNotification.channels?.includes('sms') || false}
                  onCheckedChange={(checked) => handleChannelToggle('sms', checked)}
                />
                <Label className="flex items-center space-x-1">
                  <Phone className="h-4 w-4" />
                  <span>SMS</span>
                </Label>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  checked={composeNotification.channels?.includes('email') || false}
                  onCheckedChange={(checked) => handleChannelToggle('email', checked)}
                />
                <Label className="flex items-center space-x-1">
                  <Mail className="h-4 w-4" />
                  <span>Email</span>
                </Label>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  checked={composeNotification.channels?.includes('whatsapp') || false}
                  onCheckedChange={(checked) => handleChannelToggle('whatsapp', checked)}
                />
                <Label className="flex items-center space-x-1">
                  <MessageSquare className="h-4 w-4" />
                  <span>WhatsApp</span>
                </Label>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  checked={composeNotification.channels?.includes('push') || false}
                  onCheckedChange={(checked) => handleChannelToggle('push', checked)}
                />
                <Label className="flex items-center space-x-1">
                  <Bell className="h-4 w-4" />
                  <span>Push</span>
                </Label>
              </div>
            </div>
          </div>

          <div className="flex justify-end space-x-2">
            <Button variant="outline">Save Draft</Button>
            <Button onClick={sendNotification} className="bg-blue-600 hover:bg-blue-700">
              <Send className="h-4 w-4 mr-2" />
              Send Notification
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const renderNotifications = () => (
    <div className="space-y-4">
      {notifications.map((notification) => (
        <Card key={notification.id}>
          <CardContent className="p-6">
            <div className="flex items-start justify-between">
              <div className="flex-1">
                <div className="flex items-center space-x-3 mb-2">
                  <h3 className="font-semibold">{notification.title}</h3>
                  <Badge className={getPriorityColor(notification.priority)}>
                    {notification.priority.toUpperCase()}
                  </Badge>
                  <Badge variant="outline" className={getStatusColor(notification.status)}>
                    {notification.status.toUpperCase()}
                  </Badge>
                </div>
                
                <p className="text-white/80 mb-3">{notification.message}</p>
                
                <div className="flex items-center space-x-4 text-sm text-white/60">
                  <div className="flex items-center space-x-1">
                    <Calendar className="h-4 w-4" />
                    <span>
                      {notification.sentAt 
                        ? new Date(notification.sentAt).toLocaleString()
                        : new Date(notification.createdAt).toLocaleString()
                      }
                    </span>
                  </div>
                  <div className="flex items-center space-x-1">
                    <Users className="h-4 w-4" />
                    <span>{notification.recipients.length} recipients</span>
                  </div>
                  <div className="flex space-x-1">
                    {notification.channels.map((channel) => (
                      <Badge key={channel} variant="outline" className="text-xs">
                        {channel.toUpperCase()}
                      </Badge>
                    ))}
                  </div>
                </div>

                {/* Delivery Status */}
                <div className="mt-3 grid grid-cols-2 md:grid-cols-4 gap-2">
                  {Object.entries(notification.deliveryStatus).map(([channel, status]) => (
                    <div key={channel} className="flex items-center space-x-2 text-xs">
                      <div className={`w-2 h-2 rounded-full ${
                        status === 'delivered' ? 'bg-green-500' :
                        status === 'pending' ? 'bg-yellow-500' : 'bg-red-500'
                      }`} />
                      <span className="capitalize">{channel}: {status}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div className="flex space-x-2 ml-4">
                <Button size="sm" variant="outline">
                  <Eye className="h-4 w-4" />
                </Button>
                <Button size="sm" variant="outline">
                  <Edit className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  const renderDisasterAlerts = () => (
    <div className="space-y-4">
      {disasterAlerts.map((alert) => (
        <Card key={alert.id} className={`border-l-4 ${
          alert.severity === 'critical' ? 'border-red-500' :
          alert.severity === 'high' ? 'border-orange-500' :
          alert.severity === 'medium' ? 'border-yellow-500' : 'border-green-500'
        }`}>
          <CardHeader>
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <AlertTriangle className={`h-6 w-6 ${
                  alert.severity === 'critical' ? 'text-red-600' :
                  alert.severity === 'high' ? 'text-orange-600' :
                  alert.severity === 'medium' ? 'text-yellow-600' : 'text-green-600'
                }`} />
                <div>
                  <CardTitle className="text-lg">
                    {alert.type.replace('_', ' ').toUpperCase()} Alert
                  </CardTitle>
                  <p className="text-sm text-white/80">
                    {alert.affectedRegions.join(', ')}
                  </p>
                </div>
              </div>
              <Badge className={getSeverityColor(alert.severity)}>
                {alert.severity.toUpperCase()}
              </Badge>
            </div>
          </CardHeader>
          <CardContent>
            <p className="text-white/80 mb-4">{alert.alertMessage}</p>
            
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
              <div className="text-center p-3 bg-red-50 rounded-lg">
                <div className="text-2xl font-bold text-red-600">{alert.affectedFarmers}</div>
                <div className="text-sm text-gray-600">Affected Farmers</div>
              </div>
              <div className="text-center p-3 bg-orange-50 rounded-lg">
                <div className="text-2xl font-bold text-orange-600">
                  RWF {(alert.estimatedLoss / 1000000).toFixed(0)}M
                </div>
                <div className="text-sm text-gray-600">Estimated Loss</div>
              </div>
              <div className="text-center p-3 bg-blue-50 rounded-lg">
                <div className="text-2xl font-bold text-blue-600">
                  {new Date(alert.expiresAt).toLocaleDateString()}
                </div>
                <div className="text-sm text-gray-600">Expires</div>
              </div>
            </div>

            <div>
              <Label className="text-sm font-medium text-gray-700">Recommendations</Label>
              <ul className="mt-2 space-y-1">
                {alert.recommendations.map((recommendation, index) => (
                  <li key={index} className="flex items-center space-x-2 text-sm">
                    <CheckCircle className="h-3 w-3 text-green-500 flex-shrink-0" />
                    <span>{recommendation}</span>
                  </li>
                ))}
              </ul>
            </div>

            <div className="flex justify-end space-x-2 mt-4">
              <Button variant="outline" size="sm">
                <Eye className="h-4 w-4 mr-2" />
                View Details
              </Button>
              <Button size="sm" className="bg-red-600 hover:bg-red-700">
                <Send className="h-4 w-4 mr-2" />
                Send Alert
              </Button>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  const renderSettings = () => (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Settings className="h-5 w-5" />
            <span>Notification Preferences</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div>
            <Label className="text-lg font-semibold">Delivery Channels</Label>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-3">
              {Object.entries(userConfig.channels).map(([channel, enabled]) => (
                <div key={channel} className="flex items-center space-x-2">
                  <Switch checked={enabled} />
                  <Label className="capitalize">{channel}</Label>
                </div>
              ))}
            </div>
          </div>

          <div>
            <Label className="text-lg font-semibold">Notification Types</Label>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-3">
              {Object.entries(userConfig.preferences).map(([preference, enabled]) => (
                <div key={preference} className="flex items-center space-x-2">
                  <Switch checked={enabled} />
                  <Label className="capitalize">{preference.replace(/([A-Z])/g, ' $1').trim()}</Label>
                </div>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Language</Label>
              <Select defaultValue={userConfig.language}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="en">English</SelectItem>
                  <SelectItem value="rw">Kinyarwanda</SelectItem>
                  <SelectItem value="fr">French</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Timezone</Label>
              <Select defaultValue={userConfig.timezone}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Africa/Kigali">Africa/Kigali (GMT+2)</SelectItem>
                  <SelectItem value="UTC">UTC (GMT+0)</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          <Button className="w-full">
            <Settings className="h-4 w-4 mr-2" />
            Save Preferences
          </Button>
        </CardContent>
      </Card>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto p-6">
      <div className="mb-6">
        <h1 className="text-3xl font-bold">Notification Manager</h1>
        <p className="text-gray-600">Manage SMS, WhatsApp, Email, and Push notifications</p>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="compose">Compose</TabsTrigger>
          <TabsTrigger value="notifications">Notifications</TabsTrigger>
          <TabsTrigger value="alerts">Disaster Alerts</TabsTrigger>
          <TabsTrigger value="settings">Settings</TabsTrigger>
        </TabsList>

        <TabsContent value="compose" className="mt-6">
          {renderCompose()}
        </TabsContent>

        <TabsContent value="notifications" className="mt-6">
          {renderNotifications()}
        </TabsContent>

        <TabsContent value="alerts" className="mt-6">
          {renderDisasterAlerts()}
        </TabsContent>

        <TabsContent value="settings" className="mt-6">
          {renderSettings()}
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Progress } from "@/components/ui/progress";
import { 
  CreditCard, 
  Smartphone, 
  DollarSign, 
  Clock, 
  CheckCircle, 
  XCircle, 
  AlertTriangle, 
  Phone, 
  Wifi, 
  WifiOff, 
  Eye, 
  EyeOff, 
  RefreshCw, 
  Download, 
  History, 
  Shield, 
  Banknote, 
  Receipt, 
  QrCode, 
  MessageSquare, 
  Globe,
  Zap,
  Star
} from "lucide-react";
import { PaymentTransaction } from "@/types/enhanced-api";

interface PaymentIntegrationProps {
  farmerId: string;
  policyId?: string;
  claimId?: string;
  amount: number;
  currency: 'RWF' | 'USD';
  onPaymentSuccess: (transaction: PaymentTransaction) => void;
  onPaymentFailure: (error: string) => void;
}

interface USSDMenu {
  level: number;
  options: string[];
  currentInput: string;
  response: string;
}

export function PaymentIntegration({ 
  farmerId, 
  policyId, 
  claimId, 
  amount, 
  currency, 
  onPaymentSuccess, 
  onPaymentFailure 
}: PaymentIntegrationProps) {
  const [selectedMethod, setSelectedMethod] = useState<'mobile_money' | 'ussd' | 'bank_transfer' | 'card'>('mobile_money');
  const [selectedProvider, setSelectedProvider] = useState<'mtn' | 'airtel' | 'equity' | 'bk'>('mtn');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [ussdMenu, setUssdMenu] = useState<USSDMenu>({
    level: 0,
    options: [],
    currentInput: '',
    response: ''
  });

  // Mock data - in real implementation, this would come from API
  const paymentMethods = [
    {
      id: 'mobile_money',
      name: 'Mobile Money',
      icon: Smartphone,
      providers: [
        { id: 'mtn', name: 'MTN Mobile Money', color: 'bg-yellow-600', ussd: '*182*8#' },
        { id: 'airtel', name: 'Airtel Money', color: 'bg-red-600', ussd: '*182*7#' },
        { id: 'equity', name: 'Equity Mobile', color: 'bg-blue-600', ussd: '*247#' },
        { id: 'bk', name: 'BK Mobile', color: 'bg-green-600', ussd: '*182*6#' }
      ],
      description: 'Pay instantly using your mobile money account'
    },
    {
      id: 'ussd',
      name: 'USSD Code',
      icon: Phone,
      providers: [
        { id: 'mtn', name: 'MTN (*182*8#)', color: 'bg-yellow-600', ussd: '*182*8#' },
        { id: 'airtel', name: 'Airtel (*182*7#)', color: 'bg-red-600', ussd: '*182*7#' }
      ],
      description: 'Dial USSD code on your phone to make payment'
    },
    {
      id: 'bank_transfer',
      name: 'Bank Transfer',
      icon: Banknote,
      providers: [
        { id: 'equity', name: 'Equity Bank', color: 'bg-blue-600', ussd: '' },
        { id: 'bk', name: 'Bank of Kigali', color: 'bg-green-600', ussd: '' }
      ],
      description: 'Transfer directly from your bank account'
    },
    {
      id: 'card',
      name: 'Card Payment',
      icon: CreditCard,
      providers: [
        { id: 'visa', name: 'Visa/Mastercard', color: 'bg-blue-600', ussd: '' }
      ],
      description: 'Pay using your credit or debit card'
    }
  ];

  const recentTransactions: PaymentTransaction[] = [
    {
      id: "txn_001",
      farmerId: farmerId,
      policyId: "policy_001",
      transactionType: "premium_payment",
      amount: 120000,
      currency: "RWF",
      paymentMethod: "mobile_money",
      paymentProvider: "mtn",
      status: "completed",
      transactionId: "MTN123456789",
      reference: "POL001_PREM_2024",
      initiatedDate: "2024-03-15T10:30:00Z",
      completedDate: "2024-03-15T10:32:00Z"
    },
    {
      id: "txn_002",
      farmerId: farmerId,
      claimId: "claim_001",
      transactionType: "claim_payout",
      amount: 500000,
      currency: "RWF",
      paymentMethod: "mobile_money",
      paymentProvider: "airtel",
      status: "completed",
      transactionId: "ATL987654321",
      reference: "CLM001_PAYOUT_2024",
      initiatedDate: "2024-03-14T14:20:00Z",
      completedDate: "2024-03-14T14:22:00Z"
    }
  ];

  const handleMobileMoneyPayment = async () => {
    if (!phoneNumber) {
      onPaymentFailure('Phone number is required');
      return;
    }

    setIsProcessing(true);

    // Simulate payment processing
    await new Promise(resolve => setTimeout(resolve, 3000));

    const transaction: PaymentTransaction = {
      id: `txn_${Date.now()}`,
      farmerId,
      policyId,
      claimId,
      transactionType: policyId ? 'premium_payment' : 'claim_payout',
      amount,
      currency,
      paymentMethod: 'mobile_money',
      paymentProvider: selectedProvider,
      status: 'completed',
      transactionId: `${selectedProvider.toUpperCase()}${Date.now()}`,
      reference: `${policyId || claimId}_${Date.now()}`,
      initiatedDate: new Date().toISOString(),
      completedDate: new Date().toISOString()
    };

    setIsProcessing(false);
    onPaymentSuccess(transaction);
  };

  const handleUSSDNavigation = (input: string) => {
    const newInput = ussdMenu.currentInput + input;
    const newLevel = ussdMenu.level + 1;

    let response = '';
    let options: string[] = [];

    switch (newLevel) {
      case 1:
        response = 'Welcome to Agricultural Insurance Payment\n1. Pay Premium\n2. Claim Payout\n3. Check Balance\n4. Exit';
        options = ['1', '2', '3', '4'];
        break;
      case 2:
        if (newInput.includes('1')) {
          response = 'Premium Payment\nEnter Amount: RWF ' + amount.toLocaleString() + '\n1. Confirm\n2. Cancel';
          options = ['1', '2'];
        } else if (newInput.includes('2')) {
          response = 'Claim Payout\nAmount: RWF ' + amount.toLocaleString() + '\n1. Confirm\n2. Cancel';
          options = ['1', '2'];
        }
        break;
      case 3:
        if (newInput.includes('1')) {
          response = 'Payment Successful!\nAmount: RWF ' + amount.toLocaleString() + '\nTransaction ID: ' + selectedProvider.toUpperCase() + Date.now() + '\nThank you!';
          // Complete payment
          setTimeout(() => {
            const transaction: PaymentTransaction = {
              id: `txn_${Date.now()}`,
              farmerId,
              policyId,
              claimId,
              transactionType: policyId ? 'premium_payment' : 'claim_payout',
              amount,
              currency,
              paymentMethod: 'ussd',
              paymentProvider: selectedProvider,
              status: 'completed',
              transactionId: `${selectedProvider.toUpperCase()}${Date.now()}`,
              reference: `${policyId || claimId}_${Date.now()}`,
              initiatedDate: new Date().toISOString(),
              completedDate: new Date().toISOString()
            };
            onPaymentSuccess(transaction);
          }, 2000);
        }
        break;
    }

    setUssdMenu({
      level: newLevel,
      options,
      currentInput: newInput,
      response
    });
  };

  const renderMobileMoneyPayment = () => (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Smartphone className="h-5 w-5" />
            <span>Mobile Money Payment</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Provider Selection */}
          <div className="space-y-4">
            <Label>Select Mobile Money Provider</Label>
            <div className="grid grid-cols-2 gap-4">
              {paymentMethods.find(m => m.id === 'mobile_money')?.providers.map((provider) => (
                <div
                  key={provider.id}
                  className={`p-4 border rounded-lg cursor-pointer transition-all ${
                    selectedProvider === provider.id ? 'border-blue-500 bg-blue-50' : 'hover:shadow-md'
                  }`}
                  onClick={() => setSelectedProvider(provider.id as any)}
                >
                  <div className="flex items-center space-x-3">
                    <div className={`w-8 h-8 rounded-full ${provider.color} flex items-center justify-center`}>
                      <span className="text-white font-bold text-sm">
                        {provider.name.charAt(0)}
                      </span>
                    </div>
                    <div>
                      <p className="font-medium">{provider.name}</p>
                      <p className="text-sm text-gray-600">USSD: {provider.ussd}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Phone Number */}
          <div className="space-y-2">
            <Label htmlFor="phoneNumber">Phone Number</Label>
            <Input
              id="phoneNumber"
              placeholder="+250 XXX XXX XXX"
              value={phoneNumber}
              onChange={(e) => setPhoneNumber(e.target.value)}
            />
            <p className="text-sm text-gray-500">
              Enter the phone number linked to your {paymentMethods.find(m => m.id === 'mobile_money')?.providers.find(p => p.id === selectedProvider)?.name} account
            </p>
          </div>

          {/* Payment Summary */}
          <Card className="bg-blue-50">
            <CardContent className="p-4">
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-gray-600">Amount:</span>
                  <span className="font-semibold">{currency} {amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Provider:</span>
                  <span className="font-medium">
                    {paymentMethods.find(m => m.id === 'mobile_money')?.providers.find(p => p.id === selectedProvider)?.name}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Phone:</span>
                  <span className="font-medium">{phoneNumber || 'Not provided'}</span>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Payment Button */}
          <Button
            onClick={handleMobileMoneyPayment}
            disabled={!phoneNumber || isProcessing}
            className="w-full bg-green-600 hover:bg-green-700"
          >
            {isProcessing ? (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2" />
                Processing Payment...
              </>
            ) : (
              <>
                <DollarSign className="h-4 w-4 mr-2" />
                Pay {currency} {amount.toLocaleString()}
              </>
            )}
          </Button>

          {/* Security Notice */}
          <div className="flex items-start space-x-3 p-3 bg-green-50 rounded-lg">
            <Shield className="h-5 w-5 text-green-600 mt-0.5 flex-shrink-0" />
            <div>
              <h4 className="font-medium text-green-900">Secure Payment</h4>
              <p className="text-sm text-green-700 mt-1">
                Your payment is processed securely through {paymentMethods.find(m => m.id === 'mobile_money')?.providers.find(p => p.id === selectedProvider)?.name}. 
                We never store your payment credentials.
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const renderUSSDPayment = () => (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Phone className="h-5 w-5" />
            <span>USSD Payment</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* USSD Instructions */}
          <div className="space-y-4">
            <Label>USSD Payment Instructions</Label>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="space-y-3">
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-bold">1</div>
                  <div>
                    <p className="font-medium">Dial USSD Code</p>
                    <p className="text-sm text-gray-600">
                      {paymentMethods.find(m => m.id === 'ussd')?.providers.find(p => p.id === selectedProvider)?.ussd}
                    </p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-bold">2</div>
                  <div>
                    <p className="font-medium">Follow Menu Options</p>
                    <p className="text-sm text-gray-600">Select Agricultural Insurance and follow prompts</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-bold">3</div>
                  <div>
                    <p className="font-medium">Enter Amount</p>
                    <p className="text-sm text-gray-600">Amount: {currency} {amount.toLocaleString()}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-bold">4</div>
                  <div>
                    <p className="font-medium">Confirm Payment</p>
                    <p className="text-sm text-gray-600">Enter your PIN to complete transaction</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Provider Selection */}
          <div className="space-y-4">
            <Label>Select Provider</Label>
            <div className="grid grid-cols-1 gap-4">
              {paymentMethods.find(m => m.id === 'ussd')?.providers.map((provider) => (
                <div
                  key={provider.id}
                  className={`p-4 border rounded-lg cursor-pointer transition-all ${
                    selectedProvider === provider.id ? 'border-blue-500 bg-blue-50' : 'hover:shadow-md'
                  }`}
                  onClick={() => setSelectedProvider(provider.id as any)}
                >
                  <div className="flex items-center space-x-3">
                    <div className={`w-8 h-8 rounded-full ${provider.color} flex items-center justify-center`}>
                      <span className="text-white font-bold text-sm">
                        {provider.name.charAt(0)}
                      </span>
                    </div>
                    <div>
                      <p className="font-medium">{provider.name}</p>
                      <p className="text-sm text-gray-600">USSD Code: {provider.ussd}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* USSD Simulator */}
          <Card className="bg-black text-green-400">
            <CardHeader>
              <CardTitle className="text-green-400">USSD Simulator</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="font-mono text-sm whitespace-pre-line min-h-[200px] p-4 bg-gray-900 rounded">
                {ussdMenu.response || 'Dial the USSD code to start payment process...'}
              </div>

              {ussdMenu.options.length > 0 && (
                <div className="grid grid-cols-2 gap-2">
                  {ussdMenu.options.map((option) => (
                    <Button
                      key={option}
                      variant="outline"
                      className="bg-gray-800 text-green-400 border-green-400 hover:bg-gray-700"
                      onClick={() => handleUSSDNavigation(option)}
                    >
                      {option}
                    </Button>
                  ))}
                </div>
              )}

              <div className="flex space-x-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setUssdMenu({
                    level: 0,
                    options: [],
                    currentInput: '',
                    response: 'Dial the USSD code to start payment process...'
                  })}
                  className="bg-gray-800 text-green-400 border-green-400 hover:bg-gray-700"
                >
                  Reset
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Payment Summary */}
          <Card className="bg-blue-50">
            <CardContent className="p-4">
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-gray-600">Amount:</span>
                  <span className="font-semibold">{currency} {amount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">USSD Code:</span>
                  <span className="font-medium">
                    {paymentMethods.find(m => m.id === 'ussd')?.providers.find(p => p.id === selectedProvider)?.ussd}
                  </span>
                </div>
              </div>
            </CardContent>
          </Card>
        </CardContent>
      </Card>
    </div>
  );

  const renderTransactionHistory = () => (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold">Recent Transactions</h3>
        <Button variant="outline" size="sm">
          <Download className="h-4 w-4 mr-2" />
          Export
        </Button>
      </div>

      {recentTransactions.map((transaction) => (
        <Card key={transaction.id}>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  transaction.status === 'completed' ? 'bg-green-100' :
                  transaction.status === 'pending' ? 'bg-yellow-100' : 'bg-red-100'
                }`}>
                  {transaction.status === 'completed' ? (
                    <CheckCircle className="h-5 w-5 text-green-600" />
                  ) : transaction.status === 'pending' ? (
                    <Clock className="h-5 w-5 text-yellow-600" />
                  ) : (
                    <XCircle className="h-5 w-5 text-red-600" />
                  )}
                </div>
                <div>
                  <p className="font-medium">
                    {transaction.transactionType === 'premium_payment' ? 'Premium Payment' : 'Claim Payout'}
                  </p>
                  <p className="text-sm text-gray-600">
                    {new Date(transaction.completedDate || transaction.initiatedDate).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <div className="text-right">
                <p className="font-semibold">{transaction.currency} {transaction.amount.toLocaleString()}</p>
                <div className="flex items-center space-x-2">
                  <Badge variant={
                    transaction.status === 'completed' ? 'default' :
                    transaction.status === 'pending' ? 'secondary' : 'destructive'
                  }>
                    {transaction.status.toUpperCase()}
                  </Badge>
                  <Badge variant="outline" className="text-xs">
                    {transaction.paymentProvider.toUpperCase()}
                  </Badge>
                </div>
              </div>
            </div>
            
            <div className="mt-3 pt-3 border-t text-sm text-gray-600">
              <div className="flex justify-between">
                <span>Transaction ID:</span>
                <span className="font-mono">{transaction.transactionId}</span>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto p-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl text-center">Payment Gateway</CardTitle>
          <p className="text-center text-gray-600">
            Secure payment processing for agricultural insurance
          </p>
        </CardHeader>
        <CardContent>
          <Tabs defaultValue={selectedMethod} onValueChange={(value) => setSelectedMethod(value as any)}>
            <TabsList className="grid w-full grid-cols-4">
              <TabsTrigger value="mobile_money">Mobile Money</TabsTrigger>
              <TabsTrigger value="ussd">USSD</TabsTrigger>
              <TabsTrigger value="bank_transfer">Bank Transfer</TabsTrigger>
              <TabsTrigger value="card">Card</TabsTrigger>
            </TabsList>

            <TabsContent value="mobile_money" className="mt-6">
              {renderMobileMoneyPayment()}
            </TabsContent>

            <TabsContent value="ussd" className="mt-6">
              {renderUSSDPayment()}
            </TabsContent>

            <TabsContent value="bank_transfer" className="mt-6">
              <Card>
                <CardContent className="p-6 text-center">
                  <Banknote className="h-12 w-12 mx-auto text-blue-600 mb-4" />
                  <h3 className="text-lg font-semibold mb-2">Bank Transfer</h3>
                  <p className="text-gray-600 mb-4">Direct bank transfer option coming soon</p>
                  <Button variant="outline" disabled>
                    Coming Soon
                  </Button>
                </CardContent>
              </Card>
            </TabsContent>

            <TabsContent value="card" className="mt-6">
              <Card>
                <CardContent className="p-6 text-center">
                  <CreditCard className="h-12 w-12 mx-auto text-blue-600 mb-4" />
                  <h3 className="text-lg font-semibold mb-2">Card Payment</h3>
                  <p className="text-gray-600 mb-4">Credit/Debit card payment option coming soon</p>
                  <Button variant="outline" disabled>
                    Coming Soon
                  </Button>
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>

          {/* Transaction History */}
          <div className="mt-8">
            {renderTransactionHistory()}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { 
  Shield, 
  Settings, 
  Calculator, 
  CheckCircle, 
  AlertTriangle, 
  DollarSign, 
  Calendar, 
  Crop, 
  MapPin,
  TrendingUp,
  Database,
  Zap
} from "lucide-react";

interface PolicyRule {
  id: string;
  name: string;
  description: string;
  conditions: {
    cropType: string[];
    riskLevel: string[];
    farmSize: {
      min: number;
      max: number;
    };
    location: string[];
  };
  calculations: {
    coverageRate: number; // RWF per hectare
    premiumRate: number; // Percentage of coverage
    duration: number; // Days
    deductible: number; // Percentage
  };
  status: 'active' | 'inactive';
}

interface PolicyTemplate {
  id: string;
  name: string;
  cropType: string;
  baseCoverageRate: number;
  basePremiumRate: number;
  standardDuration: number;
  description: string;
}

interface PolicyCreationEngineProps {
  assessmentId: string;
  farmerId: string;
  cropType: string;
  farmSize: number;
  riskLevel: 'low' | 'medium' | 'high';
  location: string;
  onPolicyCreated: (policy: any) => void;
  onCancel: () => void;
}

export function PolicyCreationEngine({ 
  assessmentId, 
  farmerId, 
  cropType, 
  farmSize, 
  riskLevel, 
  location,
  onPolicyCreated,
  onCancel 
}: PolicyCreationEngineProps) {
  const [activeTab, setActiveTab] = useState("rules");
  const [selectedRule, setSelectedRule] = useState<string>("");
  const [customCalculations, setCustomCalculations] = useState({
    coverageRate: 0,
    premiumRate: 0,
    duration: 0,
    deductible: 0
  });

  // Mock policy templates
  const policyTemplates: PolicyTemplate[] = [
    {
      id: "template_001",
      name: "Maize Standard Policy",
      cropType: "maize",
      baseCoverageRate: 480000, // RWF per hectare
      basePremiumRate: 10, // 10% of coverage
      standardDuration: 120, // 4 months
      description: "Standard maize insurance policy with 120-day coverage period"
    },
    {
      id: "template_002",
      name: "Rice Premium Policy",
      cropType: "rice",
      baseCoverageRate: 600000,
      basePremiumRate: 12,
      standardDuration: 150,
      description: "Premium rice insurance policy with extended coverage"
    },
    {
      id: "template_003",
      name: "Beans Basic Policy",
      cropType: "beans",
      baseCoverageRate: 360000,
      basePremiumRate: 8,
      standardDuration: 90,
      description: "Basic beans insurance policy with 90-day coverage"
    },
    {
      id: "template_004",
      name: "Coffee Premium Policy",
      cropType: "coffee",
      baseCoverageRate: 1200000,
      basePremiumRate: 15,
      standardDuration: 365,
      description: "Premium coffee insurance policy with annual coverage"
    }
  ];

  // Mock business rules
  const businessRules: PolicyRule[] = [
    {
      id: "rule_001",
      name: "Low Risk Maize Policy",
      description: "Standard policy for low-risk maize farms",
      conditions: {
        cropType: ["maize"],
        riskLevel: ["low"],
        farmSize: { min: 0.5, max: 10 },
        location: ["all"]
      },
      calculations: {
        coverageRate: 480000,
        premiumRate: 8,
        duration: 120,
        deductible: 5
      },
      status: 'active'
    },
    {
      id: "rule_002",
      name: "High Risk Adjustment",
      description: "Adjusted rates for high-risk farms",
      conditions: {
        cropType: ["maize", "rice", "beans"],
        riskLevel: ["high"],
        farmSize: { min: 0.5, max: 10 },
        location: ["all"]
      },
      calculations: {
        coverageRate: 400000,
        premiumRate: 15,
        duration: 120,
        deductible: 10
      },
      status: 'active'
    },
    {
      id: "rule_003",
      name: "Large Farm Policy",
      description: "Special rates for large farms (>5 hectares)",
      conditions: {
        cropType: ["all"],
        riskLevel: ["low", "medium"],
        farmSize: { min: 5, max: 50 },
        location: ["all"]
      },
      calculations: {
        coverageRate: 450000,
        premiumRate: 7,
        duration: 120,
        deductible: 3
      },
      status: 'active'
    }
  ];

  const calculatePolicy = () => {
    const template = policyTemplates.find(t => t.cropType === cropType.toLowerCase());
    const applicableRule = businessRules.find(rule => 
      rule.status === 'active' &&
      rule.conditions.cropType.includes(cropType.toLowerCase()) &&
      rule.conditions.riskLevel.includes(riskLevel) &&
      farmSize >= rule.conditions.farmSize.min &&
      farmSize <= rule.conditions.farmSize.max
    );

    let coverageRate = template?.baseCoverageRate || 400000;
    let premiumRate = template?.basePremiumRate || 10;
    let duration = template?.standardDuration || 120;
    let deductible = 5;

    // Apply rule adjustments
    if (applicableRule) {
      coverageRate = applicableRule.calculations.coverageRate;
      premiumRate = applicableRule.calculations.premiumRate;
      duration = applicableRule.calculations.duration;
      deductible = applicableRule.calculations.deductible;
    }

    // Risk level adjustments
    if (riskLevel === 'high') {
      coverageRate *= 0.9; // 10% reduction for high risk
      premiumRate *= 1.5; // 50% increase for high risk
    } else if (riskLevel === 'low') {
      premiumRate *= 0.8; // 20% reduction for low risk
    }

    const totalCoverage = coverageRate * farmSize;
    const premiumAmount = (totalCoverage * premiumRate) / 100;
    const deductibleAmount = (totalCoverage * deductible) / 100;

    return {
      coverageRate: Math.round(coverageRate),
      totalCoverage: Math.round(totalCoverage),
      premiumAmount: Math.round(premiumAmount),
      deductibleAmount: Math.round(deductibleAmount),
      premiumRate,
      deductible,
      duration,
      effectiveDate: new Date().toISOString(),
      expiryDate: new Date(Date.now() + duration * 24 * 60 * 60 * 1000).toISOString()
    };
  };

  const policyCalculation = calculatePolicy();

  const renderBusinessRules = () => (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold">Business Rules Configuration</h3>
        <Button className="bg-blue-600 hover:bg-blue-700">
          <Settings className="h-4 w-4 mr-2" />
          Configure Rules
        </Button>
      </div>

      <div className="space-y-4">
        {businessRules.map((rule) => (
          <Card key={rule.id} className={selectedRule === rule.id ? 'ring-2 ring-blue-500' : ''}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between mb-3">
                <div>
                  <h4 className="font-semibold">{rule.name}</h4>
                  <p className="text-sm text-gray-600">{rule.description}</p>
                </div>
                <Badge variant={rule.status === 'active' ? 'default' : 'secondary'}>
                  {rule.status}
                </Badge>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                <div>
                  <Label className="text-gray-500">Conditions</Label>
                  <div className="space-y-1">
                    <p><strong>Crops:</strong> {rule.conditions.cropType.join(', ')}</p>
                    <p><strong>Risk Levels:</strong> {rule.conditions.riskLevel.join(', ')}</p>
                    <p><strong>Farm Size:</strong> {rule.conditions.farmSize.min} - {rule.conditions.farmSize.max} ha</p>
                  </div>
                </div>
                <div>
                  <Label className="text-gray-500">Calculations</Label>
                  <div className="space-y-1">
                    <p><strong>Coverage Rate:</strong> RWF {rule.calculations.coverageRate.toLocaleString()}/ha</p>
                    <p><strong>Premium Rate:</strong> {rule.calculations.premiumRate}%</p>
                    <p><strong>Duration:</strong> {rule.calculations.duration} days</p>
                    <p><strong>Deductible:</strong> {rule.calculations.deductible}%</p>
                  </div>
                </div>
              </div>

              <div className="flex justify-end mt-4">
                <Button 
                  size="sm" 
                  variant="outline"
                  onClick={() => setSelectedRule(rule.id)}
                >
                  Apply Rule
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );

  const renderPolicyTemplates = () => (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold">Policy Templates</h3>
        <Button className="bg-green-600 hover:bg-green-700">
          <Database className="h-4 w-4 mr-2" />
          Manage Templates
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {policyTemplates.map((template) => (
          <Card key={template.id}>
            <CardContent className="p-4">
              <div className="flex items-center space-x-3 mb-3">
                <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                  <Crop className="h-5 w-5 text-blue-600" />
                </div>
                <div>
                  <h4 className="font-semibold">{template.name}</h4>
                  <p className="text-sm text-gray-600 capitalize">{template.cropType}</p>
                </div>
              </div>
              
              <p className="text-sm text-gray-600 mb-4">{template.description}</p>
              
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span>Coverage Rate:</span>
                  <span className="font-medium">RWF {template.baseCoverageRate.toLocaleString()}/ha</span>
                </div>
                <div className="flex justify-between">
                  <span>Premium Rate:</span>
                  <span className="font-medium">{template.basePremiumRate}%</span>
                </div>
                <div className="flex justify-between">
                  <span>Duration:</span>
                  <span className="font-medium">{template.standardDuration} days</span>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );

  const renderPolicyCalculation = () => (
    <div className="space-y-6">
      <div className="flex items-center space-x-3">
        <Calculator className="h-6 w-6 text-blue-600" />
        <h3 className="text-lg font-semibold">Automated Policy Calculation</h3>
      </div>

      <Card className="bg-gradient-to-r from-blue-50 to-green-50">
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Shield className="h-5 w-5" />
            <span>Generated Policy Details</span>
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Input Parameters */}
          <div>
            <h4 className="font-semibold mb-3">Input Parameters</h4>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
              <div className="p-3 bg-white rounded-lg">
                <Label className="text-gray-500">Crop Type</Label>
                <p className="font-medium capitalize">{cropType}</p>
              </div>
              <div className="p-3 bg-white rounded-lg">
                <Label className="text-gray-500">Farm Size</Label>
                <p className="font-medium">{farmSize} hectares</p>
              </div>
              <div className="p-3 bg-white rounded-lg">
                <Label className="text-gray-500">Risk Level</Label>
                <Badge variant={riskLevel === 'low' ? 'default' : riskLevel === 'medium' ? 'secondary' : 'destructive'}>
                  {riskLevel.toUpperCase()}
                </Badge>
              </div>
              <div className="p-3 bg-white rounded-lg">
                <Label className="text-gray-500">Location</Label>
                <p className="font-medium">{location}</p>
              </div>
            </div>
          </div>

          {/* Policy Calculations */}
          <div>
            <h4 className="font-semibold mb-3">Policy Calculations</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Coverage Rate per Hectare</span>
                  <span className="font-semibold text-lg">RWF {policyCalculation.coverageRate.toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Total Coverage Amount</span>
                  <span className="font-semibold text-lg text-green-600">RWF {policyCalculation.totalCoverage.toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Premium Rate</span>
                  <span className="font-semibold">{policyCalculation.premiumRate}%</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Premium Amount</span>
                  <span className="font-semibold text-lg text-blue-600">RWF {policyCalculation.premiumAmount.toLocaleString()}</span>
                </div>
              </div>
              
              <div className="space-y-4">
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Deductible Rate</span>
                  <span className="font-semibold">{policyCalculation.deductible}%</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Deductible Amount</span>
                  <span className="font-semibold text-lg text-orange-600">RWF {policyCalculation.deductibleAmount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Policy Duration</span>
                  <span className="font-semibold">{policyCalculation.duration} days</span>
                </div>
                <div className="flex justify-between items-center p-3 bg-white rounded-lg">
                  <span className="text-gray-600">Expiry Date</span>
                  <span className="font-semibold">{new Date(policyCalculation.expiryDate).toLocaleDateString()}</span>
                </div>
              </div>
            </div>
          </div>

          {/* Risk Adjustments */}
          <div>
            <h4 className="font-semibold mb-3">Risk Adjustments Applied</h4>
            <div className="space-y-2">
              {riskLevel === 'high' && (
                <div className="flex items-center space-x-2 text-sm">
                  <AlertTriangle className="h-4 w-4 text-red-600" />
                  <span>High Risk: Coverage reduced by 10%, Premium increased by 50%</span>
                </div>
              )}
              {riskLevel === 'low' && (
                <div className="flex items-center space-x-2 text-sm">
                  <CheckCircle className="h-4 w-4 text-green-600" />
                  <span>Low Risk: Premium reduced by 20%</span>
                </div>
              )}
              {farmSize > 5 && (
                <div className="flex items-center space-x-2 text-sm">
                  <TrendingUp className="h-4 w-4 text-blue-600" />
                  <span>Large Farm: Special rates applied</span>
                </div>
              )}
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );

  const handleCreatePolicy = () => {
    const newPolicy = {
      id: `POL${Date.now()}`,
      farmerId,
      assessmentId,
      cropType,
      farmSize,
      riskLevel,
      location,
      ...policyCalculation,
      status: 'pending_payment',
      createdAt: new Date().toISOString(),
      createdBy: 'system'
    };

    onPolicyCreated(newPolicy);
  };

  return (
    <div className="max-w-6xl mx-auto p-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl text-center">Automated Policy Creation Engine</CardTitle>
          <p className="text-center text-gray-600">
            AI-powered policy generation with business rules and risk adjustments
          </p>
        </CardHeader>
        <CardContent>
          <Tabs value={activeTab} onValueChange={setActiveTab}>
            <TabsList className="grid w-full grid-cols-3">
              <TabsTrigger value="rules">Business Rules</TabsTrigger>
              <TabsTrigger value="templates">Templates</TabsTrigger>
              <TabsTrigger value="calculation">Policy Calculation</TabsTrigger>
            </TabsList>

            <TabsContent value="rules" className="mt-6">
              {renderBusinessRules()}
            </TabsContent>

            <TabsContent value="templates" className="mt-6">
              {renderPolicyTemplates()}
            </TabsContent>

            <TabsContent value="calculation" className="mt-6">
              {renderPolicyCalculation()}
            </TabsContent>
          </Tabs>

          <div className="flex justify-between mt-8">
            <Button variant="outline" onClick={onCancel}>
              Cancel
            </Button>
            <Button 
              onClick={handleCreatePolicy}
              className="bg-green-600 hover:bg-green-700"
            >
              <Zap className="h-4 w-4 mr-2" />
              Create Policy
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { MapPicker } from "@/components/maps/MapPicker";
import { FileUpload } from "@/components/upload/FileUpload";
import { 
  User, 
  MapPin, 
  CreditCard, 
  FileText, 
  CheckCircle, 
  AlertTriangle,
  Upload,
  Eye,
  EyeOff,
  Phone,
  Mail,
  Home,
  Shield,
  Camera,
  MapIcon
} from "lucide-react";
import { FarmerProfile } from "@/types/enhanced-api";

interface FarmerRegistrationProps {
  onComplete: (profile: FarmerProfile) => void;
  onCancel: () => void;
}

export function FarmerRegistration({ onComplete, onCancel }: FarmerRegistrationProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [showUpiPassword, setShowUpiPassword] = useState(false);
  const [profile, setProfile] = useState<Partial<FarmerProfile>>({
    personalInfo: {
      name: "",
      email: "",
      phone: "",
      upiCredentials: {
        upiId: "",
        bankAccount: "",
        ifscCode: ""
      }
    },
    farmDetails: {
      location: {
        coordinates: [30.1234, -1.9456], // Default to Rwanda coordinates
        address: "",
        district: "",
        province: ""
      },
      totalFarmSize: 0,
      landOwnership: {
        verified: false,
        documentType: 'title_deed'
      }
    }
  });

  const totalSteps = 4;

  const handleInputChange = (section: string, field: string, value: any) => {
    setProfile(prev => ({
      ...prev,
      [section]: {
        ...prev[section as keyof typeof prev],
        [field]: value
      }
    }));
  };

  const handleNestedInputChange = (section: string, subsection: string, field: string, value: any) => {
    setProfile(prev => ({
      ...prev,
      [section]: {
        ...prev[section as keyof typeof prev],
        [subsection]: {
          ...(prev[section as keyof typeof prev] as any)?.[subsection],
          [field]: value
        }
      }
    }));
  };

  const handleCoordinatesChange = (coordinates: [number, number]) => {
    handleNestedInputChange('farmDetails', 'location', 'coordinates', coordinates);
  };

  const handleFileUpload = (files: File[]) => {
    // Handle land ownership document upload
    if (files.length > 0) {
      const file = files[0];
      // In real implementation, upload to server and get URL
      handleNestedInputChange('farmDetails', 'landOwnership', 'documentUrl', URL.createObjectURL(file));
    }
  };

  const validateStep = (step: number): boolean => {
    switch (step) {
      case 1:
        return !!(profile.personalInfo?.name && profile.personalInfo?.email && profile.personalInfo?.phone);
      case 2:
        return !!(profile.farmDetails?.location?.address && profile.farmDetails?.district && profile.farmDetails?.province);
      case 3:
        return !!(profile.personalInfo?.upiCredentials?.upiId && profile.personalInfo?.upiCredentials?.bankAccount && profile.personalInfo?.upiCredentials?.ifscCode);
      case 4:
        return !!(profile.farmDetails?.totalFarmSize && profile.farmDetails?.totalFarmSize > 0);
      default:
        return false;
    }
  };

  const nextStep = () => {
    if (validateStep(currentStep) && currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const prevStep = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    if (validateStep(currentStep)) {
      const completeProfile: FarmerProfile = {
        id: `farmer_${Date.now()}`,
        ...profile,
        personalInfo: profile.personalInfo!,
        farmDetails: profile.farmDetails!,
        registrationDate: new Date().toISOString(),
        status: 'pending_verification'
      } as FarmerProfile;
      
      onComplete(completeProfile);
    }
  };

  const renderStepIndicator = () => (
    <div className="flex items-center justify-center mb-8">
      {Array.from({ length: totalSteps }, (_, i) => (
        <div key={i} className="flex items-center">
          <div className={`
            w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium
            ${i + 1 <= currentStep 
              ? 'bg-blue-600 text-white' 
              : 'bg-gray-200 text-gray-500'
            }
          `}>
            {i + 1}
          </div>
          {i < totalSteps - 1 && (
            <div className={`
              w-16 h-1 mx-2
              ${i + 1 < currentStep ? 'bg-blue-600' : 'bg-gray-200'}
            `} />
          )}
        </div>
      ))}
    </div>
  );

  const renderPersonalInfo = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <User className="h-12 w-12 mx-auto text-blue-600 mb-4" />
        <h3 className="text-xl font-semibold">Personal Information</h3>
        <p className="text-gray-600">Please provide your basic personal details</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <Label htmlFor="name">Full Name *</Label>
          <Input
            id="name"
            placeholder="Enter your full name"
            value={profile.personalInfo?.name || ''}
            onChange={(e) => handleInputChange('personalInfo', 'name', e.target.value)}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="phone">Phone Number *</Label>
          <div className="relative">
            <Phone className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
            <Input
              id="phone"
              placeholder="+250 XXX XXX XXX"
              className="pl-10"
              value={profile.personalInfo?.phone || ''}
              onChange={(e) => handleInputChange('personalInfo', 'phone', e.target.value)}
            />
          </div>
        </div>

        <div className="space-y-2 md:col-span-2">
          <Label htmlFor="email">Email Address *</Label>
          <div className="relative">
            <Mail className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
            <Input
              id="email"
              type="email"
              placeholder="your.email@example.com"
              className="pl-10"
              value={profile.personalInfo?.email || ''}
              onChange={(e) => handleInputChange('personalInfo', 'email', e.target.value)}
            />
          </div>
        </div>
      </div>
    </div>
  );

  const renderFarmDetails = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <Home className="h-12 w-12 mx-auto text-green-600 mb-4" />
        <h3 className="text-xl font-semibold">Farm Location Details</h3>
        <p className="text-gray-600">Provide your farm location and size information</p>
      </div>

      <div className="space-y-6">
        <div className="space-y-2">
          <Label>Farm Location *</Label>
          <MapPicker
            coordinates={profile.farmDetails?.location?.coordinates || [30.1234, -1.9456]}
            onCoordinatesChange={handleCoordinatesChange}
            height="300px"
          />
          <p className="text-sm text-gray-500">
            Click on the map to set your farm location
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <Label htmlFor="address">Address *</Label>
            <Textarea
              id="address"
              placeholder="Enter your farm address"
              value={profile.farmDetails?.location?.address || ''}
              onChange={(e) => handleNestedInputChange('farmDetails', 'location', 'address', e.target.value)}
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="district">District *</Label>
            <Select
              value={profile.farmDetails?.location?.district || ''}
              onValueChange={(value) => handleNestedInputChange('farmDetails', 'location', 'district', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select district" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="musanze">Musanze</SelectItem>
                <SelectItem value="rubavu">Rubavu</SelectItem>
                <SelectItem value="burera">Burera</SelectItem>
                <SelectItem value="rwamagana">Rwamagana</SelectItem>
                <SelectItem value="kayonza">Kayonza</SelectItem>
                <SelectItem value="ngoma">Ngoma</SelectItem>
                <SelectItem value="huye">Huye</SelectItem>
                <SelectItem value="nyanza">Nyanza</SelectItem>
                <SelectItem value="gisagara">Gisagara</SelectItem>
                <SelectItem value="nyaruguru">Nyaruguru</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="province">Province *</Label>
            <Select
              value={profile.farmDetails?.location?.province || ''}
              onValueChange={(value) => handleNestedInputChange('farmDetails', 'location', 'province', value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select province" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="northern">Northern Province</SelectItem>
                <SelectItem value="eastern">Eastern Province</SelectItem>
                <SelectItem value="southern">Southern Province</SelectItem>
                <SelectItem value="western">Western Province</SelectItem>
                <SelectItem value="kigali">Kigali City</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="farmSize">Total Farm Size (Hectares) *</Label>
            <Input
              id="farmSize"
              type="number"
              placeholder="Enter farm size in hectares"
              value={profile.farmDetails?.totalFarmSize || ''}
              onChange={(e) => handleInputChange('farmDetails', 'totalFarmSize', parseFloat(e.target.value) || 0)}
            />
          </div>
        </div>

        <div className="space-y-4">
          <Label>Land Ownership Verification</Label>
          <div className="space-y-3">
            <div className="flex items-center space-x-2">
              <Checkbox
                id="ownershipVerified"
                checked={profile.farmDetails?.landOwnership?.verified || false}
                onCheckedChange={(checked) => 
                  handleNestedInputChange('farmDetails', 'landOwnership', 'verified', checked)
                }
              />
              <Label htmlFor="ownershipVerified">
                I confirm that I have legal ownership/rights to this land
              </Label>
            </div>

            <div className="space-y-2">
              <Label htmlFor="documentType">Ownership Document Type</Label>
              <Select
                value={profile.farmDetails?.landOwnership?.documentType || 'title_deed'}
                onValueChange={(value) => 
                  handleNestedInputChange('farmDetails', 'landOwnership', 'documentType', value)
                }
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select document type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="title_deed">Title Deed</SelectItem>
                  <SelectItem value="lease_agreement">Lease Agreement</SelectItem>
                  <SelectItem value="customary_rights">Customary Rights</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Upload Ownership Document</Label>
              <FileUpload
                onUpload={handleFileUpload}
                accept=".pdf,.jpg,.jpeg,.png"
                maxSize={5 * 1024 * 1024} // 5MB
                multiple={false}
              />
              {profile.farmDetails?.landOwnership?.documentUrl && (
                <div className="flex items-center space-x-2 text-green-600">
                  <CheckCircle className="h-4 w-4" />
                  <span className="text-sm">Document uploaded successfully</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  const renderUpiCredentials = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <CreditCard className="h-12 w-12 mx-auto text-purple-600 mb-4" />
        <h3 className="text-xl font-semibold">UPI Payment Credentials</h3>
        <p className="text-gray-600">Set up your UPI details for seamless premium payments</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <Label htmlFor="upiId">UPI ID *</Label>
          <Input
            id="upiId"
            placeholder="yourname@bank"
            value={profile.personalInfo?.upiCredentials?.upiId || ''}
            onChange={(e) => handleNestedInputChange('personalInfo', 'upiCredentials', 'upiId', e.target.value)}
          />
          <p className="text-sm text-gray-500">Example: john.doe@mtn or 0781234567@airtel</p>
        </div>

        <div className="space-y-2">
          <Label htmlFor="bankAccount">Bank Account Number *</Label>
          <Input
            id="bankAccount"
            placeholder="Enter your bank account number"
            value={profile.personalInfo?.upiCredentials?.bankAccount || ''}
            onChange={(e) => handleNestedInputChange('personalInfo', 'upiCredentials', 'bankAccount', e.target.value)}
          />
        </div>

        <div className="space-y-2 md:col-span-2">
          <Label htmlFor="ifscCode">IFSC Code *</Label>
          <Input
            id="ifscCode"
            placeholder="Enter your bank's IFSC code"
            value={profile.personalInfo?.upiCredentials?.ifscCode || ''}
            onChange={(e) => handleNestedInputChange('personalInfo', 'upiCredentials', 'ifscCode', e.target.value)}
          />
          <p className="text-sm text-gray-500">
            Find your IFSC code on your bank passbook or online banking
          </p>
        </div>
      </div>

      <div className="bg-blue-50 p-4 rounded-lg">
        <div className="flex items-start space-x-3">
          <Shield className="h-5 w-5 text-blue-600 mt-0.5" />
          <div>
            <h4 className="font-medium text-blue-900">Secure Payment Processing</h4>
            <p className="text-sm text-blue-700 mt-1">
              Your UPI credentials are encrypted and securely stored. We use industry-standard 
              security measures to protect your financial information.
            </p>
          </div>
        </div>
      </div>
    </div>
  );

  const renderReview = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <CheckCircle className="h-12 w-12 mx-auto text-green-600 mb-4" />
        <h3 className="text-xl font-semibold">Review Your Information</h3>
        <p className="text-gray-600">Please review all details before submitting</p>
      </div>

      <div className="space-y-6">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <User className="h-5 w-5" />
              <span>Personal Information</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label className="text-sm font-medium text-gray-500">Name</Label>
                <p>{profile.personalInfo?.name}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">Phone</Label>
                <p>{profile.personalInfo?.phone}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">Email</Label>
                <p>{profile.personalInfo?.email}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">UPI ID</Label>
                <p>{profile.personalInfo?.upiCredentials?.upiId}</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center space-x-2">
              <MapPin className="h-5 w-5" />
              <span>Farm Details</span>
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label className="text-sm font-medium text-gray-500">Address</Label>
                <p>{profile.farmDetails?.location?.address}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">District</Label>
                <p>{profile.farmDetails?.location?.district}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">Province</Label>
                <p>{profile.farmDetails?.location?.province}</p>
              </div>
              <div>
                <Label className="text-sm font-medium text-gray-500">Farm Size</Label>
                <p>{profile.farmDetails?.totalFarmSize} hectares</p>
              </div>
            </div>
            <div className="mt-4">
              <Label className="text-sm font-medium text-gray-500">Coordinates</Label>
              <p className="text-sm font-mono">
                {profile.farmDetails?.location?.coordinates?.join(', ')}
              </p>
            </div>
          </CardContent>
        </Card>

        <div className="bg-yellow-50 p-4 rounded-lg">
          <div className="flex items-start space-x-3">
            <AlertTriangle className="h-5 w-5 text-yellow-600 mt-0.5" />
            <div>
              <h4 className="font-medium text-yellow-900">Verification Required</h4>
              <p className="text-sm text-yellow-700 mt-1">
                Your registration will be reviewed by our team. You'll receive a notification 
                once your account is verified and ready to use.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  const renderCurrentStep = () => {
    switch (currentStep) {
      case 1:
        return renderPersonalInfo();
      case 2:
        return renderFarmDetails();
      case 3:
        return renderUpiCredentials();
      case 4:
        return renderReview();
      default:
        return null;
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl text-center">Farmer Registration</CardTitle>
          <p className="text-center text-gray-600">
            Join Rwanda's AI Agricultural Insurance Platform
          </p>
        </CardHeader>
        <CardContent>
          {renderStepIndicator()}
          
          <div className="mb-8">
            {renderCurrentStep()}
          </div>

          <div className="flex justify-between">
            <Button
              variant="outline"
              onClick={currentStep === 1 ? onCancel : prevStep}
            >
              {currentStep === 1 ? 'Cancel' : 'Previous'}
            </Button>

            {currentStep < totalSteps ? (
              <Button
                onClick={nextStep}
                disabled={!validateStep(currentStep)}
              >
                Next
              </Button>
            ) : (
              <Button
                onClick={handleSubmit}
                disabled={!validateStep(currentStep)}
                className="bg-green-600 hover:bg-green-700"
              >
                Submit Registration
              </Button>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

